private struct HazardItem: Codable, Identifiable, Hashable {
    let id: String
    let title: String?
    let url: String?
    let source: String?
    let kind: String?
    let location: String?
    let severity: String?
    let startedAt: String?

    private enum CodingKeys: String, CodingKey {
        case title, url, source, kind, location, severity, startedAt
    }

    init(from decoder: Decoder) throws {
        let container = try decoder.container(keyedBy: CodingKeys.self)
        title = try container.decodeIfPresent(String.self, forKey: .title)
        url = try container.decodeIfPresent(String.self, forKey: .url)
        source = try container.decodeIfPresent(String.self, forKey: .source)
        kind = try container.decodeIfPresent(String.self, forKey: .kind)
        location = try container.decodeIfPresent(String.self, forKey: .location)
        severity = try container.decodeIfPresent(String.self, forKey: .severity)
        startedAt = try container.decodeIfPresent(String.self, forKey: .startedAt)

        let parts = [url, title, source, kind, location, severity, startedAt]
            .compactMap { $0?.trimmingCharacters(in: .whitespacesAndNewlines) }
            .filter { !$0.isEmpty }
        id = parts.isEmpty ? UUID().uuidString : parts.joined(separator: "|")
    }

    init(id: String = UUID().uuidString,
         title: String? = nil,
         url: String? = nil,
         source: String? = nil,
         kind: String? = nil,
         location: String? = nil,
         severity: String? = nil,
         startedAt: String? = nil) {
        self.id = id
        self.title = title
        self.url = url
        self.source = source
        self.kind = kind
        self.location = location
        self.severity = severity
        self.startedAt = startedAt
    }
}

