            case "voiceSemantics", "voice_semantics":
                voiceSemantics = try? container.decode(UserOutlookVoiceSemantics.self, forKey: key)
            default:
                break
            }
        }

        self.ok = ok
        self.generatedAt = generatedAt
        self.availableWindows = availableWindows
        self.dailyOutlook = dailyOutlook
        self.forecastDataReady = forecastDataReady
        self.next24h = next24h
        self.next72h = next72h
        self.next7d = next7d
        self.error = error
