private struct MediaViewerPayload: Identifiable {
    let id: String
    let url: URL
    let title: String?
    let credit: String?
    let isVideo: Bool
}

private struct MediaViewerSheet: View {
    let payload: MediaViewerPayload
    @Environment(\.dismiss) private var dismiss
    @State private var player: AVPlayer? = nil

    var body: some View {
        ZStack {
            Color.black.ignoresSafeArea()
            VStack(spacing: 12) {
                VStack(spacing: 2) {
                    if let title = payload.title, !title.isEmpty {
                        Text(title).font(.headline).foregroundColor(.white)
                    }
                    if let credit = payload.credit, !credit.isEmpty {
                        Text(credit).font(.caption).foregroundColor(.white.opacity(0.7))
                    }
                }
                .padding(.top, 16)
                .padding(.horizontal, 16)

                if payload.isVideo {
                    VideoPlayer(player: player)
                        .onAppear {
                            if player == nil { player = AVPlayer(url: payload.url) }
                            player?.play()
                        }
                        .onDisappear {
                            player?.pause()
                            player = nil
                        }
                        .scaledToFit()
                        .frame(maxWidth: .infinity, maxHeight: 520)
                } else {
                    AsyncImage(url: payload.url) { phase in
                        switch phase {
                        case .empty:
                            ProgressView().tint(.white)
                        case .success(let image):
                            image
                                .resizable()
                                .scaledToFit()
                                .frame(maxWidth: .infinity, maxHeight: 520)
                        case .failure:
                            Image(systemName: "exclamationmark.triangle.fill")
                                .foregroundColor(.orange)
                        @unknown default:
                            EmptyView()
                        }
                    }
                }
                Spacer()
            }
        }
        .onTapGesture(count: 2) { dismiss() }
        .safeAreaInset(edge: .top) {
            HStack {
                Spacer()
                Button { dismiss() } label: {
                    Image(systemName: "xmark.circle.fill")
                        .font(.title)
                        .foregroundColor(.white)
                        .padding(10)
                        .background(Color.black.opacity(0.35), in: Circle())
                }
                .padding(.trailing, 12)
            }
        }
    }
}

#if canImport(CoreLocation)
private final class OneShotLocationProvider: NSObject, CLLocationManagerDelegate {
    private let manager = CLLocationManager()
    private var continuation: CheckedContinuation<CLLocation?, Never>?

    override init() {
        super.init()
        manager.delegate = self
        manager.desiredAccuracy = kCLLocationAccuracyKilometer
    }

    func requestLocation() async -> CLLocation? {
        let status = manager.authorizationStatus
        if status == .denied || status == .restricted {
            return nil
        }
        return await withCheckedContinuation { continuation in
            self.continuation = continuation
            if status == .notDetermined {
                manager.requestWhenInUseAuthorization()
                return
            }
            manager.requestLocation()
        }
    }

    func locationManager(_ manager: CLLocationManager, didUpdateLocations locations: [CLLocation]) {
        guard let continuation else { return }
        self.continuation = nil
        continuation.resume(returning: locations.last)
    }

    func locationManager(_ manager: CLLocationManager, didFailWithError error: Error) {
        guard let continuation else { return }
        self.continuation = nil
        continuation.resume(returning: nil)
    }

    func locationManagerDidChangeAuthorization(_ manager: CLLocationManager) {
        let status = manager.authorizationStatus
        if status == .authorizedAlways || status == .authorizedWhenInUse {
            manager.requestLocation()
        } else if status == .denied || status == .restricted {
            guard let continuation else { return }
            self.continuation = nil
            continuation.resume(returning: nil)
        }
    }
}
#endif

