    private var appNoticeURL: URL? {
        let support = HelpCenterContent.shared.metadata.webSupportURL.trimmingCharacters(in: .whitespacesAndNewlines)
        guard let supportURL = URL(string: support),
              let scheme = supportURL.scheme,
              let host = supportURL.host else {
            return URL(string: "https://gaiaeyes.com/wp-json/gaia/v1/app-notice")
        }
        var components = URLComponents()
        components.scheme = scheme
        components.host = host
        components.path = "/wp-json/gaia/v1/app-notice"
        return components.url
    }

    private var appNoticeURLCandidates: [URL] {
        var urls: [URL] = []
        if let appNoticeURL {
            urls.append(appNoticeURL)
        }
        [
            "https://gaiaeyes.com/wp-json/gaia/v1/app-notice",
            "https://www.gaiaeyes.com/wp-json/gaia/v1/app-notice",
        ]
        .compactMap(URL.init(string:))
        .forEach { candidate in
            if !urls.contains(candidate) {
                urls.append(candidate)
            }
        }
        return urls
    }

    private func appNoticeRequestURL(for url: URL) -> URL {
        var components = URLComponents(url: url, resolvingAgainstBaseURL: false)
        var queryItems = components?.queryItems ?? []
        queryItems.append(URLQueryItem(name: "_gaia_notice_ts", value: String(Int(Date().timeIntervalSince1970))))
        components?.queryItems = queryItems
        return components?.url ?? url
    }

    private func visibleAppNotice(for placement: AppNoticePlacement) -> AppNotice? {
        let dismissedKeys = Set(dismissedAppNoticeKeysRaw.split(separator: "\n").map(String.init))
        return appNotices.first { notice in
            notice.isVisible(in: placement)
                && notice.dismissalKey != dismissedAppNoticeID
                && !dismissedKeys.contains(notice.dismissalKey)
        }
    }

    private func dismissAppNotice(_ notice: AppNotice) {
        var dismissedKeys = Set(dismissedAppNoticeKeysRaw.split(separator: "\n").map(String.init))
        dismissedKeys.insert(notice.dismissalKey)
        dismissedAppNoticeKeysRaw = dismissedKeys.sorted().joined(separator: "\n")
        dismissedAppNoticeID = notice.dismissalKey
    }

