            activePatternDriverKeys: activePatternRefs.compactMap { $0.driverKey ?? $0.signalKey },
            activePatternOutcomeKeys: activePatternRefs.compactMap(\.outcomeKey),
            recentSymptomCodes: symptomsToday.map(\.symptomCode),
