            withAnimation {
                if self.symptomToast?.id == toast.id {
                    self.symptomToast = nil
                }
            }
        }
    }

    // MARK: - Features diagnostics helpers
    @MainActor
    private func fetchFeaturesDiagnostics() async {
        featuresDiagnosticsError = nil
        featuresDiagnosticsLoading = true
        defer { featuresDiagnosticsLoading = false }

        let api = state.apiWithAuth()
        do {
            let envelope = try await api.fetchFeaturesDiagnostics(tz: preferredTimeZoneIdentifier)
            if let diagnostics = envelope.diagnostics {
                featuresDiagnostics = diagnostics
                let src = diagnostics.source ?? "-"
                appLog("[UI] features diagnostics refreshed (source=\(src))")
            }
            if envelope.ok {
                if envelope.diagnostics == nil {
                    featuresDiagnosticsError = "Diagnostics missing from response"
                }
            } else {
                featuresDiagnosticsError = envelope.error ?? "Diagnostics unavailable"
            }
        } catch {
            featuresDiagnosticsError = error.localizedDescription
        }
    }

    @MainActor
    private func fetchAppNotice() async {
        var lastFailureStatus: Int?
        for url in appNoticeURLCandidates {
            var request = URLRequest(
                url: appNoticeRequestURL(for: url),
                cachePolicy: .reloadIgnoringLocalAndRemoteCacheData,
                timeoutInterval: 8
            )
            request.httpMethod = "GET"
            request.setValue("application/json", forHTTPHeaderField: "Accept")
            request.setValue("no-cache", forHTTPHeaderField: "Cache-Control")
            request.setValue("no-cache", forHTTPHeaderField: "Pragma")
            do {
                let (data, response) = try await URLSession.shared.data(for: request)
                let status = (response as? HTTPURLResponse)?.statusCode ?? -1
                guard (200...299).contains(status) else {
                    lastFailureStatus = status
                    if status == 404 {
                        continue
                    }
                    appLog("[UI] app notice fetch failed status=\(status)")
                    return
                }
                let envelope = try JSONDecoder().decode(AppNoticeEnvelope.self, from: data)
                let nextNotices = envelope.ok == false ? [] : envelope.visibleNotices
                appNotices = nextNotices
                if nextNotices.isEmpty {
                    appLog("[UI] app notice empty")
                }
                return
            } catch is CancellationError {
                return
            } catch let error as URLError where error.code == .cancelled {
                return
            } catch {
                appLog("[UI] app notice fetch error: \(error.localizedDescription)")
                return
            }
        }
        if let lastFailureStatus {
            appLog("[UI] app notice fetch failed status=\(lastFailureStatus)")
        }
    }

    private func fetchHomeFeed() async {
        await MainActor.run {
            homeFeedLoading = true
        }
        let mode = await MainActor.run { experienceProfile.mode.rawValue }
        let encodedMode = mode.addingPercentEncoding(withAllowedCharacters: .urlQueryAllowed) ?? mode
        let api = state.apiWithAuth()
        do {
            let envelope: HomeFeedEnvelope = try await api.getJSON(
                "v1/profile/home-feed?mode=\(encodedMode)",
                as: HomeFeedEnvelope.self,
                retries: 1,
                perRequestTimeout: 12
            )
            let nextItem = envelope.ok == false ? nil : envelope.item
            await MainActor.run {
                homeFeedItem = nextItem
                homeFeedLoading = false
            }
            if let nextItem {
                await markHomeFeedSeen(nextItem, dismissed: false)
            }
        } catch is CancellationError {
            await MainActor.run { homeFeedLoading = false }
        } catch let error as URLError where error.code == .cancelled {
            await MainActor.run { homeFeedLoading = false }
        } catch {
            await MainActor.run {
                homeFeedItem = nil
                homeFeedLoading = false
            }
            appLog("[UI] home feed fetch error: \(error.localizedDescription)")
        }
    }

    private func markHomeFeedSeen(_ item: HomeFeedItem, dismissed: Bool) async {
        let itemID = item.trimmedID
        guard !itemID.isEmpty else { return }
        let seenCacheKey = dismissed ? "\(itemID):dismissed" : "\(itemID):seen"
        let shouldPost = await MainActor.run {
            homeFeedSeenIDs.insert(seenCacheKey).inserted
        }
        guard shouldPost else { return }

        let payload = HomeFeedSeenRequest(itemID: itemID, dismissed: dismissed)
        do {
            let _: HomeFeedSeenEnvelope = try await state.apiWithAuth().postJSON(
                "v1/profile/home-feed/seen",
                body: payload,
                as: HomeFeedSeenEnvelope.self
            )
        } catch is CancellationError {
            await MainActor.run { _ = homeFeedSeenIDs.remove(seenCacheKey) }
        } catch let error as URLError where error.code == .cancelled {
            await MainActor.run { _ = homeFeedSeenIDs.remove(seenCacheKey) }
        } catch {
            await MainActor.run { _ = homeFeedSeenIDs.remove(seenCacheKey) }
            appLog("[UI] home feed seen save error: \(error.localizedDescription)")
        }
    }

    @MainActor
    private func copyTrace(_ lines: [String]) {
        let ordered = Array(lines.reversed())
        let text = ordered.joined(separator: "\n")
#if canImport(UIKit)
        UIPasteboard.general.string = text
#endif
        let count = ordered.count
        appLog("[UI] diagnostics trace copied (\(count) lines)")
        showSymptomToast(count == 1 ? "Copied 1 trace line" : "Copied \(count) trace lines")
    }

    @MainActor
    private func shareTrace(_ lines: [String]) {
#if canImport(UIKit)
        let ordered = Array(lines.reversed())
        let text = ordered.joined(separator: "\n")
        let activity = UIActivityViewController(activityItems: [text], applicationActivities: nil)
        if let scene = UIApplication.shared.connectedScenes.first as? UIWindowScene,
           let window = scene.windows.first,
           let root = window.rootViewController {
            if let popover = activity.popoverPresentationController {
                popover.sourceView = root.view
                popover.sourceRect = CGRect(x: root.view.bounds.midX, y: root.view.bounds.midY, width: 0, height: 0)
            }
            root.present(activity, animated: true)
        }
#endif
        appLog("[UI] diagnostics trace share sheet presented")
    }

    @MainActor
    private func appendTraceToStatus(_ lines: [String]) {
        let ordered = Array(lines.reversed())
        let payload = ordered.isEmpty ? ["(no trace lines)"] : ordered
        state.statusLines.append(contentsOf: payload)
        appLog("[UI] diagnostics trace appended to status (\(payload.count) lines)")
        showSymptomToast("Trace appended to Status")
    }

    private func parseDebugDate(_ raw: String?) -> Date? {
        guard let raw = raw?.trimmingCharacters(in: .whitespacesAndNewlines), !raw.isEmpty else { return nil }
        let precise = ISO8601DateFormatter()
        precise.formatOptions = [.withInternetDateTime, .withFractionalSeconds]
        if let date = precise.date(from: raw) {
            return date
        }
        if let date = ISO8601DateFormatter().date(from: raw) {
            return date
        }
        let dayFormatter = DateFormatter()
        dayFormatter.dateFormat = "yyyy-MM-dd"
        dayFormatter.timeZone = TimeZone(identifier: "America/Chicago") ?? .current
        return dayFormatter.date(from: raw)
    }

    private func dashboardSnapshotReferenceDate(from payload: DashboardPayload?) -> Date? {
        guard let payload else { return nil }
        return [
            parseDebugDate(payload.lastSymptomUpdateAt),
            parseDebugDate(payload.memberPost?.updatedAt),
            parseDebugDate(payload.personalPost?.updatedAt),
            parseDebugDate(payload.publicPost?.updatedAt),
        ]
        .compactMap { $0 }
        .max()
    }

    private func dashboardNeedsForegroundRefresh(now: Date = Date()) -> Bool {
        let referenceDate: Date
        if dashboardLastFetchAt != .distantPast {
            referenceDate = dashboardLastFetchAt
        } else if let cachedDate = dashboardSnapshotReferenceDate(from: dashboardPayload ?? decodeDashboardPayload(from: dashboardPayloadCacheJSON)) {
            referenceDate = cachedDate
        } else {
            return true
        }
        return now.timeIntervalSince(referenceDate) >= 5 * 60
    }

    private func debugFormattedDate(_ date: Date?) -> String {
        guard let date else { return "—" }
        let formatter = DateFormatter()
        formatter.dateStyle = .medium
        formatter.timeStyle = .short
        return formatter.string(from: date)
    }

    private func debugAgeText(for date: Date?) -> String {
        guard let date else { return "—" }
        let seconds = max(0, Int(Date().timeIntervalSince(date)))
        if seconds < 60 {
            return "\(seconds)s"
        }
        let minutes = seconds / 60
        if minutes < 60 {
            return "\(minutes)m"
        }
        let hours = minutes / 60
        if hours < 48 {
            return "\(hours)h"
        }
        return "\(hours / 24)d"
    }

    private func debugFreshnessState(for date: Date?, staleAfter: TimeInterval) -> DebugFreshnessState {
        guard let date else { return .missing }
        return Date().timeIntervalSince(date) > staleAfter ? .stale : .fresh
    }

    private func healthDiagnosticsValue(prefix: String, metric: String) -> String? {
        UserDefaults.standard.string(forKey: "gaia.hk.\(prefix).\(metric)")?.trimmingCharacters(in: .whitespacesAndNewlines)
    }

    private func healthDiagnosticsDate(prefix: String, metric: String) -> Date? {
        parseDebugDate(healthDiagnosticsValue(prefix: prefix, metric: metric))
    }

    private func billingPlan(for entitlements: [Entitlement], hasAccessToken: Bool) -> MembershipPlan {
        guard hasAccessToken else { return .free }
        if entitlements.contains(where: { ($0.isActive == true) && $0.key.lowercased().contains("pro") }) {
            return .pro
        }
        if entitlements.contains(where: { ($0.isActive == true) && $0.key.lowercased().contains("plus") }) {
            return .plus
        }
        return MembershipPlan(rawValue: cachedPlanRaw) ?? .free
    }

    private var hasPlusAccess: Bool {
        if dashboardPayload?.entitled == true {
            return true
        }
        let plan = MembershipPlan(rawValue: cachedPlanRaw) ?? .free
        return plan == .plus || plan == .pro
    }

    @MainActor
    private func refreshBillingDiagnostics(showSuccessMessage: Bool = false) async {
        debugEntitlementsError = nil
        debugEntitlementsLoading = true
        defer { debugEntitlementsLoading = false }

        auth.loadFromKeychain()
        let token = await auth.validAccessToken()
        _ = await auth.resolveSupabaseUserId()
        await revenueCat.identifyIfNeeded(appUserID: auth.currentSupabaseUserId())
        await revenueCat.refreshProducts(appUserID: auth.currentSupabaseUserId())
        await revenueCat.refreshCustomerInfo(appUserID: auth.currentSupabaseUserId())

        guard let token, !token.isEmpty else {
            debugEntitlements = []
            debugEntitlementsUserId = auth.supabaseUserId
            debugEntitlementsEmail = auth.supabaseEmail
            cachedPlanRaw = MembershipPlan.free.rawValue
            if showSuccessMessage {
                debugToolkitMessage = "No signed-in billing session on this device."
            }
            return
        }

        do {
            let service = try CheckoutService()
            let response = try await service.fetchEntitlements(accessToken: token)
            debugEntitlements = response.entitlements
            debugEntitlementsUserId = response.userId ?? auth.supabaseUserId
            debugEntitlementsEmail = response.email ?? auth.supabaseEmail
            let resolvedPlan = billingPlan(for: response.entitlements, hasAccessToken: true)
            cachedPlanRaw = resolvedPlan.rawValue
            cachedPlanSyncedAt = ISO8601DateFormatter().string(from: Date())
            if showSuccessMessage {
                debugToolkitMessage = "Entitlements refreshed."
            }
        } catch {
            debugEntitlementsError = error.localizedDescription
            if showSuccessMessage {
                debugToolkitMessage = "Entitlement refresh failed."
            }
        }
    }

    @MainActor
    private func restorePurchasesForDebug() async {
        let userID = await auth.resolveSupabaseUserId()
        do {
            let plan = try await revenueCat.restore(appUserID: userID)
            cachedPlanRaw = plan.rawValue
            cachedPlanSyncedAt = ISO8601DateFormatter().string(from: Date())
            await refreshBillingDiagnostics(showSuccessMessage: false)
            debugToolkitMessage = "RevenueCat restore completed."
        } catch {
            debugEntitlementsError = error.localizedDescription
            debugToolkitMessage = "RevenueCat restore failed."
        }
    }

    private func decodedPatternsPayloadFromCache() -> UserPatternsPayload? {
        guard !userPatternsCacheJSON.isEmpty,
              let data = userPatternsCacheJSON.data(using: .utf8) else { return nil }
        return try? JSONDecoder().decode(UserPatternsPayload.self, from: data)
    }

    private func healthObjectType(for option: HealthPermissionOption) -> HKObjectType? {
        switch option {
        case .heartRate:
            return HKObjectType.quantityType(forIdentifier: .heartRate)
        case .heartRateVariability:
            return HKObjectType.quantityType(forIdentifier: .heartRateVariabilitySDNN)
        case .sleep:
            return HKObjectType.categoryType(forIdentifier: .sleepAnalysis)
        case .spo2:
            return HKObjectType.quantityType(forIdentifier: .oxygenSaturation)
        case .respiratoryRate:
            return HKObjectType.quantityType(forIdentifier: .respiratoryRate)
        case .restingHeartRate:
            return HKObjectType.quantityType(forIdentifier: .restingHeartRate)
        case .bloodPressure:
            return HKObjectType.correlationType(forIdentifier: .bloodPressure)
        case .wristTemperature:
            if #available(iOS 16.0, *) {
                return HKObjectType.quantityType(forIdentifier: .appleSleepingWristTemperature)
            }
            return nil
        case .cycleTracking:
            return HKObjectType.categoryType(forIdentifier: .menstrualFlow)
        case .stepCount:
            return HKObjectType.quantityType(forIdentifier: .stepCount)
        }
    }

    private func healthPermissionStatus(for option: HealthPermissionOption, metric: String) -> String {
        guard HKHealthStore.isHealthDataAvailable() else { return "Unavailable" }
        guard let objectType = healthObjectType(for: option) else { return "Unsupported" }

        let isSelected = state.selectedHealthPermissionKeys.contains(option.rawValue)
        guard isSelected else { return "Not selected" }

        let backgroundStatus = healthDiagnosticsValue(prefix: "bg_delivery_status", metric: metric)?.lowercased()
        let backgroundError = healthDiagnosticsValue(prefix: "bg_delivery_error", metric: metric)?.lowercased() ?? ""
        let lastObserverAt = healthDiagnosticsDate(prefix: "observer_event", metric: metric)
        let lastAnchorAt = healthDiagnosticsDate(prefix: "anchor_advanced", metric: metric)
        let lastSampleAt = healthDiagnosticsDate(prefix: "last_sample", metric: metric)
        let sourceHint = healthDiagnosticsValue(prefix: "last_source", metric: metric)

        if lastSampleAt != nil || sourceHint != nil {
            return "Read active"
        }
        if lastObserverAt != nil || lastAnchorAt != nil {
            return "Read active"
        }
        if backgroundStatus == "enabled" {
            return "Read enabled"
        }
        if backgroundStatus == "skipped" {
            return "Selected"
        }
        if backgroundStatus == "failed" {
            if backgroundError.contains("not authorized") || backgroundError.contains("authorization") || backgroundError.contains("denied") {
                return "Likely denied"
            }
            return "Verification failed"
        }

        let sharingStatus = HKHealthStore().authorizationStatus(for: objectType)
        if sharingStatus == .sharingAuthorized {
            return "Authorized"
        }
        if !state.healthkitRequestedAtISO.isEmpty {
            return "Requested / pending evidence"
        }
        return "Not requested"
    }

    private func makeFreshnessItem(
        id: String,
        title: String,
        date: Date?,
        staleAfter: TimeInterval,
        endpoint: String,
        sourceKind: String,
        detail: String? = nil
    ) -> DebugFreshnessItem {
        DebugFreshnessItem(
            id: id,
            title: title,
            endpoint: endpoint,
            sourceKind: sourceKind,
            updatedAt: date,
            state: debugFreshnessState(for: date, staleAfter: staleAfter),
            detail: detail
        )
    }

    private var debugHealthMetricItems: [DebugHealthMetricItem] {
        let specs: [(String, String, HealthPermissionOption)] = [
            ("heart_rate", "Heart rate", .heartRate),
            ("sleep_stage", "Sleep", .sleep),
            ("hrv_sdnn", "HRV", .heartRateVariability),
            ("spo2", "SpO2", .spo2),
            ("respiratory_rate", "Respiratory rate", .respiratoryRate),
        ]
        return specs.map { metric, title, option in
            let backgroundStatus = healthDiagnosticsValue(prefix: "bg_delivery_status", metric: metric)?.capitalized ?? "Unknown"
            let sourceHint = healthDiagnosticsValue(prefix: "last_source", metric: metric)
            let derivedAt = debugMartBackedMetricDate(for: metric)
            return DebugHealthMetricItem(
                id: metric,
                title: title,
                permissionStatus: healthPermissionStatus(for: option, metric: metric),
                backgroundDeliveryStatus: backgroundStatus,
                lastObserverAt: healthDiagnosticsDate(prefix: "observer_event", metric: metric),
                lastAnchorAt: healthDiagnosticsDate(prefix: "anchor_advanced", metric: metric),
                lastSampleAt: healthDiagnosticsDate(prefix: "last_sample", metric: metric),
                sourceHint: sourceHint,
                derivedAt: derivedAt,
                derivedSource: derivedAt == nil ? nil : "daily_features mart"
            )
        }
    }

    private var debugRawHealthImportDate: Date? {
        let dates = [
            StatusStore.shared.lastUpload(for: "heart_rate"),
            StatusStore.shared.lastUpload(for: "sleep_stage"),
            StatusStore.shared.lastUpload(for: "hrv_sdnn"),
            StatusStore.shared.lastUpload(for: "spo2"),
            StatusStore.shared.lastUpload(for: "respiratory_rate"),
            parseDebugDate(state.lastHealthBackfillAtISO)
        ].compactMap { $0 }
        return dates.max()
    }

    private var debugSelectedFeatures: FeaturesToday? {
        features ?? lastKnownFeatures
    }

    private var debugMartBackedHealthDate: Date? {
        guard let selected = debugSelectedFeatures, bodyMetricScore(for: selected) > 0 else {
            return nil
        }
        return parseDebugDate(selected.updatedAt)
    }

    private func debugMartBackedMetricDate(for metric: String) -> Date? {
        guard let selected = debugSelectedFeatures,
              debugMetricHasMartEvidence(metric, features: selected) else {
            return nil
        }
        return parseDebugDate(selected.updatedAt)
    }

    private func debugMetricHasMartEvidence(_ metric: String, features: FeaturesToday) -> Bool {
        switch metric {
        case "heart_rate":
            return [
                features.hrMin,
                features.hrMax,
                features.restingHrAvg,
                features.restingHrBaselineDelta,
            ].contains { $0?.value != nil }
        case "sleep_stage":
            return [
                features.sleepTotalMinutes,
                features.remM,
                features.coreM,
                features.deepM,
                features.awakeM,
                features.inbedM,
                features.sleepEfficiency,
                features.sleepDebtProxy,
                features.sleepVs14dBaselineDelta,
            ].contains { $0?.value != nil }
        case "hrv_sdnn":
            return features.hrvAvg?.value != nil
        case "spo2":
            return features.spo2AvgDisplay != nil
        case "respiratory_rate":
            return [
                features.respiratoryRateAvg,
                features.respiratoryRateSleepAvg,
                features.respiratoryRateBaselineDelta,
            ].contains { $0?.value != nil }
        default:
            return false
        }
    }

    private var debugHealthImportDate: Date? {
        switch (debugRawHealthImportDate, debugMartBackedHealthDate) {
        case let (raw?, mart?):
            return max(raw, mart)
        case let (raw?, nil):
            return raw
        case let (nil, mart?):
            return mart
        default:
            return nil
        }
    }

    private var debugSleepFreshnessNote: String {
        let rawSleepDate = debugHealthMetricItems.first(where: { $0.id == "sleep_stage" })?.lastSampleAt
        let martSleepDate = debugMartBackedMetricDate(for: "sleep_stage")
        if let martSleepDate {
            if let rawSleepDate {
                let rawHours = Date().timeIntervalSince(rawSleepDate) / 3600.0
                if rawHours > 36, martSleepDate > rawSleepDate {
                    return "Sleep metrics are current in the daily_features row. Raw HealthKit sleep sample evidence is older (\(Int(rawHours.rounded()))h since the last tracked sample)."
                }
            }
            return "Sleep metrics are current in the daily_features row."
        }
        guard let rawSleepDate else {
            return "No imported sleep-stage sample is tracked yet."
        }
        let hours = Date().timeIntervalSince(rawSleepDate) / 3600.0
        if hours > 36 {
            return "Sleep import looks stale (\(Int(hours.rounded()))h since the last imported sleep sample)."
        }
        return "Sleep import is within the expected freshness window."
    }

    private var debugFreshnessItems: [DebugFreshnessItem] {
        let selected = debugSelectedFeatures
        let earthscopePersonal = preferredEarthscopePost(dashboardPayload?.personalPost, requestedDay: chicagoTodayString())
        let earthscopeMember = preferredEarthscopePost(dashboardPayload?.memberPost, requestedDay: chicagoTodayString())
        let earthscopePublic = preferredEarthscopePost(dashboardPayload?.publicPost, requestedDay: chicagoTodayString())
        let earthscopePost = earthscopePersonal ?? earthscopeMember ?? earthscopePublic
        let earthscopeKind: String = {
            if earthscopePersonal != nil { return "personal_post" }
            if earthscopeMember != nil { return "member_post" }
            if earthscopePublic != nil { return "public_post" }
            return "missing"
        }()
        let patternsPayload = decodedPatternsPayloadFromCache()
        let patternsDate = parseDebugDate(patternsPayload?.generatedAt) ?? dashboardLastFetchAt
        let schumannDate = parseDebugDate(selected?.updatedAt) ?? dashboardLastFetchAt
        let healthImportSourceKind: String = {
            guard let martDate = debugMartBackedHealthDate else {
                return "healthkit"
            }
            if let rawDate = debugRawHealthImportDate, rawDate > martDate {
                return "healthkit"
            }
            return "daily_features"
        }()
        let healthImportEndpoint = healthImportSourceKind == "daily_features"
            ? "daily_features / HealthKitBackgroundSync"
            : "HealthKitBackgroundSync"
        let healthImportDetail: String? = {
            guard let martDate = debugMartBackedHealthDate else {
                return nil
            }
            if let rawDate = debugRawHealthImportDate, rawDate < martDate {
                return "Body metrics are current in the daily_features row. Raw HealthKit upload evidence is older."
            }
            return "Body metrics are current in the daily_features row."
        }()

        let dashboardSnapshotDate = dashboardLastFetchAt == .distantPast
            ? dashboardSnapshotReferenceDate(from: dashboardPayload ?? decodeDashboardPayload(from: dashboardPayloadCacheJSON))
            : dashboardLastFetchAt

        return [
            makeFreshnessItem(
                id: "dashboard",
                title: "Dashboard snapshot",
                date: dashboardSnapshotDate,
                staleAfter: 30 * 60,
                endpoint: "v1/dashboard?day=\(chicagoTodayString())",
                sourceKind: dashboardLastUpdatedText == "cached" ? "cache" : "api",
                detail: dashboardLastUpdatedText == "cached" ? "Using cached dashboard payload." : nil
            ),
            makeFreshnessItem(
                id: "earthscope",
                title: "EarthScope snapshot",
                date: parseDebugDate(earthscopePost?.updatedAt),
                staleAfter: 18 * 60 * 60,
                endpoint: "v1/dashboard / v1/earthscope/member",
                sourceKind: earthscopeKind,
                detail: earthscopePost?.title ?? earthscopePost?.caption
            ),
            makeFreshnessItem(
                id: "local_weather",
                title: "Local weather",
                date: parseDebugDate(localHealth?.asof),
                staleAfter: 2 * 60 * 60,
                endpoint: "v1/local/check?zip=\(sanitizedZip(localHealthZip))",
                sourceKind: profileUseGPS ? "gps" : "zip"
            ),
            makeFreshnessItem(
                id: "aqi_allergens",
                title: "AQI / allergens",
                date: parseDebugDate(localHealth?.allergens?.updatedAt) ?? parseDebugDate(localHealth?.asof),
                staleAfter: 2 * 60 * 60,
                endpoint: "v1/local/check?zip=\(sanitizedZip(localHealthZip))",
                sourceKind: localHealth?.allergens?.source ?? "local_check"
            ),
            makeFreshnessItem(
                id: "space_weather",
