    @MainActor
    private func applyUserOutlook(_ payload: UserForecastOutlook) {
        userOutlook = payload
        let preserved = mergedUserOutlook(payload, fallback: lastKnownUserOutlook)
        lastKnownUserOutlook = preserved
        if let encoded = try? JSONEncoder().encode(preserved), let json = String(data: encoded, encoding: .utf8) {
            userOutlookCacheJSON = json
        }
    }

    private func fetchSpaceVisuals() async {
        if let payload = await state.fetchSpaceVisuals() {
            await MainActor.run { applySpaceVisuals(payload) }
        } else if let cached = decodeSpaceVisuals(from: spaceVisualsCacheJSON) {
            await MainActor.run { lastKnownSpaceVisuals = cached }
        }
    }

    private func fetchSpaceOutlook(days: Int = 7, force: Bool = false) async {
        let normalizedDays = max(1, min(7, days))
        let shouldStart = await MainActor.run { () -> Bool in
            let availableDays = max(
                spaceOutlook?.forecastDaily?.count ?? 0,
                lastKnownSpaceOutlook?.forecastDaily?.count ?? 0
            )
            if spaceOutlookFetchInFlight {
                pendingSpaceOutlookFetchDays = max(pendingSpaceOutlookFetchDays, normalizedDays)
                return false
            }
            if !force &&
                availableDays >= normalizedDays &&
                spaceOutlookLastFetchedDays >= normalizedDays &&
                Date().timeIntervalSince(spaceOutlookLastFetchAt) < 90 {
                return false
            }
            spaceOutlookFetchInFlight = true
            spaceOutlookRequestedDays = normalizedDays
            return true
        }
        guard shouldStart else { return }
        defer {
            Task { @MainActor in
                let followUpDays = pendingSpaceOutlookFetchDays
                let requestedDays = spaceOutlookRequestedDays
                pendingSpaceOutlookFetchDays = 0
                spaceOutlookRequestedDays = 0
                spaceOutlookFetchInFlight = false
                spaceOutlookLastFetchAt = Date()
                if followUpDays > requestedDays {
                    Task { await fetchSpaceOutlook(days: followUpDays, force: true) }
                }
            }
        }
        let api = state.apiWithAuth()
        let endpoint = "v1/space/forecast/outlook?days=\(normalizedDays)"
        do {
            let payload: SpaceForecastOutlook = try await api.getJSON(endpoint, as: SpaceForecastOutlook.self, perRequestTimeout: 30)
            await MainActor.run {
                applySpaceOutlook(payload)
                spaceOutlookLastFetchedDays = max(spaceOutlookLastFetchedDays, payload.forecastDaily?.count ?? 0)
            }
            return
        } catch is CancellationError {
            return
        } catch let uerr as URLError where uerr.code == .cancelled {
            return
        } catch {
            appLog("[UI] space outlook error: \(error.localizedDescription)")
            if let cached = decodeSpaceOutlook(from: spaceOutlookCacheJSON) {
                await MainActor.run { lastKnownSpaceOutlook = cached }
                return
            }
            do {
                let env: Envelope<SpaceForecastOutlook> = try await api.getJSON(endpoint, as: Envelope<SpaceForecastOutlook>.self, perRequestTimeout: 30)
                if let payload = env.payload {
                    await MainActor.run {
                        applySpaceOutlook(payload)
                        spaceOutlookLastFetchedDays = max(spaceOutlookLastFetchedDays, payload.forecastDaily?.count ?? 0)
                    }
                } else {
                    appLog("[UI] space outlook payload missing; keeping last snapshot")
                }
            } catch {
                appLog("[UI] space outlook fallback decode failed: \(error.localizedDescription)")
            }
        }
    }

    private func fetchUserOutlook() async {
        let backendAvailable = await MainActor.run { state.backendDBAvailable }
        if !backendAvailable, let cached = decodeUserOutlook(from: userOutlookCacheJSON) {
            await MainActor.run { lastKnownUserOutlook = cached }
        }
        await MainActor.run {
            userOutlookLoading = true
            userOutlookError = nil
        }
        let api = state.apiWithAuth()
        do {
            let payload: UserForecastOutlook = try await api.getJSON("v1/users/me/outlook", as: UserForecastOutlook.self, perRequestTimeout: 30)
            await MainActor.run {
                if payload.ok == false {
                    userOutlookError = payload.error ?? "Outlook unavailable"
                } else {
                    applyUserOutlook(payload)
                }
                userOutlookLoading = false
            }
        } catch is CancellationError {
            await MainActor.run { userOutlookLoading = false }
        } catch let uerr as URLError where uerr.code == .cancelled {
            await MainActor.run { userOutlookLoading = false }
        } catch {
            if let cached = decodeUserOutlook(from: userOutlookCacheJSON) {
                await MainActor.run { lastKnownUserOutlook = cached }
            }
            await MainActor.run {
                userOutlookError = error.localizedDescription
                userOutlookLoading = false
            }
        }
    }

    private func applyBackendAuthHeaders(to request: inout URLRequest) {
        let supabaseBearer = auth.supabaseAccessToken?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
        if !supabaseBearer.isEmpty {
            request.setValue("Bearer \(supabaseBearer)", forHTTPHeaderField: "Authorization")
            return
        }

        let bearer = state.bearer.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !bearer.isEmpty else { return }
        request.setValue("Bearer \(bearer)", forHTTPHeaderField: "Authorization")

        let bearerLower = bearer.lowercased()
        let isDeveloperBearer = bearerLower == DeveloperAuthDefaults.bearer.lowercased() || bearerLower.contains("gaia-dev")
        let devUser = state.userId.trimmingCharacters(in: .whitespacesAndNewlines)
        if isDeveloperBearer, !devUser.isEmpty, devUser.lowercased() != "anonymous" {
            request.setValue(devUser, forHTTPHeaderField: "X-Dev-UserId")
        }
    }

    private func hasBackendAuthHeader() -> Bool {
        let supabaseBearer = auth.supabaseAccessToken?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
        if !supabaseBearer.isEmpty {
            return true
        }
        return !state.bearer.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty
    }

    private func ensureBackendIdentity(reason: String) async -> Bool {
        auth.loadFromKeychain()
        if let token = await auth.validAccessToken(), !token.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty {
            await MainActor.run {
                handleAuthScopeChangeIfNeeded()
            }
            return true
        }

        do {
            try await auth.signInAnonymously()
            await MainActor.run {
                handleAuthScopeChangeIfNeeded()
            }
            appLog("[AUTH] backend identity ready via anonymous session reason=\(reason)")
            return true
        } catch {
            appLog("[AUTH] anonymous backend identity failed reason=\(reason): \(String(describing: error))")
            return false
        }
    }

    private func continueOnboardingWithoutAccount() async -> Bool {
        await MainActor.run {
            onboardingAccountBusy = true
            onboardingAccountMessage = nil
        }
        let ok = await ensureBackendIdentity(reason: "onboarding continue without account")
        await MainActor.run {
            onboardingAccountBusy = false
            onboardingAccountMessage = ok
                ? "App-only account ready. You can add email later for website access."
                : "Could not prepare the app account. Check connection and try again."
        }
        return ok
    }

    private func signInForOnboarding(email: String, password: String) async -> Bool {
        await MainActor.run {
            onboardingAccountBusy = true
            onboardingAccountMessage = nil
        }
        do {
            try await auth.signInWithPassword(email: email, password: password)
            await MainActor.run {
                handleAuthScopeChangeIfNeeded()
                onboardingAccountBusy = false
                onboardingAccountMessage = "Signed in."
            }
            await fetchProfileSettings()
            return true
        } catch {
            await MainActor.run {
                onboardingAccountBusy = false
                onboardingAccountMessage = error.localizedDescription
            }
            return false
        }
    }

    private func createAccountForOnboarding(email: String, password: String) async -> Bool {
        await MainActor.run {
            onboardingAccountBusy = true
            onboardingAccountMessage = nil
        }
        do {
            let signedIn = try await auth.createAccountWithPassword(email: email, password: password)
            await MainActor.run {
                if signedIn {
                    handleAuthScopeChangeIfNeeded()
                    onboardingAccountMessage = "Account created."
                } else {
                    onboardingAccountMessage = "Check your email to verify the account, then sign in here."
                }
                onboardingAccountBusy = false
            }
            if signedIn {
                await fetchProfileSettings()
            }
            return signedIn
        } catch {
            await MainActor.run {
                onboardingAccountBusy = false
                onboardingAccountMessage = error.localizedDescription
            }
            return false
        }
    }

    private func putJSON<Body: Encodable, Resp: Decodable>(_ path: String, body: Body, as responseType: Resp.Type) async throws -> Resp {
        let clean = path.hasPrefix("/") ? String(path.dropFirst()) : path
        guard var url = URL(string: state.baseURLString.trimmingCharacters(in: .whitespacesAndNewlines)) else {
            throw URLError(.badURL)
        }
        url.appendPathComponent(clean)
        var req = URLRequest(url: url)
        req.httpMethod = "PUT"
        req.timeoutInterval = 30
        req.setValue("application/json", forHTTPHeaderField: "Content-Type")
        req.setValue("application/json", forHTTPHeaderField: "Accept")
        applyBackendAuthHeaders(to: &req)
        let encoder = JSONEncoder()
        req.httpBody = try encoder.encode(body)
        let (data, response) = try await URLSession.shared.data(for: req)
        let code = (response as? HTTPURLResponse)?.statusCode ?? -1
        guard (200...299).contains(code) else {
            throw DecodingPreviewError(endpoint: path, preview: String(data: data, encoding: .utf8) ?? "", underlying: URLError(.badServerResponse))
        }
        let decoder = JSONDecoder()
        decoder.keyDecodingStrategy = .convertFromSnakeCase
        return try decoder.decode(Resp.self, from: data)
    }

    private func decodeDashboardPayload(from json: String) -> DashboardPayload? {
        guard !json.isEmpty, let data = json.data(using: .utf8) else { return nil }
        let decoder = JSONDecoder()
        decoder.keyDecodingStrategy = .convertFromSnakeCase
        return try? decoder.decode(DashboardPayload.self, from: data)
    }

    private func currentEarthscopePost(_ post: DashboardEarthscopePost?, requestedDay: String) -> DashboardEarthscopePost? {
        guard let post else { return nil }
        let day = (post.day ?? "").trimmingCharacters(in: .whitespacesAndNewlines)
        guard !day.isEmpty, day == requestedDay else { return nil }
        return post
    }

    private func preferredEarthscopePost(_ post: DashboardEarthscopePost?, requestedDay: String) -> DashboardEarthscopePost? {
        if let current = currentEarthscopePost(post, requestedDay: requestedDay) {
            return current
        }
        guard let post else { return nil }
        let hasVisibleContent =
            !(post.title ?? "").trimmingCharacters(in: .whitespacesAndNewlines).isEmpty ||
            !(post.caption ?? "").trimmingCharacters(in: .whitespacesAndNewlines).isEmpty ||
            !(post.bodyMarkdown ?? "").trimmingCharacters(in: .whitespacesAndNewlines).isEmpty
        return hasVisibleContent ? post : nil
    }

    private func compactEarthscopeSummary(_ values: [String?], maxCount: Int) -> String? {
        var cleaned: [String] = []
        for value in values {
            let trimmed = value?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
            if trimmed.isEmpty || cleaned.contains(trimmed) {
                continue
            }
            cleaned.append(trimmed)
            if cleaned.count >= maxCount {
                break
            }
        }
        guard !cleaned.isEmpty else { return nil }
        return cleaned.joined(separator: " ")
    }

    private func earthscopeSemanticSummary(from post: DashboardEarthscopePost?) -> String? {
        guard let semantic = post?.metricsJson?.voiceSemantic else { return nil }
        let symptomPreview = semantic.facts?.symptomPhrases?.first
        let primaryAction = semantic.actions?.primary?.first?.label

        switch semantic.kind {
        case "earthscope_member_post":
            return compactEarthscopeSummary(
                [
                    semantic.interpretation?.seedSummary,
                    semantic.interpretation?.seedNowText,
                    symptomPreview.map { "You may notice \($0)." },
                    primaryAction,
                ],
                maxCount: 2
            )
        case "earthscope_summary":
            return compactEarthscopeSummary(
                [
                    semantic.interpretation?.seedDailyBrief,
                    semantic.interpretation?.themeSentence,
                    primaryAction,
                ],
                maxCount: 2
            )
        default:
            return compactEarthscopeSummary(
                [
                    semantic.interpretation?.seedDailyBrief,
                    semantic.interpretation?.themeSentence,
                    primaryAction,
                ],
                maxCount: 1
            )
        }
    }

    private var guideEarthscopeSummary: String? {
        let summary = dashboardPayload?.earthscopeSummary?.trimmingCharacters(in: .whitespacesAndNewlines)
        if let summary, !summary.isEmpty {
            return summary
        }
        let requestedDay = dashboardPayload?.day ?? chicagoTodayString()
        let personalPost = preferredEarthscopePost(dashboardPayload?.personalPost, requestedDay: requestedDay)
        let memberPost = preferredEarthscopePost(dashboardPayload?.memberPost, requestedDay: requestedDay)
        let publicPost = preferredEarthscopePost(dashboardPayload?.publicPost, requestedDay: requestedDay)
        return personalPost?.caption
            ?? earthscopeSemanticSummary(from: personalPost)
            ?? memberPost?.caption
            ?? earthscopeSemanticSummary(from: memberPost)
            ?? publicPost?.caption
            ?? earthscopeSemanticSummary(from: publicPost)
    }

    private var guideEarthscopeUpdatedAt: String? {
        let requestedDay = dashboardPayload?.day ?? chicagoTodayString()
        return preferredEarthscopePost(dashboardPayload?.personalPost, requestedDay: requestedDay)?.updatedAt
            ?? preferredEarthscopePost(dashboardPayload?.memberPost, requestedDay: requestedDay)?.updatedAt
            ?? preferredEarthscopePost(dashboardPayload?.publicPost, requestedDay: requestedDay)?.updatedAt
    }

    private func bestEffortDashboardJSON<T: Decodable>(
        api: APIClient,
        path: String,
        as type: T.Type,
        timeout: TimeInterval,
        label: String
    ) async -> T? {
        do {
            return try await api.getJSON(path, as: type, retries: 0, perRequestTimeout: timeout)
        } catch let error as URLError where error.code == .timedOut {
            appLog("[UI] \(label) timed out: \(path)")
            return nil
        } catch {
            appLog("[UI] \(label) skipped: \(error.localizedDescription)")
            return nil
        }
    }

    private func signalBarSchumannPill(from envelope: SignalBarSchumannLatestEnvelope) -> SignalPill? {
        guard let amplitude = envelope.amplitude?.srTotal020 else {
            return nil
        }

        let value: String
        let state: SignalBarState
        switch amplitude {
        case ..<0.03:
            value = "Calm"
            state = .quiet
        case ..<0.06:
            value = "Stable"
            state = .quiet
        case ..<0.10:
            value = "Active"
            state = .watch
        case ..<0.16:
            value = "Elevated"
            state = .elevated
        default:
            value = "Intense"
            state = .strong
        }

        return SignalPill(
            key: "schumann",
            label: "SR",
            value: value,
            state: state,
            driverKey: "schumann",
            detailTarget: "schumann",
            updatedAt: envelope.generatedAt
        )
    }

    private func fetchLiveSchumannSignalBarItem(api: APIClient) async -> SignalPill? {
        guard let envelope: SignalBarSchumannLatestEnvelope = await bestEffortDashboardJSON(
            api: api,
            path: "v1/earth/schumann/latest",
            as: SignalBarSchumannLatestEnvelope.self,
            timeout: 5,
            label: "signal bar schumann"
        ) else {
            return nil
        }
        return signalBarSchumannPill(from: envelope)
    }

    private func refreshLiveSchumannSignalBar(api: APIClient? = nil) async {
        let resolvedAPI = api ?? state.apiWithAuth()
        guard let pill = await fetchLiveSchumannSignalBarItem(api: resolvedAPI) else {
            return
        }
        await MainActor.run {
            liveSchumannSignalBarItem = pill
        }
    }

    private func fetchDashboardPayload(force: Bool = false) async {
        let shouldStart = await MainActor.run { () -> Bool in
            if dashboardFetchInFlight { return false }
            if !force, dashboardPayload != nil, Date().timeIntervalSince(dashboardLastFetchAt) < 60 {
                return false
            }
            dashboardFetchInFlight = true
            dashboardLoading = true
            dashboardError = nil
            return true
        }
        guard shouldStart else { return }

        defer {
            Task { @MainActor in
                dashboardFetchInFlight = false
                dashboardLoading = false
            }
        }

        let api = state.apiWithAuth()
        let dashboardDay = chicagoTodayString()
        let endpoint = "v1/dashboard?day=\(dashboardDay)"
        let startedAt = Date()
        let backoffs: [UInt64] = [500_000_000, 1_500_000_000]
        var lastError: Error?
        let cachedDashboardPayload = decodeDashboardPayload(from: dashboardPayloadCacheJSON)
        let hadUsableDashboardAtStart = await MainActor.run {
            dashboardPayload != nil || lastNonNilDashboardGauges != nil
        }
        let hasFallbackDashboard = hadUsableDashboardAtStart || cachedDashboardPayload != nil
        let attemptCount = (!force && hasFallbackDashboard) ? 1 : 3
        let requestTimeout: TimeInterval = hasFallbackDashboard ? 60 : 20

        for attempt in 0..<attemptCount {
            do {
                let payload: DashboardPayload = try await api.getJSON(
                    endpoint,
                    as: DashboardPayload.self,
                    retries: 0,
                    perRequestTimeout: requestTimeout
                )
                var resolvedPayload = payload
                var fallbackUsed = false
                var fallbackSourceDay: String? = nil

                let currentMemberPost = currentEarthscopePost(resolvedPayload.memberPost, requestedDay: dashboardDay)
                let currentPersonalPost = currentEarthscopePost(resolvedPayload.personalPost, requestedDay: dashboardDay)
                let currentPublicPost = currentEarthscopePost(resolvedPayload.publicPost, requestedDay: dashboardDay)
                let hasCurrentMemberEarthscope = (currentMemberPost != nil || currentPersonalPost != nil)
                let hasAvailableMemberEarthscope =
                    preferredEarthscopePost(resolvedPayload.memberPost, requestedDay: dashboardDay) != nil ||
                    preferredEarthscopePost(resolvedPayload.personalPost, requestedDay: dashboardDay) != nil

                if resolvedPayload.gauges == nil || (!hasCurrentMemberEarthscope && !hasAvailableMemberEarthscope) {
                    if let memberEnv: MemberEarthscopeEnvelope = await bestEffortDashboardJSON(
                        api: api,
                        path: "v1/earthscope/member?day=\(dashboardDay)",
                        as: MemberEarthscopeEnvelope.self,
                        timeout: 8,
                        label: "dashboard member earthscope"
                    ),
                    memberEnv.ok == true,
                    let memberPost = memberEnv.post {
                        let normalizedMember = DashboardEarthscopePost(
                            day: memberPost.day,
                            title: memberPost.title,
                            caption: memberPost.caption,
                            bodyMarkdown: memberPost.bodyMarkdown,
                            metricsJson: memberPost.metricsJson,
                            updatedAt: memberPost.updatedAt
                        )
                        resolvedPayload = DashboardPayload(
                            day: resolvedPayload.day,
                            gauges: resolvedPayload.gauges ?? memberPost.metricsJson?.gauges,
                            gaugesMeta: resolvedPayload.gaugesMeta,
                            gaugeZones: resolvedPayload.gaugeZones,
                            gaugeLabels: resolvedPayload.gaugeLabels,
                            gaugesDelta: resolvedPayload.gaugesDelta,
                            drivers: resolvedPayload.drivers,
                            signalBar: resolvedPayload.signalBar,
                            driversCompact: resolvedPayload.driversCompact,
                            primaryDriver: resolvedPayload.primaryDriver,
                            supportingDrivers: resolvedPayload.supportingDrivers,
                            patternRelevantGauges: resolvedPayload.patternRelevantGauges,
                            activePatternRefs: resolvedPayload.activePatternRefs,
                            todayPersonalThemes: resolvedPayload.todayPersonalThemes,
                            todayRelevanceExplanations: resolvedPayload.todayRelevanceExplanations,
                            healthStatusExplainer: resolvedPayload.healthStatusExplainer,
                            gaugeRecentLogBoosts: resolvedPayload.gaugeRecentLogBoosts,
                            lastSymptomUpdateAt: resolvedPayload.lastSymptomUpdateAt,
                            modalModels: resolvedPayload.modalModels,
                            earthscopeSummary: resolvedPayload.earthscopeSummary,
                            supportItems: resolvedPayload.supportItems,
                            guideState: resolvedPayload.guideState,
                            alerts: resolvedPayload.alerts,
                            entitled: resolvedPayload.entitled,
                            memberPost: currentMemberPost ?? currentPersonalPost ?? normalizedMember,
                            publicPost: currentPublicPost,
                            personalPost: currentPersonalPost
                        )
                    }
                }

                let needsGaugeFallback = resolvedPayload.gauges == nil
                let needsPaidFallback = (resolvedPayload.entitled == true) && resolvedPayload.memberPost == nil && resolvedPayload.personalPost == nil
                if needsGaugeFallback || needsPaidFallback {
                    for offset in [-1, -2, -3] {
                        let fallbackDay = chicagoDayString(offsetDays: offset)
                        let fallbackEndpoint = "v1/dashboard?day=\(fallbackDay)"
                        guard let older: DashboardPayload = await bestEffortDashboardJSON(
                            api: api,
                            path: fallbackEndpoint,
                            as: DashboardPayload.self,
                            timeout: 5,
                            label: "dashboard fallback day \(fallbackDay)"
                        ) else {
                            continue
                        }
                        let hasUsefulFallback =
                            older.gauges != nil ||
                            older.memberPost != nil ||
                            older.personalPost != nil ||
                            older.publicPost != nil
                        guard hasUsefulFallback else { continue }

                        resolvedPayload = DashboardPayload(
                            day: payload.day ?? older.day,
                            gauges: resolvedPayload.gauges ?? older.gauges,
                            gaugesMeta: resolvedPayload.gaugesMeta ?? older.gaugesMeta,
                            gaugeZones: resolvedPayload.gaugeZones ?? older.gaugeZones,
                            gaugeLabels: resolvedPayload.gaugeLabels ?? older.gaugeLabels,
                            gaugesDelta: resolvedPayload.gaugesDelta ?? older.gaugesDelta,
                            drivers: resolvedPayload.drivers ?? older.drivers,
                            signalBar: resolvedPayload.signalBar ?? older.signalBar,
                            driversCompact: resolvedPayload.driversCompact ?? older.driversCompact,
                            primaryDriver: resolvedPayload.primaryDriver ?? older.primaryDriver,
                            supportingDrivers: resolvedPayload.supportingDrivers ?? older.supportingDrivers,
                            patternRelevantGauges: resolvedPayload.patternRelevantGauges ?? older.patternRelevantGauges,
                            activePatternRefs: resolvedPayload.activePatternRefs ?? older.activePatternRefs,
                            todayPersonalThemes: resolvedPayload.todayPersonalThemes ?? older.todayPersonalThemes,
                            todayRelevanceExplanations: resolvedPayload.todayRelevanceExplanations ?? older.todayRelevanceExplanations,
                            healthStatusExplainer: resolvedPayload.healthStatusExplainer ?? older.healthStatusExplainer,
                            gaugeRecentLogBoosts: resolvedPayload.gaugeRecentLogBoosts ?? older.gaugeRecentLogBoosts,
                            lastSymptomUpdateAt: resolvedPayload.lastSymptomUpdateAt ?? older.lastSymptomUpdateAt,
                            modalModels: resolvedPayload.modalModels ?? older.modalModels,
                            earthscopeSummary: resolvedPayload.earthscopeSummary,
                            supportItems: preferLongerArray(resolvedPayload.supportItems, fallback: older.supportItems),
                            guideState: resolvedPayload.guideState ?? older.guideState,
                            alerts: (resolvedPayload.alerts?.isEmpty == false) ? resolvedPayload.alerts : older.alerts,
                            entitled: resolvedPayload.entitled ?? older.entitled,
                            memberPost: resolvedPayload.memberPost ?? resolvedPayload.personalPost ?? older.memberPost ?? older.personalPost,
                            publicPost: resolvedPayload.publicPost ?? older.publicPost,
                            personalPost: resolvedPayload.personalPost ?? older.personalPost
                        )
                        fallbackUsed = true
                        fallbackSourceDay = fallbackDay
                        break
                    }
                }

                let resolvedCurrentMemberPost = currentEarthscopePost(resolvedPayload.memberPost, requestedDay: dashboardDay)
                let resolvedCurrentPersonalPost = currentEarthscopePost(resolvedPayload.personalPost, requestedDay: dashboardDay)
                let preferredMemberPost = preferredEarthscopePost(resolvedPayload.memberPost, requestedDay: dashboardDay)
                let preferredPersonalPost = preferredEarthscopePost(resolvedPayload.personalPost, requestedDay: dashboardDay)
                let preferredPublicPost = preferredEarthscopePost(resolvedPayload.publicPost, requestedDay: dashboardDay)

                if preferredMemberPost == nil && preferredPersonalPost == nil && preferredPublicPost == nil {
                    if let features: FeaturesToday = await bestEffortDashboardJSON(
                        api: api,
                        path: "v1/features/today",
                        as: FeaturesToday.self,
                        timeout: 5,
                        label: "dashboard features fallback"
                    ),
                       (features.postTitle != nil || features.postCaption != nil || features.postBody != nil) {
                        let fallbackPublic = DashboardEarthscopePost(
                            day: features.day,
                            title: features.postTitle,
                            caption: features.postCaption,
                            bodyMarkdown: features.postBody,
                            metricsJson: nil,
                            updatedAt: features.updatedAt
                        )
                        resolvedPayload = DashboardPayload(
                            day: resolvedPayload.day,
                            gauges: resolvedPayload.gauges,
                            gaugesMeta: resolvedPayload.gaugesMeta,
                            gaugeZones: resolvedPayload.gaugeZones,
                            gaugeLabels: resolvedPayload.gaugeLabels,
                            gaugesDelta: resolvedPayload.gaugesDelta,
                            drivers: resolvedPayload.drivers,
                            signalBar: resolvedPayload.signalBar,
                            driversCompact: resolvedPayload.driversCompact,
                            primaryDriver: resolvedPayload.primaryDriver,
                            supportingDrivers: resolvedPayload.supportingDrivers,
                            patternRelevantGauges: resolvedPayload.patternRelevantGauges,
                            activePatternRefs: resolvedPayload.activePatternRefs,
                            todayPersonalThemes: resolvedPayload.todayPersonalThemes,
                            todayRelevanceExplanations: resolvedPayload.todayRelevanceExplanations,
                            healthStatusExplainer: resolvedPayload.healthStatusExplainer,
                            gaugeRecentLogBoosts: resolvedPayload.gaugeRecentLogBoosts,
                            lastSymptomUpdateAt: resolvedPayload.lastSymptomUpdateAt,
                            modalModels: resolvedPayload.modalModels,
                            earthscopeSummary: resolvedPayload.earthscopeSummary,
                            supportItems: resolvedPayload.supportItems,
                            guideState: resolvedPayload.guideState,
                            alerts: resolvedPayload.alerts,
                            entitled: resolvedPayload.entitled,
                            memberPost: preferredMemberPost,
                            publicPost: preferredEarthscopePost(fallbackPublic, requestedDay: dashboardDay),
                            personalPost: preferredPersonalPost
                        )
                    }
                }

                resolvedPayload = mergedDashboardPayload(
                    resolvedPayload,
                    fallback: cachedDashboardPayload,
                    requestedDay: dashboardDay
                )

                let encoded = try? JSONEncoder().encode(resolvedPayload)
                let json = encoded.flatMap { String(data: $0, encoding: .utf8) }
                let liveSchumannSignalBarItem = await fetchLiveSchumannSignalBarItem(api: api)
                let durationMs = Int(Date().timeIntervalSince(startedAt) * 1000.0)
                await MainActor.run {
                    if let g = resolvedPayload.gauges {
                        lastNonNilDashboardGauges = g
                    }
                    let gaugesForRender = resolvedPayload.gauges ?? lastNonNilDashboardGauges
                    let effectivePayload = DashboardPayload(
                        day: resolvedPayload.day,
                        gauges: gaugesForRender,
                        gaugesMeta: resolvedPayload.gaugesMeta,
                        gaugeZones: resolvedPayload.gaugeZones,
                        gaugeLabels: resolvedPayload.gaugeLabels,
                        gaugesDelta: resolvedPayload.gaugesDelta,
                        drivers: resolvedPayload.drivers,
                        signalBar: resolvedPayload.signalBar,
                        driversCompact: resolvedPayload.driversCompact,
                        primaryDriver: resolvedPayload.primaryDriver,
                        supportingDrivers: resolvedPayload.supportingDrivers,
                        patternRelevantGauges: resolvedPayload.patternRelevantGauges,
                        activePatternRefs: resolvedPayload.activePatternRefs,
                        todayPersonalThemes: resolvedPayload.todayPersonalThemes,
                        todayRelevanceExplanations: resolvedPayload.todayRelevanceExplanations,
                        healthStatusExplainer: resolvedPayload.healthStatusExplainer,
                        gaugeRecentLogBoosts: resolvedPayload.gaugeRecentLogBoosts,
                        lastSymptomUpdateAt: resolvedPayload.lastSymptomUpdateAt,
                        modalModels: resolvedPayload.modalModels,
                        earthscopeSummary: resolvedPayload.earthscopeSummary,
                        supportItems: resolvedPayload.supportItems,
                        guideState: resolvedPayload.guideState,
                        alerts: resolvedPayload.alerts,
                        entitled: resolvedPayload.entitled,
                        memberPost: preferredEarthscopePost(resolvedPayload.memberPost, requestedDay: dashboardDay),
                        publicPost: preferredEarthscopePost(resolvedPayload.publicPost, requestedDay: dashboardDay),
                        personalPost: preferredEarthscopePost(resolvedPayload.personalPost, requestedDay: dashboardDay)
                    )
                    dashboardPayload = effectivePayload
                    if let liveSchumannSignalBarItem {
                        self.liveSchumannSignalBarItem = liveSchumannSignalBarItem
                    }
                    if let json {
                        dashboardPayloadCacheJSON = json
                    }
                    dashboardError = nil
                    dashboardLastFetchAt = Date()
                    let out = DateFormatter()
                    out.dateStyle = .none
                    out.timeStyle = .short
                    dashboardLastUpdatedText = out.string(from: dashboardLastFetchAt)
                }
                appLog(
                    "[UI] dashboard ok: day=\(dashboardDay) ms=\(durationMs) gauges=\(resolvedPayload.gauges != nil) alerts=\(resolvedPayload.alerts?.count ?? 0) member_current=\(resolvedCurrentMemberPost != nil || resolvedCurrentPersonalPost != nil) member_available=\(preferredMemberPost != nil || preferredPersonalPost != nil) public_available=\(preferredPublicPost != nil) entitled=\(String(describing: resolvedPayload.entitled)) fallback=\(fallbackUsed) fallback_day=\(fallbackSourceDay ?? "-")"
                )
                return
            } catch {
                if isCancellationError(error) { return }
                lastError = error
                if attempt < min(backoffs.count, attemptCount - 1) {
                    try? await Task.sleep(nanoseconds: backoffs[attempt])
                }
            }
        }

        let liveSchumannSignalBarItem = await fetchLiveSchumannSignalBarItem(api: api)
        await MainActor.run {
            if dashboardPayload == nil, let cached = cachedDashboardPayload {
                dashboardPayload = cached
                dashboardLastUpdatedText = "cached"
            }
            let hasUsableDashboard = dashboardPayload != nil || lastNonNilDashboardGauges != nil
            let shouldSuppressTransientRefreshError =
                hasUsableDashboard && lastError.map(isTransientNetworkError) == true
            dashboardError = shouldSuppressTransientRefreshError
                ? nil
                : (lastError?.localizedDescription ?? "dashboard fetch failed")
            if let liveSchumannSignalBarItem {
                self.liveSchumannSignalBarItem = liveSchumannSignalBarItem
            }
        }
        if hasFallbackDashboard, lastError.map(isTransientNetworkError) == true {
            appLog("[UI] dashboard refresh suppressed transient error: \(lastError?.localizedDescription ?? "unknown")")
            return
        }
        appLog("[UI] dashboard payload error: \(lastError?.localizedDescription ?? "unknown")")
    }

    private func fetchLatestCameraCheck() async {
        let shouldStart = await MainActor.run { () -> Bool in
            if latestCameraCheckLoading {
                return false
            }
            latestCameraCheckLoading = true
            latestCameraCheckError = nil
            return true
        }
        guard shouldStart else { return }

        defer {
            Task { @MainActor in
                latestCameraCheckLoading = false
            }
        }

        do {
            let remoteSummary = try await CameraHealthSupabaseClient.shared.fetchLatestDailySummary()
            let localSummary = await CameraHealthLocalStore.shared.latestSummary()
            let summary = newestCameraCheckSummary(remote: remoteSummary, local: localSummary)
            await MainActor.run {
                latestCameraCheck = summary
                latestCameraCheckError = nil
            }
        } catch CameraHealthSupabaseError.notAuthenticated {
            let localSummary = await CameraHealthLocalStore.shared.latestSummary()
            await MainActor.run {
                latestCameraCheck = localSummary
                latestCameraCheckError = nil
            }
        } catch CameraHealthSupabaseError.missingUserId {
            let localSummary = await CameraHealthLocalStore.shared.latestSummary()
            await MainActor.run {
                latestCameraCheck = localSummary
                latestCameraCheckError = nil
            }
        } catch {
            let localSummary = await CameraHealthLocalStore.shared.latestSummary()
            await MainActor.run {
                latestCameraCheck = localSummary
                latestCameraCheckError = localSummary == nil ? "Latest check unavailable" : nil
            }
            appLog("[UI] camera check fetch error: \(error.localizedDescription)")
        }
    }

    private func newestCameraCheckSummary(remote: CameraHealthDailySummary?, local: CameraHealthDailySummary?) -> CameraHealthDailySummary? {
        switch (remote, local) {
        case let (remote?, local?):
            return (remote.captureDate ?? .distantPast) >= (local.captureDate ?? .distantPast) ? remote : local
        case let (remote?, nil):
            return remote
        case let (nil, local?):
            return local
        case (nil, nil):
            return nil
        }
    }

    private func applyExperienceProfile(_ incoming: UserExperienceProfile) {
        var resolved = incoming
        let remoteStep = incoming.onboardingStep
        let localStep = OnboardingStep(rawValue: onboardingStepRaw) ?? remoteStep
        let localIndex = OnboardingStep.ordered.firstIndex(of: localStep) ?? 0
        let remoteIndex = OnboardingStep.ordered.firstIndex(of: remoteStep) ?? 0
        let temperatureStepIndex = OnboardingStep.ordered.firstIndex(of: .temperatureUnit) ?? 0
        if !incoming.onboardingCompleted && localIndex > remoteIndex {
            resolved.onboardingStep = localStep
        }
        if !incoming.onboardingCompleted && remoteIndex <= temperatureStepIndex {
            resolved.tempUnit = .localeDefault
        }
        if onboardingCompleted && !incoming.onboardingCompleted {
            resolved.onboardingCompleted = true
        }
        resolved.favoriteSymptomCodes = _normalizeFavoriteSymptomCodesForUI(resolved.favoriteSymptomCodes)

        experienceProfile = resolved
        guideProfileStore.sync(from: resolved)
        onboardingStepRaw = resolved.onboardingStep.rawValue
        onboardingCompleted = resolved.onboardingCompleted
        if resolved.onboardingCompleted {
            didLocationOnboarding = true
            showOnboardingFlow = false
        } else {
            showOnboardingFlow = true
        }
        if let backfillAt = resolved.lastBackfillAt, let stamp = formatUpdated(backfillAt) {
            backfillMessage = "Last import \(stamp)"
        }
    }

    private func resolvedProfileAfterSave(_ saved: UserExperienceProfile, applying update: UserExperienceProfileUpdate) -> UserExperienceProfile {
        profileAfterApplying(update, to: saved)
    }

    private func profileAfterApplying(_ update: UserExperienceProfileUpdate, to profile: UserExperienceProfile) -> UserExperienceProfile {
        var resolved = profile
        if let mode = update.mode {
            resolved.mode = mode
        }
        if let guide = update.guide {
            resolved.guide = guide
        }
        if let tone = update.tone {
            resolved.tone = tone
        }
        if let tempUnit = update.tempUnit {
            resolved.tempUnit = tempUnit
        }
        if let trackedStatKeys = update.trackedStatKeys {
            resolved.trackedStatKeys = trackedStatKeys
        }
        if let smartStatSwapEnabled = update.smartStatSwapEnabled {
            resolved.smartStatSwapEnabled = smartStatSwapEnabled
        }
        if let favoriteSymptomCodes = update.favoriteSymptomCodes {
            resolved.favoriteSymptomCodes = _normalizeFavoriteSymptomCodesForUI(favoriteSymptomCodes)
        }
        if let lunarSensitivityDeclared = update.lunarSensitivityDeclared {
            resolved.lunarSensitivityDeclared = lunarSensitivityDeclared
        }
        if let onboardingStep = update.onboardingStep {
            resolved.onboardingStep = onboardingStep
        }
        if let onboardingCompleted = update.onboardingCompleted {
            resolved.onboardingCompleted = onboardingCompleted
        }
        if let lastBackfillAt = update.lastBackfillAt {
            resolved.lastBackfillAt = lastBackfillAt
        }
        return resolved
    }

    private func _normalizeFavoriteSymptomCodesForUI(_ codes: [String]) -> [String] {
        var normalized: [String] = []
        for code in codes {
            let token = normalize(code)
            if token.isEmpty || normalized.contains(token) {
                continue
            }
            normalized.append(token)
            if normalized.count >= FavoriteSymptomPreference.maxCount {
                break
            }
        }
        return normalized
    }

    private func putProfilePreferences(_ body: UserExperienceProfileUpdate) async throws -> UserExperienceProfile {
        guard var url = URL(string: state.baseURLString.trimmingCharacters(in: .whitespacesAndNewlines)) else {
            throw URLError(.badURL)
        }
        url.appendPathComponent("v1/profile/preferences")
        var req = URLRequest(url: url)
        req.httpMethod = "PUT"
        req.timeoutInterval = 30
        req.setValue("application/json", forHTTPHeaderField: "Content-Type")
        req.setValue("application/json", forHTTPHeaderField: "Accept")
        applyBackendAuthHeaders(to: &req)
        let encoder = JSONEncoder()
        req.httpBody = try encoder.encode(body)
        let (data, response) = try await URLSession.shared.data(for: req)
        let code = (response as? HTTPURLResponse)?.statusCode ?? -1
        guard (200...299).contains(code) else {
            throw DecodingPreviewError(endpoint: "v1/profile/preferences", preview: String(data: data, encoding: .utf8) ?? "", underlying: URLError(.badServerResponse))
        }
        let decoder = JSONDecoder()
        decoder.keyDecodingStrategy = .convertFromSnakeCase
        let envelope = try decoder.decode(UserExperienceProfileEnvelope.self, from: data)
        guard envelope.ok != false else {
            let detail = [envelope.error, envelope.detail]
                .compactMap { $0?.trimmingCharacters(in: .whitespacesAndNewlines) }
                .filter { !$0.isEmpty }
                .joined(separator: " ")
            throw DecodingPreviewError(endpoint: "v1/profile/preferences", preview: detail, underlying: URLError(.badServerResponse))
        }
        return envelope.preferences ?? .default
    }

    private func postGuideSeenSignature(_ signature: String) async throws -> DashboardGuideState? {
        guard var url = URL(string: state.baseURLString.trimmingCharacters(in: .whitespacesAndNewlines)) else {
            throw URLError(.badURL)
        }
        url.appendPathComponent("v1/profile/guide/seen")
        var req = URLRequest(url: url)
        req.httpMethod = "POST"
        req.timeoutInterval = 20
        req.setValue("application/json", forHTTPHeaderField: "Content-Type")
        req.setValue("application/json", forHTTPHeaderField: "Accept")
        applyBackendAuthHeaders(to: &req)
        req.httpBody = try JSONEncoder().encode(["signature": signature])
        let (data, response) = try await URLSession.shared.data(for: req)
        let code = (response as? HTTPURLResponse)?.statusCode ?? -1
        guard (200...299).contains(code) else {
            throw DecodingPreviewError(endpoint: "v1/profile/guide/seen", preview: String(data: data, encoding: .utf8) ?? "", underlying: URLError(.badServerResponse))
        }
        let decoder = JSONDecoder()
        decoder.keyDecodingStrategy = .convertFromSnakeCase
        let envelope = try decoder.decode(DashboardGuideStateEnvelope.self, from: data)
        guard envelope.ok != false else {
            return nil
        }
        return envelope.guideState
    }

