    private func saveProfilePreferences(_ update: UserExperienceProfileUpdate) async {
        let revision = await MainActor.run { () -> Int in
            profilePreferenceSaveRevision += 1
            let revision = profilePreferenceSaveRevision
            applyExperienceProfile(profileAfterApplying(update, to: experienceProfile))
            return revision
        }
        do {
            guard await ensureBackendIdentity(reason: "save profile preferences") else {
                appLog("[UI] save profile preferences fallback: no backend auth")
                return
            }
            let saved = try await putProfilePreferences(update)
            await MainActor.run {
                guard revision == profilePreferenceSaveRevision else { return }
                applyExperienceProfile(resolvedProfileAfterSave(saved, applying: update))
            }
        } catch {
            if isCancellationError(error) { return }
            appLog("[UI] save profile preferences error: \(String(describing: error))")
        }
    }

    private func formatDeleteAccountPreflightMessage(_ result: DeleteAccountPreflightResult) -> String {
        let rowsFound = max(0, result.rowsFound ?? 0)
        let tablesWithRows = max(0, result.tablesWithRows ?? 0)
        let largestSummary = (result.largestTables ?? [])
            .prefix(3)
            .map { "\($0.table) (\($0.rows))" }
            .joined(separator: ", ")
        let issueText = (result.issues ?? [])
            .map { $0.trimmingCharacters(in: .whitespacesAndNewlines) }
            .filter { !$0.isEmpty }
            .joined(separator: " ")

        var segments: [String] = []
        if result.deleteReady == true {
            segments.append("Ready. Would delete \(rowsFound) rows across \(tablesWithRows) areas.")
        } else {
            segments.append("Preflight found setup issues.")
        }
        if !largestSummary.isEmpty {
            segments.append("Largest areas: \(largestSummary).")
        }
        if !issueText.isEmpty {
            segments.append(issueText)
        }
        return segments.joined(separator: " ")
    }

    private func runDeleteAccountPreflight() async {
        await MainActor.run {
            accountDeletionPreflightInFlight = true
            accountDeletionPreflightMessage = nil
        }

        let trimmedBase = state.baseURLString.trimmingCharacters(in: .whitespacesAndNewlines)
        guard let token = await auth.validAccessToken(), !token.isEmpty else {
            await MainActor.run {
                accountDeletionPreflightMessage = "Sign in again to run the delete preflight."
                accountDeletionPreflightInFlight = false
            }
            return
        }

        let api = APIClient(
            config: APIConfig(
                baseURLString: trimmedBase.isEmpty ? DeveloperAuthDefaults.baseURL : trimmedBase,
                bearer: token,
                timeout: 45
            )
        )

        do {
            let envelope = try await api.deleteAccountPreflight()
            if envelope.ok == false {
                let message = envelope.error?.trimmingCharacters(in: .whitespacesAndNewlines)
                throw NSError(
                    domain: "GaiaEyes",
                    code: 1,
                    userInfo: [NSLocalizedDescriptionKey: (message?.isEmpty == false ? message! : "Could not run the delete preflight.")]
                )
            }
            guard let result = envelope.payload else {
                throw NSError(
                    domain: "GaiaEyes",
                    code: 2,
                    userInfo: [NSLocalizedDescriptionKey: "Delete preflight returned no summary."]
                )
            }
            await MainActor.run {
                accountDeletionPreflightMessage = formatDeleteAccountPreflightMessage(result)
                accountDeletionPreflightInFlight = false
            }
        } catch {
            appLog("[UI] delete account preflight error: \(error.localizedDescription)")
            await MainActor.run {
                accountDeletionPreflightMessage = error.localizedDescription
                accountDeletionPreflightInFlight = false
            }
        }
    }

    private func deleteAccountFromSettings() async {
        await MainActor.run {
            accountDeletionInFlight = true
            accountDeletionMessage = nil
            accountDeletionPreflightMessage = nil
        }

        let trimmedBase = state.baseURLString.trimmingCharacters(in: .whitespacesAndNewlines)
        guard let token = await auth.validAccessToken(), !token.isEmpty else {
            await MainActor.run {
                accountDeletionMessage = "Sign in again to delete your account."
                accountDeletionInFlight = false
            }
            return
        }

        let api = APIClient(
            config: APIConfig(
                baseURLString: trimmedBase.isEmpty ? DeveloperAuthDefaults.baseURL : trimmedBase,
                bearer: token,
                timeout: 60
            )
        )

        do {
            let result = try await api.deleteAccount()
            if result.ok == false {
                let message = result.error?.trimmingCharacters(in: .whitespacesAndNewlines)
                throw NSError(
                    domain: "GaiaEyes",
                    code: 1,
                    userInfo: [NSLocalizedDescriptionKey: (message?.isEmpty == false ? message! : "Could not delete your account.")]
                )
            }
            await MainActor.run {
                accountDeletionMessage = "Your Gaia Eyes account was deleted."
                accountDeletionInFlight = false
                showMissionSettingsSheet = false
                showGuideSheet = false
                showMissionInsightsSheet = false
                showCurrentSymptomsSheet = false
                showDailyCheckInSheet = false
                dashboardPayload = nil
                dashboardError = nil
                dashboardLastUpdatedText = nil
                currentSymptomsSnapshot = nil
                dailyCheckInStatus = nil
                userOutlook = nil
                lastKnownUserOutlook = nil
            }
            auth.signOutSupabase()
        } catch {
            appLog("[UI] delete account error: \(error.localizedDescription)")
            await MainActor.run {
                accountDeletionMessage = error.localizedDescription
                accountDeletionInFlight = false
            }
        }
    }

