    private func fetchNotificationPreferences() async {
        do {
            let prefs = try await PushNotificationService.fetchPreferences()
            await MainActor.run {
                notificationPreferences = prefs
                pushPermissionGranted = PushNotificationService.storedPermissionGranted()
                pushDeviceToken = PushNotificationService.storedDeviceToken()
                notificationSettingsMessage = nil
            }
        } catch {
            if isCancellationError(error) { return }
            await MainActor.run {
                if notificationPreferences.timeZone.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty {
                    notificationPreferences.timeZone = TimeZone.current.identifier
                }
                pushPermissionGranted = PushNotificationService.storedPermissionGranted()
                pushDeviceToken = PushNotificationService.storedDeviceToken()
            }
            appLog("[UI] notification preferences fetch error: \(error.localizedDescription)")
        }
    }

    private func saveNotificationPreferences(requestAuthorizationIfNeeded: Bool = false) async {
        await MainActor.run {
            notificationSettingsSaving = true
            notificationSettingsMessage = nil
            if notificationPreferences.timeZone.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty {
                notificationPreferences.timeZone = TimeZone.current.identifier
            }
        }

        var payload = await MainActor.run { notificationPreferences }
        let permissionGranted = await MainActor.run { pushPermissionGranted }
        if requestAuthorizationIfNeeded && payload.enabled && !permissionGranted {
            let granted = await PushNotificationService.requestAuthorization()
            await MainActor.run {
                pushPermissionGranted = granted
            }
            if !granted {
                AppAnalytics.track("notifications_denied")
                await MainActor.run {
                    notificationSettingsSaving = false
                    notificationSettingsMessage = "Allow notifications in iOS Settings to finish enabling pushes."
                    notificationPreferences.enabled = false
                }
                return
            }
            await refreshPushState()
            payload = await MainActor.run { notificationPreferences }
        }

        do {
            let saved = try await PushNotificationService.savePreferences(payload)
            let synced = await PushNotificationService.syncTokenRegistration(preferences: saved)
            await MainActor.run {
                notificationPreferences = saved
                notificationSettingsSaving = false
                pushPermissionGranted = PushNotificationService.storedPermissionGranted()
                pushDeviceToken = PushNotificationService.storedDeviceToken()
                if saved.enabled && pushDeviceToken == nil {
                    notificationSettingsMessage = "Settings saved. APNs token will sync after iOS registration completes."
                } else if saved.enabled && !synced {
                    notificationSettingsMessage = "Settings saved. Push token sync is waiting on auth or APNs registration."
                } else {
                    notificationSettingsMessage = "Notification settings saved"
                }
            }
            await fetchFeaturesToday(trigger: .refresh, bypassGuard: true)
            AppAnalytics.track(saved.enabled ? "notifications_enabled" : "notifications_disabled")
        } catch {
            await MainActor.run {
                notificationSettingsSaving = false
                let message = error.localizedDescription.trimmingCharacters(in: .whitespacesAndNewlines)
                notificationSettingsMessage = message.isEmpty ? "Could not save notification settings" : message
            }
            appLog("[UI] save notification settings error: \(error.localizedDescription)")
        }
    }

    private func preferredSymptomPresets(_ presets: [SymptomPreset], favoriteCodes: [String]) -> [SymptomPreset] {
        let favoriteSet = Set(favoriteCodes.map(normalize))
        guard !favoriteSet.isEmpty else { return presets }
        let favorites = presets.filter { favoriteSet.contains(normalize($0.code)) }
        let remaining = presets.filter { !favoriteSet.contains(normalize($0.code)) }
        return favorites + remaining
    }

    private var followUpFilterPresets: [SymptomPreset] {
        let filtered = symptomPresets.filter { $0.code != SymptomCodeHelper.fallbackCode }
        return Array(preferredSymptomPresets(filtered, favoriteCodes: experienceProfile.favoriteSymptomCodes).prefix(8))
    }

    private func followUpSymptomCodeBinding(_ code: String) -> Binding<Bool> {
        let normalized = normalize(code)
        return Binding(
            get: {
                notificationPreferences.symptomFollowupSymptomCodes.contains(normalized)
            },
            set: { enabled in
                if enabled {
                    if !notificationPreferences.symptomFollowupSymptomCodes.contains(normalized) {
                        notificationPreferences.symptomFollowupSymptomCodes.append(normalized)
                    }
                } else {
                    notificationPreferences.symptomFollowupSymptomCodes.removeAll { $0 == normalized }
                }
            }
        )
    }

    private var notificationsSettingsSummaryLine: String {
        guard notificationPreferences.enabled else {
            return "Notifications off"
        }
        if notificationPreferences.symptomFollowupsEnabled {
            if let activeLabels = currentSymptomsSnapshot?.semanticActiveLabelSummary {
                return "Follow-up prompts on for \(activeLabels)"
            }
            return "Follow-up prompts on"
        }
        if notificationPreferences.dailyCheckinsEnabled {
            return "Daily check-ins on"
        }
        return "Notifications on"
    }

    private var symptomFollowUpSettingsSummaryLine: String {
        if let summary = currentSymptomsSnapshot?.semanticFollowUpSummary {
            return summary
        }
        return "Receive check-in prompts after you log a symptom so Gaia can learn how it changes over time."
    }

    private func requestHealthPermissionsForOnboarding() async -> Bool {
        await MainActor.run {
            healthPermissionsMessage = nil
        }
        AppAnalytics.track("healthkit_permission_started")
        let granted = await state.requestHealthPermissions()
        let requestedAt = await MainActor.run { state.healthkitRequestedAtISO }
        await saveProfilePreferences(UserExperienceProfileUpdate(healthkitRequested: true))
        await MainActor.run {
            if !requestedAt.isEmpty {
                experienceProfile.healthkitRequestedAt = requestedAt
            }
            healthPermissionsMessage = granted
                ? "Health access updated. Gaia will use whatever HealthKit data you allowed. If body data stays blank, open Apple Health and your wearable app once so they finish syncing, then return to Gaia."
                : "Gaia could not update Health access right now. You can keep going and retry later in Settings."
        }
        AppAnalytics.track(granted ? "healthkit_permission_completed" : "healthkit_permission_failed")
        return granted
    }

    private func runUnifiedHealthBackfill() async -> Bool {
        let alreadyRunning = await MainActor.run {
            if backfillInFlight {
                return true
            }
            backfillInFlight = true
            backfillMessage = "Preparing your 30-day Health import…"
            return false
        }
        if alreadyRunning {
            return true
        }
        AppAnalytics.track("health_backfill_started", properties: ["window": "30d"])
        let task = Task { @MainActor in
            let summary = await state.syncHealthBackfillLast30Days { message in
                backfillMessage = message
            }
            let syncStamp = state.lastHealthBackfillAtISO
            let finishedCleanly = summary.didUploadAnyData || summary.isSuccessful
            if finishedCleanly, !syncStamp.isEmpty {
                await saveProfilePreferences(UserExperienceProfileUpdate(lastBackfillAt: syncStamp))
                await fetchDashboardPayload(force: true)
                await fetchLocalHealth()
            }
            backfillInFlight = false
            if summary.didUploadAnyData {
                experienceProfile.lastBackfillAt = syncStamp.isEmpty ? experienceProfile.lastBackfillAt : syncStamp
                if let updated = formatUpdated(syncStamp) {
                    backfillMessage = "\(summary.userFacingMessage) Last sync \(updated)."
                } else {
                    backfillMessage = summary.userFacingMessage
                }
            } else if summary.isSuccessful {
                backfillMessage = summary.userFacingMessage
            } else {
                backfillMessage = summary.userFacingMessage
            }
            AppAnalytics.track(
                finishedCleanly ? "health_backfill_completed" : "health_backfill_failed",
                properties: ["window": "30d"]
            )
            backfillTask = nil
        }
        await MainActor.run {
            backfillTask = task
        }
        return true
    }

    private func handleIncomingPushRoute(_ route: GaiaPushRoute) {
        let targetType = route.targetType.trimmingCharacters(in: .whitespacesAndNewlines).lowercased()
        showMissionInsightsSheet = false
        showLocalConditionsSheet = false
        showSchumannDashboardSheet = false
        showMissionSettingsSheet = false
        showGuideSheet = false
        if targetType == "daily_checkin" {
            pendingPushRoute = nil
            openBody(route: .dailyCheckIn)
            Task { await fetchDailyCheckInStatus(api: state.apiWithAuth()) }
            return
        }
        if targetType == "guide" || targetType == "guide_hub" {
            pendingPushRoute = nil
            openGuideHub()
            return
        }
        if targetType == "daily_poll" || targetType == "daily_feedback" {
            pendingPushRoute = nil
            openGuideHub(focus: .dailyPoll)
            return
        }
        if targetType == "earthscope" || targetType == "what_matters_now" {
            pendingPushRoute = nil
            openGuideHub(focus: .earthScope)
            return
        }
        if targetType == "understanding" || targetType == "how_it_works" {
            pendingPushRoute = nil
            openGuideHub(focus: .understanding)
            return
        }
        if targetType == "current_symptoms" || targetType == "symptoms" {
            pendingPushRoute = nil
            openBody(route: .currentSymptoms)
            Task { await fetchCurrentSymptomsSummary(api: state.apiWithAuth()) }
            return
        }
        pendingPushRoute = route
    }

    private func onboardingOptions(forHealthContext healthContextOnly: Bool) -> [OnboardingTagOption] {
        let preferredKeys = healthContextOnly
            ? [
                "allergies_sinus",
                "migraine_history",
                "chronic_pain",
                "fibromyalgia",
                "nervous_system_dysregulation",
                "pots_dysautonomia",
                "insomnia_sleep_disruption",
            ]
            : [
                "pressure_sensitive",
                "pain_sensitive",
                "exertion_recovery_sensitive",
                "sleep_sensitive",
                "anxiety_sensitive",
                "geomagnetic_sensitive",
                "air_quality_sensitive",
                "temperature_sensitive",
            ]
        let fallback: [String: OnboardingTagOption] = [
            "pressure_sensitive": OnboardingTagOption(id: "pressure_sensitive", title: "Pressure Sensitive", subtitle: "Barometric swings can hit harder."),
            "pain_sensitive": OnboardingTagOption(id: "pain_sensitive", title: "Pain Sensitive", subtitle: "Pain or body flares can surface faster."),
            "exertion_recovery_sensitive": OnboardingTagOption(id: "exertion_recovery_sensitive", title: "Exertion / Recovery Sensitive", subtitle: "Heavy activity can hit harder and recovery may take longer."),
            "sleep_sensitive": OnboardingTagOption(id: "sleep_sensitive", title: "Sleep Sensitive", subtitle: "Sleep disruption affects recovery quickly."),
            "anxiety_sensitive": OnboardingTagOption(id: "anxiety_sensitive", title: "Anxiety Sensitive", subtitle: "Stress-reactive periods can hit harder."),
            "geomagnetic_sensitive": OnboardingTagOption(id: "geomagnetic_sensitive", title: "Geomagnetic Sensitive", subtitle: "Space-weather shifts may feel more noticeable."),
            "air_quality_sensitive": OnboardingTagOption(id: "air_quality_sensitive", title: "Air Quality Sensitive", subtitle: "Air irritation can affect energy or focus."),
            "temperature_sensitive": OnboardingTagOption(id: "temperature_sensitive", title: "Temperature Sensitive", subtitle: "Rapid temperature changes can throw you off."),
            "allergies_sinus": OnboardingTagOption(id: "allergies_sinus", title: "Allergies / Sinus", subtitle: "Air and seasonal triggers affect you."),
            "migraine_history": OnboardingTagOption(id: "migraine_history", title: "Migraine History", subtitle: "Head-pressure or migraine patterns matter here."),
            "chronic_pain": OnboardingTagOption(id: "chronic_pain", title: "Chronic Pain", subtitle: "Pain flare patterns matter here."),
            "fibromyalgia": OnboardingTagOption(id: "fibromyalgia", title: "Fibromyalgia", subtitle: "Pain and fatigue flares matter here."),
            "nervous_system_dysregulation": OnboardingTagOption(id: "nervous_system_dysregulation", title: "Nervous System Dysregulation", subtitle: "Overload and regulation shifts matter here."),
            "pots_dysautonomia": OnboardingTagOption(id: "pots_dysautonomia", title: "POTS / Dysautonomia", subtitle: "Circulation and autonomic changes matter here."),
            "insomnia_sleep_disruption": OnboardingTagOption(id: "insomnia_sleep_disruption", title: "Insomnia / Sleep Disruption", subtitle: "Sleep instability matters here."),
        ]

        let filtered = tagCatalog.filter { item in
            let canonicalKey = canonicalProfileTagKey(item.tagKey)
            let isHealth = healthContextTagKeys.contains(canonicalKey) || (item.section ?? "").lowercased().contains("health")
                || (item.section ?? "").lowercased().contains("context")
            return isHealth == healthContextOnly
        }
        let mapped = Dictionary(uniqueKeysWithValues: filtered.map { item in
            let canonicalKey = canonicalProfileTagKey(item.tagKey)
            return (
                canonicalKey,
                OnboardingTagOption(
                    id: canonicalKey,
                    title: item.label ?? fallback[canonicalKey]?.title ?? canonicalKey.replacingOccurrences(of: "_", with: " ").capitalized,
                    subtitle: item.description ?? fallback[canonicalKey]?.subtitle
                )
            )
        })

        var ordered: [OnboardingTagOption] = []
        for key in preferredKeys {
            if let option = mapped[key] ?? fallback[key] {
                ordered.append(option)
            }
        }
        let existing = Set(ordered.map(\.id))
        let extras = mapped.values
            .filter { !existing.contains($0.id) }
            .sorted { $0.title.localizedCaseInsensitiveCompare($1.title) == .orderedAscending }
        return ordered + extras
    }

    private var onboardingSensitivityOptions: [OnboardingTagOption] {
        onboardingOptions(forHealthContext: false)
    }

    private var onboardingHealthContextOptions: [OnboardingTagOption] {
        onboardingOptions(forHealthContext: true)
    }

    private func onboardingActivationDriverDetail(_ driver: DashboardDriverItem) -> String {
        let vocabulary = experienceProfile.mode.copyVocabulary
        let label = vocabulary.driverLabel(
            for: driver.key,
            fallback: driver.label ?? driver.key.replacingOccurrences(of: "_", with: " ").capitalized
        )
            .trimmingCharacters(in: .whitespacesAndNewlines)
        if driver.key.trimmingCharacters(in: .whitespacesAndNewlines).lowercased() == "temp",
           let value = driver.value {
            return "\(label) is running at a \(LocalConditionsFormatting.formatTemperatureDelta(value, unit: experienceProfile.tempUnit)) day-over-day swing."
        }
        let display = (vocabulary.translating(driver.display) ?? driver.display ?? "")
            .trimmingCharacters(in: .whitespacesAndNewlines)
        if !display.isEmpty {
            let prefix = "\(label): "
            if display.hasPrefix(prefix) {
                let trimmed = String(display.dropFirst(prefix.count)).trimmingCharacters(in: .whitespacesAndNewlines)
                if trimmed.split(separator: " ").count >= 4 {
                    return trimmed
                }
            }
            return display
        }
        if let state = driver.state, !state.isEmpty {
            return "\(label) is \(state.lowercased()) right now."
        }
        return "Gaia is tracking this live condition right now."
    }

    private var onboardingActivationData: OnboardingActivationData {
        let vocabulary = experienceProfile.mode.copyVocabulary
        let liveDrivers = Array((dashboardPayload?.drivers ?? []).prefix(3)).map { driver in
            OnboardingActivationDriver(
                id: driver.id,
                title: vocabulary.driverLabel(
                    for: driver.key,
                    fallback: driver.label ?? driver.key.replacingOccurrences(of: "_", with: " ").capitalized
                ),
                detail: onboardingActivationDriverDetail(driver)
            )
        }
        let fallbackDrivers = [
            OnboardingActivationDriver(
                id: "mission_control",
                title: "\(vocabulary.missionControlLabel) is live",
                detail: "Gaia is already tracking live space, Earth, and local conditions when they are available."
            ),
            OnboardingActivationDriver(
                id: "personalization",
                title: "Personalization is building",
                detail: "Your sensitivities and context already shape what Gaia ranks higher for you."
            ),
            OnboardingActivationDriver(
                id: "next_action",
                title: "Start building patterns",
                detail: "Log how you feel after onboarding and Gaia will start connecting these live signals to your own history."
            ),
        ]
        let headline: String
        if let topDriver = liveDrivers.first?.title, !topDriver.isEmpty {
            headline = "\(topDriver) is one of the clearest live signals right now."
        } else if let summary = vocabulary.translating(guideEarthscopeSummary), !summary.isEmpty {
            headline = summary
        } else {
            headline = "Your live signal stack is ready."
        }
        let explanation: String
        if let syncStamp = experienceProfile.lastBackfillAt, !syncStamp.isEmpty {
            explanation = "Gaia already has recent Health data layered into your live view. Personal patterns will sharpen as you log how you feel."
        } else {
            explanation = "Gaia can already surface the strongest live conditions shaping today. Personal patterns will build as you log symptoms and add more history."
        }
        let footer: String?
        if notificationPreferences.enabled {
            footer = "Alerts are ready to follow the same signal families you chose here. Log how you feel in \(vocabulary.missionControlLabel) to start building personal patterns."
        } else {
            footer = "Log how you feel in \(vocabulary.missionControlLabel) to start building personal patterns. You can adjust alerts and imports later in Settings."
        }
        return OnboardingActivationData(
            headline: headline,
            explanation: explanation,
            drivers: liveDrivers.isEmpty ? fallbackDrivers : liveDrivers,
            nextActionTitle: "Open \(vocabulary.missionControlLabel)",
            secondaryActionTitle: "Finish",
            footer: footer
        )
    }

    private func resolveLocationInput(zip: String, useGPS: Bool) async -> (zip: String?, lat: Double?, lon: Double?, usedGPS: Bool) {
        let cleaned = sanitizedZip(zip)
        if !useGPS {
            return (cleaned.isEmpty ? nil : cleaned, nil, nil, false)
        }
#if canImport(CoreLocation)
        let provider = await MainActor.run { locationProvider }
        if let location = await provider.requestLocation() {
            let lat = location.coordinate.latitude
            let lon = location.coordinate.longitude
            if let gpsZip = await reverseGeocodeZip(from: location), !gpsZip.isEmpty {
                return (gpsZip, lat, lon, true)
            }
            if !cleaned.isEmpty {
                return (cleaned, lat, lon, true)
            }
            return (nil, lat, lon, true)
        }
#endif
        return (cleaned.isEmpty ? nil : cleaned, nil, nil, false)
    }

#if canImport(CoreLocation)
    private func reverseGeocodeZip(from location: CLLocation) async -> String? {
        await withCheckedContinuation { continuation in
            CLGeocoder().reverseGeocodeLocation(location) { placemarks, _ in
                let zip = placemarks?.first?.postalCode?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
                continuation.resume(returning: zip.isEmpty ? nil : zip)
            }
        }
    }
#endif

    private func sanitizedZip(_ raw: String) -> String {
        let trimmed = raw.trimmingCharacters(in: .whitespacesAndNewlines)
        let filtered = trimmed.filter { $0.isLetter || $0.isNumber }
        return filtered
    }

    private func scheduleLocalHealthRefresh() {
        localZipRefreshTask?.cancel()
        localZipRefreshTask = Task {
            do {
                try await Task.sleep(nanoseconds: 600_000_000)
            } catch {
                return
            }
            await fetchLocalHealth()
        }
    }

    private func fetchLocalHealth() async {
        if !profileLocalInsightsEnabled {
            await MainActor.run {
                localHealth = nil
                localHealthError = nil
                localHealthLoading = false
            }
            return
        }
        let zip = sanitizedZip(localHealthZip)
        guard !zip.isEmpty else {
            await MainActor.run {
                localHealth = nil
                localHealthError = "Enter a ZIP code"
            }
            return
        }
        if zip != localHealthZip {
            await MainActor.run { localHealthZip = zip }
        }
        await MainActor.run {
            localHealthLoading = true
            localHealthError = nil
        }
        let api = state.apiWithAuth()
        do {
            let payload: LocalCheckResponse = try await api.getJSON("v1/local/check?zip=\(zip)", as: LocalCheckResponse.self, perRequestTimeout: 30)
            await MainActor.run {
                if payload.ok == true {
                    localHealth = payload
                    localHealthError = nil
                } else {
                    localHealth = nil
                    localHealthError = payload.error ?? "Local health unavailable"
                }
                localHealthLoading = false
            }
        } catch {
            if isCancellationError(error) {
                await MainActor.run {
                    localHealthLoading = false
                }
                return
            }
            await MainActor.run {
                localHealth = nil
                localHealthError = error.localizedDescription
                localHealthLoading = false
            }
        }
    }

    private func fetchMagnetosphere(force: Bool = false) async {
        let shouldStart = await MainActor.run { () -> Bool in
            if magnetosphereFetchInFlight {
                return false
            }
            if !force && magnetosphere != nil && Date().timeIntervalSince(magnetosphereLastFetchAt) < 90 {
                return false
            }
            magnetosphereFetchInFlight = true
            return true
        }
        guard shouldStart else { return }
        defer {
            Task { @MainActor in
                magnetosphereFetchInFlight = false
                magnetosphereLastFetchAt = Date()
            }
        }
        await MainActor.run {
            magnetosphereLoading = true
            magnetosphereError = nil
        }
        let api = state.apiWithAuth()
        do {
            let payload: MagnetosphereResponse = try await api.getJSON("v1/space/magnetosphere", as: MagnetosphereResponse.self, perRequestTimeout: 30)
            await MainActor.run {
                if payload.ok == true {
                    magnetosphere = payload.data
                    magnetosphereError = nil
                } else {
                    magnetosphere = nil
                    magnetosphereError = payload.error ?? "Magnetosphere unavailable"
                }
                magnetosphereLoading = false
            }
        } catch {
            if isCancellationError(error) {
                await MainActor.run {
                    magnetosphereLoading = false
                }
                return
            }
            await MainActor.run {
                magnetosphere = nil
                magnetosphereError = error.localizedDescription
                magnetosphereLoading = false
            }
        }
    }

    private func fetchQuakes() async {
        await MainActor.run {
            quakeLoading = true
            quakeError = nil
        }
        let api = state.apiWithAuth()
        var hadError: String? = nil
        do {
            let latest: QuakesLatestResponse = try await api.getJSON("v1/quakes/latest", as: QuakesLatestResponse.self, perRequestTimeout: 30)
            await MainActor.run { quakeLatest = latest.item }
            if latest.ok != true, let err = latest.error { hadError = err }
        } catch {
            if isCancellationError(error) {
                await MainActor.run {
                    quakeLoading = false
                }
                return
            }
            hadError = error.localizedDescription
        }
        do {
            let events: QuakesEventsResponse = try await api.getJSON("v1/quakes/events", as: QuakesEventsResponse.self, perRequestTimeout: 30)
            await MainActor.run { quakeEvents = events.items ?? [] }
            if events.ok != true, let err = events.error { hadError = err }
        } catch {
            if isCancellationError(error) {
                await MainActor.run {
                    quakeLoading = false
                }
                return
            }
            if hadError == nil { hadError = error.localizedDescription }
        }
        await MainActor.run {
            quakeError = hadError
            quakeLoading = false
        }
    }

