        private struct ModalPresentation: Identifiable {
            let id: String
            let entry: DashboardModalEntry

            var contextType: String {
                id.split(separator: ":", maxSplits: 1).first.map(String.init) ?? ""
            }

            var contextKey: String {
                let parts = id.split(separator: ":", maxSplits: 1)
                guard parts.count == 2 else { return "" }
                return String(parts[1])
            }
        }

        private struct GaugeRow: Identifiable {
            let key: String
            let label: String
            let value: Double?
            let delta: Int
            let zoneKey: String?
            let zoneLabel: String?
            let tappable: Bool
            let showAffordance: Bool

            var id: String { key }
        }

        private struct ArcGaugeCard: View {
            let row: GaugeRow
            let onTap: (() -> Void)?
            private let ringLineWidth: CGFloat = 9
            private let meterSize: CGFloat = 108

            private var valueText: String {
                guard let value = row.value else { return "—" }
                return String(Int(round(value)))
            }

            private var deltaText: String {
                let value = row.delta
                return value > 0 ? "(+\(value))" : "(\(value))"
            }

            private var deltaColor: Color {
                abs(row.delta) >= 5 ? GaugePalette.zoneColor(row.zoneKey) : .secondary
            }

            private var statusText: String {
                if row.value == nil {
                    return "Calibrating"
                }
                if let label = row.zoneLabel, !label.isEmpty {
                    return label
                }
                if let zone = row.zoneKey, !zone.isEmpty {
                    return zone.replacingOccurrences(of: "_", with: " ").capitalized
                }
                return "Calibrating"
            }

            private var zoneKeyText: String {
                guard
                    let zone = row.zoneKey,
                    !zone.isEmpty,
                    zone.lowercased() != "calibrating"
                else { return "" }
                return zone.replacingOccurrences(of: "_", with: " ").capitalized
            }

            private var progress: CGFloat? {
                guard let value = row.value else { return nil }
                return CGFloat(min(1.0, max(0.0, value / 100.0)))
            }

            private func markerPosition(in size: CGSize, progress: CGFloat) -> CGPoint {
                let diameter = min(size.width, size.height)
                let radius = max(0, (diameter * 0.5) - (ringLineWidth * 0.5))
                let center = CGPoint(x: size.width * 0.5, y: size.height * 0.5)
                let angle = ((Double(progress) * 360.0) - 90.0) * Double.pi / 180.0
                return CGPoint(
                    x: center.x + CGFloat(cos(angle)) * radius,
                    y: center.y + CGFloat(sin(angle)) * radius
                )
            }

            private var content: some View {
                VStack(alignment: .leading, spacing: 8) {
                    HStack(alignment: .firstTextBaseline, spacing: 6) {
                        Text(row.label)
                            .font(.subheadline.weight(.semibold))
                            .foregroundColor(Color.white.opacity(0.92))
                        Spacer(minLength: 4)
                        if row.showAffordance {
                            Image(systemName: "sparkles")
                                .font(.caption2)
                                .foregroundColor(GaugePalette.zoneColor(row.zoneKey))
                        }
                    }

                    ZStack {
                        Circle()
                            .stroke(GaugePalette.ringBackground, lineWidth: ringLineWidth)

                        if let progress {
                            Circle()
                                .trim(from: 0.0, to: max(0.002, progress))
                                .stroke(
                                    GaugePalette.arcGradient,
                                    style: StrokeStyle(lineWidth: ringLineWidth, lineCap: .round)
                                )
                                .rotationEffect(.degrees(-90))
                                .shadow(
                                    color: row.showAffordance
                                    ? GaugePalette
                                        .zoneColor(row.zoneKey)
                                        .opacity(GaugePalette.glowOpacity(row.zoneKey))
                                    : .clear,
                                    radius: row.showAffordance ? GaugePalette.glowRadius(row.zoneKey) : 0,
                                    x: 0,
                                    y: 0
                                )
                        }

                        GeometryReader { geo in
                            if let progress {
                                let point = markerPosition(in: geo.size, progress: progress)
                                Circle()
                                    .fill(GaugePalette.marker)
                                    .overlay(Circle().stroke(GaugePalette.zoneColor(row.zoneKey), lineWidth: 1.75))
                                    .frame(width: 10, height: 10)
                                    .position(point)
                            }
                        }

                        VStack(spacing: 2) {
                            HStack(spacing: 4) {
                                Text(valueText)
                                    .font(.system(size: 24, weight: .heavy, design: .rounded))
                                if row.value != nil {
                                    Text(deltaText)
                                        .font(.caption2)
                                        .foregroundColor(deltaColor)
                                }
                            }
                            Text(statusText)
                                .font(.caption)
                                .foregroundColor(
                                    row.value == nil
                                    ? .secondary
                                    : GaugePalette.zoneColor(row.zoneKey)
                                )
                        }
                    }
                    .frame(width: meterSize, height: meterSize)
                    .frame(maxWidth: .infinity)

                    if !zoneKeyText.isEmpty {
                        Text(zoneKeyText)
                            .font(.caption2)
                            .foregroundColor(.secondary)
                    }
                }
                .padding(10)
                .background(Color.black.opacity(0.25))
                .clipShape(RoundedRectangle(cornerRadius: 14, style: .continuous))
                .overlay(
                    RoundedRectangle(cornerRadius: 14, style: .continuous)
                        .stroke(
                            row.showAffordance
                            ? GaugePalette.zoneColor(row.zoneKey).opacity(0.45)
                            : Color.white.opacity(0.05),
                            lineWidth: row.showAffordance ? 1.2 : 1
                        )
                )
                .shadow(
                    color: row.showAffordance
                    ? GaugePalette.zoneColor(row.zoneKey).opacity(0.20)
                    : .clear,
                    radius: row.showAffordance ? 8 : 0,
                    x: 0,
                    y: 0
                )
            }

            var body: some View {
                if let onTap {
                    Button(action: onTap) {
                        content
                    }
                    .buttonStyle(.plain)
                } else {
                    content
                }
            }
        }

        private enum WhatMattersRole: String, CaseIterable {
            case leading
            case supporting
            case background

            var title: String {
                switch self {
                case .leading:
                    return "Leading now"
                case .supporting:
                    return "Also in play"
                case .background:
                    return "In the background"
                }
            }

            var subtitle: String {
                switch self {
                case .leading:
                    return "The clearest signal in your mix right now."
                case .supporting:
                    return "Still active, but not leading."
                case .background:
                    return "Present, but in the background."
                }
            }

            var maxVisible: Int {
                switch self {
                case .leading:
                    return 1
                case .supporting:
                    return 2
                case .background:
                    return 2
                }
            }

            var titleFont: Font {
                switch self {
                case .leading:
                    return .headline
                case .supporting, .background:
                    return .subheadline.weight(.semibold)
                }
            }

            func background(for zoneKey: String) -> Color {
                switch self {
                case .leading:
                    return GaugePalette.zoneColor(zoneKey).opacity(0.16)
                case .supporting:
                    return Color.black.opacity(0.26)
                case .background:
                    return Color.black.opacity(0.14)
                }
            }

            func border(for zoneKey: String) -> Color {
                switch self {
                case .leading:
                    return GaugePalette.zoneColor(zoneKey).opacity(0.62)
                case .supporting:
                    return GaugePalette.zoneColor(zoneKey).opacity(0.26)
                case .background:
                    return Color.white.opacity(0.05)
                }
            }

            func shadow(for zoneKey: String) -> Color {
                switch self {
                case .leading:
                    return GaugePalette.zoneColor(zoneKey).opacity(0.22)
                case .supporting:
                    return GaugePalette.zoneColor(zoneKey).opacity(0.10)
                case .background:
                    return .clear
                }
            }
        }

