        private struct DriverStatusRow: View {
            let driver: DashboardDriverItem
            let role: WhatMattersRole
            let tempUnit: TemperatureUnit
            let zoneKey: String
            let pillSeverity: StatusPill.Severity
            let onTap: (() -> Void)?

            private func formattedValue() -> String {
                guard let value = driver.value else { return "" }
                let unit = (driver.unit ?? "").trimmingCharacters(in: .whitespacesAndNewlines)
                let key = driver.key.lowercased()
                let text: String
                if key == "sw" || key == "solar_wind" || key == "aqi" {
                    text = String(Int(round(value)))
                } else if key == "schumann" {
                    text = String(format: "%.2f", value)
                } else if abs(value - round(value)) < 0.01 {
                    text = String(Int(round(value)))
                } else {
                    text = String(format: "%.1f", value)
                }
                if key == "temp" {
                    return LocalConditionsFormatting.formatTemperatureDelta(value, unit: tempUnit)
                }
                if unit.isEmpty { return text }
                return "\(text) \(unit)"
            }

            private var iconName: String {
                switch driver.key.lowercased() {
                case "pressure":
                    return "gauge.with.dots.needle.bottom.50percent"
                case "temp":
                    return "thermometer.medium"
                case "humidity":
                    return "humidity.fill"
                case "aqi":
                    return "aqi.low"
                case "allergens":
                    return "leaf.fill"
                case "kp":
                    return "sun.max.fill"
                case "bz":
                    return "arrow.down.circle.fill"
                case "sw", "solar_wind":
                    return "wind"
                case "schumann":
                    return "waveform.path.ecg.rectangle"
                default:
                    return "circle.hexagongrid.fill"
                }
            }

            private var summaryText: String {
                let personal = (driver.personalReason ?? "").trimmingCharacters(in: .whitespacesAndNewlines)
                if !personal.isEmpty {
                    return personal
                }
                if driver.key.trimmingCharacters(in: .whitespacesAndNewlines).lowercased() == "temp",
                   let value = driver.value {
                    return "Temperature swing is \(LocalConditionsFormatting.formatTemperatureDelta(value, unit: tempUnit)) over the last day."
                }
                let display = (driver.display ?? "").trimmingCharacters(in: .whitespacesAndNewlines)
                if !display.isEmpty {
                    return display
                }
                return "\(driver.label ?? driver.key.replacingOccurrences(of: "_", with: " ").capitalized) is \(driver.state ?? "Calm")."
            }

            private var content: some View {
                HStack(alignment: .top, spacing: 12) {
                    ZStack {
                        RoundedRectangle(cornerRadius: 14, style: .continuous)
                            .fill(Color.white.opacity(0.06))
                        Image(systemName: iconName)
                            .font(.system(size: 18, weight: .semibold))
                            .foregroundColor(GaugePalette.zoneColor(zoneKey))
                    }
                    .frame(width: 44, height: 44)

                    VStack(alignment: .leading, spacing: 10) {
                        VStack(alignment: .leading, spacing: 2) {
                            Text(driver.label ?? driver.key.replacingOccurrences(of: "_", with: " ").capitalized)
                                .font(.headline)
                                .foregroundColor(.white)
                            Text(role.title)
                                .font(.caption.weight(.semibold))
                                .foregroundColor(role == .background ? .white.opacity(0.54) : GaugePalette.zoneColor(zoneKey))
                        }

                        Text(summaryText)
                            .font(.caption)
                            .foregroundColor(.white.opacity(role == .background ? 0.58 : 0.72))
                            .fixedSize(horizontal: false, vertical: true)
                    }

                    Spacer(minLength: 8)

                    VStack(alignment: .trailing, spacing: 8) {
                        StatusPill(driver.state ?? "Calm", severity: pillSeverity)

                        let value = formattedValue()
                        if !value.isEmpty {
                            Text(value)
                                .font(.caption.weight(.semibold))
                                .foregroundColor(.secondary)
                                .multilineTextAlignment(.trailing)
                        }

                        if onTap != nil {
                            Image(systemName: "chevron.right")
                                .font(.caption.weight(.semibold))
                                .foregroundColor(.white.opacity(0.42))
                        }
                    }
                }
                .padding(14)
                .background(Color.white.opacity(role == .leading ? 0.055 : 0.04))
                .clipShape(RoundedRectangle(cornerRadius: 12, style: .continuous))
                .overlay(
                    RoundedRectangle(cornerRadius: 12, style: .continuous)
                        .stroke(role.border(for: zoneKey), lineWidth: role == .leading ? 1.2 : 1)
                )
                .shadow(
                    color: role.shadow(for: zoneKey),
                    radius: role == .leading ? 12 : 6,
                    x: 0,
                    y: 0
                )
            }

            var body: some View {
                if let onTap {
                    Button(action: onTap) {
                        content
                    }
                    .buttonStyle(.plain)
                } else {
                    content
                }
            }
        }

        private struct ContextModalSheetView: View {
            let experienceMode: ExperienceMode
            let contextType: String
            let contextKey: String
            let entry: DashboardModalEntry
            let gaugeRecentLogBoosts: [String: Double]
            let lastSymptomUpdateAt: String?
            let currentSymptomsSnapshot: CurrentSymptomsSnapshot?
            let drivers: [DashboardDriverItem]
            let onQuickLog: (MissionControlQuickLogRequest) -> Void
            let onOpenCustomLog: (SymptomQueuedEvent) -> Void
            let onOpenCurrentSymptoms: () -> Void
            let onOpenAllDrivers: (String?) -> Void
            @Environment(\.dismiss) private var dismiss
            @State private var selectedQuickLogs: Set<DashboardQuickLogOption> = []

            private var vocabulary: CopyVocabulary {
                experienceMode.copyVocabulary
            }

            private var modalType: String {
                (entry.modalType ?? "full").trimmingCharacters(in: .whitespacesAndNewlines).lowercased()
            }

            private var isGaugeContext: Bool {
                contextType == "gauge"
            }

            private func translated(_ raw: String?) -> String? {
                vocabulary.presenting(raw)
            }

            private func normalizedPopupToken(_ raw: String?) -> String {
                (raw ?? "")
                    .trimmingCharacters(in: .whitespacesAndNewlines)
                    .lowercased()
                    .replacingOccurrences(of: "-", with: " ")
                    .replacingOccurrences(of: "_", with: " ")
                    .components(separatedBy: CharacterSet.alphanumerics.inverted)
                    .filter { !$0.isEmpty }
                    .joined(separator: " ")
            }

            private func normalizedGaugePopupKey(_ raw: String) -> String {
                switch normalizedPopupToken(raw) {
                case "stamina", "recovery load", "recoveryload", "recovery_load":
                    return "recoveryLoad"
                case "health status", "healthstatus", "health_status":
                    return "healthStatus"
                default:
                    return raw
                        .trimmingCharacters(in: .whitespacesAndNewlines)
                        .replacingOccurrences(of: "-", with: "_")
                        .lowercased()
                }
            }

            private func normalizedDriverPopupKey(_ raw: String?) -> String {
                let normalized = (raw ?? "")
                    .trimmingCharacters(in: .whitespacesAndNewlines)
                    .replacingOccurrences(of: "-", with: "_")
                    .lowercased()
                switch normalized {
                case "temperature":
                    return "temp"
                case "resonance":
                    return "schumann"
                case "solar_wind":
                    return "sw"
                case "geomagnetic":
                    return "kp"
                default:
                    return normalized
                }
            }

            private func gaugePopupTitle(for gaugeKey: String) -> String {
                if let title = translated(entry.title), !title.isEmpty {
                    return title
                }
                switch normalizedGaugePopupKey(gaugeKey) {
                case "pain":
                    return "Pain"
                case "focus":
                    return "Focus"
                case "energy":
                    return "Energy"
                case "recoveryLoad":
                    return "Recovery Load"
                case "sleep":
                    return "Sleep"
                case "mood":
                    return "Mood"
                case "heart":
                    return "Heart"
                case "healthStatus":
                    return "Health Status"
                default:
                    return gaugeKey.replacingOccurrences(of: "_", with: " ").capitalized
                }
            }

            private var quickLog: DashboardQuickLog? {
                if let quickLog = entry.quickLog {
                    return quickLog
                }
                let options = (entry.cta?.prefill ?? ["OTHER"]).map { code in
                    DashboardQuickLogOption(
                        code: normalize(code),
                        label: normalize(code).replacingOccurrences(of: "_", with: " ").capitalized
                    )
                }
                return DashboardQuickLog(
                    title: "Log what you're feeling:",
                    confirmLabel: entry.cta?.label,
                    options: options,
                    defaultSeverity: 5,
                    baseTags: nil
                )
            }

            private func dismissAndOpenCurrentSymptoms() {
                dismiss()
                DispatchQueue.main.asyncAfter(deadline: .now() + 0.15) {
                    onOpenCurrentSymptoms()
                }
            }

            private func dismissAndOpenAllDrivers() {
                dismiss()
                DispatchQueue.main.asyncAfter(deadline: .now() + 0.15) {
                    onOpenAllDrivers(nil)
                }
            }

            private func dedupedSymptomLabels(_ labels: [String]) -> [String] {
                var seen: Set<String> = []
                var output: [String] = []
                for label in labels {
                    let normalized = normalizedPopupToken(label)
                    guard !normalized.isEmpty, !seen.contains(normalized) else { continue }
                    seen.insert(normalized)
                    output.append(label)
                }
                return output
            }

            private func symptomMatches(label: String, candidates: [String]) -> Bool {
                let normalizedLabel = normalizedPopupToken(label)
                guard !normalizedLabel.isEmpty else { return false }
                return candidates.contains { candidate in
                    let normalizedCandidate = normalizedPopupToken(candidate)
                    guard !normalizedCandidate.isEmpty else { return false }
                    if normalizedLabel == normalizedCandidate {
                        return true
                    }
                    if normalizedCandidate == "pain" {
                        return normalizedLabel.contains("pain")
                    }
                    return normalizedLabel.contains(normalizedCandidate)
                }
            }

            func gaugePopupRelevantSymptoms(for gaugeKey: String) -> [String] {
                guard let currentSymptomsSnapshot else { return [] }
                let activeLabels = currentSymptomsSnapshot.items.map { translated($0.label) ?? $0.label }
                let relevantLabels: [String]
                switch normalizedGaugePopupKey(gaugeKey) {
                case "pain":
                    relevantLabels = activeLabels.filter {
                        symptomMatches(
                            label: $0,
                            candidates: ["headache", "sinus pressure", "joint pain", "muscle pain", "nerve pain", "stiffness"]
                        )
                    }
                case "focus":
                    relevantLabels = activeLabels.filter {
                        symptomMatches(
                            label: $0,
                            candidates: ["brain fog", "headache", "fatigue", "sinus pressure"]
                        )
                    }
                case "energy":
                    relevantLabels = activeLabels.filter {
                        symptomMatches(label: $0, candidates: ["fatigue", "drained", "brain fog"])
                    }
                case "recoveryLoad":
                    relevantLabels = activeLabels.filter {
                        symptomMatches(label: $0, candidates: ["fatigue", "drained", "brain fog", "pain"])
                    }
                case "sleep":
                    relevantLabels = activeLabels.filter {
                        symptomMatches(label: $0, candidates: ["fatigue", "drained", "restless"])
                    }
                case "mood":
                    relevantLabels = activeLabels.filter {
                        symptomMatches(label: $0, candidates: ["anxious", "restless", "drained"])
                    }
                case "heart":
                    relevantLabels = activeLabels.filter {
                        symptomMatches(label: $0, candidates: ["palpitations", "anxious", "fatigue"])
                    }
                case "healthStatus":
                    relevantLabels = activeLabels
                default:
                    relevantLabels = []
                }
                return Array(dedupedSymptomLabels(relevantLabels).prefix(3))
            }

            private func dedupedDrivers(_ source: [DashboardDriverItem]) -> [DashboardDriverItem] {
                var seen: Set<String> = []
                var output: [DashboardDriverItem] = []
                for driver in source {
                    let normalized = normalizedDriverPopupKey(driver.key)
                    guard !normalized.isEmpty, !seen.contains(normalized) else { continue }
                    seen.insert(normalized)
                    output.append(driver)
                }
                return output
            }

            private func gaugePopupInfluencerScore(for driver: DashboardDriverItem) -> Double {
                max(driver.personalRelevanceScore ?? 0, driver.rawSeverityScore ?? 0)
            }

            private func driverMatches(_ driver: DashboardDriverItem, candidates: [String]) -> Bool {
                let normalized = normalizedDriverPopupKey(driver.key)
                return candidates.contains { candidate in
                    normalized == normalizedDriverPopupKey(candidate)
                }
            }

            func gaugePopupCurrentInfluencers(for gaugeKey: String) -> [DashboardDriverItem] {
                let availableDrivers = dedupedDrivers(drivers)
                let normalizedGaugeKey = normalizedGaugePopupKey(gaugeKey)

                if normalizedGaugeKey == "healthStatus" {
                    return Array(
                        availableDrivers
                            .sorted {
                                let lhs = gaugePopupInfluencerScore(for: $0)
                                let rhs = gaugePopupInfluencerScore(for: $1)
                                if lhs == rhs {
                                    return normalizedDriverPopupKey($0.key) < normalizedDriverPopupKey($1.key)
                                }
                                return lhs > rhs
                            }
                            .prefix(4)
                    )
                }

                let priorityMap: [[String]]
                switch normalizedGaugeKey {
                case "pain":
                    priorityMap = [["allergen_exposure"], ["overexertion"], ["allergens"], ["pressure"], ["temp", "temperature"], ["aqi"]]
                case "focus":
                    priorityMap = [["allergen_exposure"], ["allergens"], ["pressure"], ["aqi"], ["schumann", "resonance"]]
                case "energy":
                    priorityMap = [["overexertion"], ["allergen_exposure"], ["temp", "temperature"], ["aqi"], ["allergens"]]
                case "recoveryLoad":
                    priorityMap = [["overexertion"], ["temp", "temperature"], ["pressure"], ["aqi"]]
                case "sleep":
                    priorityMap = [["overexertion"], ["allergen_exposure"], ["pressure"], ["temp", "temperature"], ["schumann", "resonance"]]
                case "mood":
                    priorityMap = [["pressure"], ["schumann", "resonance"], ["aqi"]]
                case "heart":
                    priorityMap = [["overexertion"], ["allergen_exposure"], ["kp", "geomagnetic"], ["bz"], ["sw", "solar_wind"], ["pressure"]]
                default:
                    priorityMap = []
                }

                var selected: [DashboardDriverItem] = []
                var seen: Set<String> = []
                for candidates in priorityMap {
                    guard let match = availableDrivers.first(where: {
                        let normalized = normalizedDriverPopupKey($0.key)
                        return !seen.contains(normalized) && driverMatches($0, candidates: candidates)
                    }) else { continue }
                    seen.insert(normalizedDriverPopupKey(match.key))
                    selected.append(match)
                    if selected.count == 4 {
                        break
                    }
                }
                return selected
            }

