        private struct CameraCheckCard: View {
            let summary: CameraHealthDailySummary?
            let isLoading: Bool
            let errorText: String?

            private func statusColor(_ summary: CameraHealthDailySummary?) -> Color {
                switch summary?.summaryStatus ?? .pending {
                case .good:
                    return .green
                case .partial:
                    return .yellow
                case .poor:
                    return .orange
                case .pending:
                    return .secondary
                }
            }

            private func statusLabel(_ summary: CameraHealthDailySummary?) -> String {
                (summary?.summaryStatus ?? .pending).rawValue.capitalized
            }

            private func qualityLabel(_ quality: String?) -> String {
                let token = (quality ?? "unknown").trimmingCharacters(in: .whitespacesAndNewlines)
                if token.isEmpty { return "Unknown" }
                return token.capitalized
            }

            private func saveScopeText(_ summary: CameraHealthDailySummary) -> String {
                switch summary.persistedSaveScope {
                case .account:
                    return "Saved to your account"
                case .localOnly:
                    return "Saved locally only"
                case .notSaved:
                    return "Not saved"
                }
            }

            private func summaryText(_ summary: CameraHealthDailySummary) -> String {
                switch summary.summaryStatus {
                case .good:
                    return "Heart rate and HRV were captured."
                case .partial:
                    if summary.hrvMetricStatus == .notRequested {
                        return "Heart rate was captured. HRV was not requested in Quick HR mode."
                    }
                    return "Heart rate was captured. HRV is not shown because signal quality was too low."
                case .poor:
                    return "No reliable reading yet."
                case .pending:
                    return "Latest check is still loading."
                }
            }

            private func poorSuggestion(_ summary: CameraHealthDailySummary) -> String {
                if summary.qualityScore ?? 0 < 0.45 {
                    return "Try lighter pressure, full lens coverage, and keep still."
                }
                return "Try another run after adjusting finger placement."
            }

            private func timeText(_ raw: String?) -> String? {
                guard let raw, let date = ISO8601DateFormatter().date(from: raw) else { return nil }
                let out = DateFormatter()
                out.dateStyle = .none
                out.timeStyle = .short
                return out.string(from: date)
            }

            var body: some View {
                VStack(alignment: .leading, spacing: 8) {
                    HStack {
                        Label("Latest Check", systemImage: "camera.metering.center.weighted")
                            .font(.headline)
                        Spacer()
                        if summary != nil {
                            Text(statusLabel(summary))
                                .font(.caption.weight(.semibold))
                                .padding(.horizontal, 8)
                                .padding(.vertical, 4)
                                .background(statusColor(summary).opacity(0.18))
                                .foregroundColor(statusColor(summary))
                                .clipShape(Capsule())
                        }
                    }
                    if isLoading {
                        ProgressView("Loading latest check...")
                            .font(.caption)
                    } else if let errorText, !errorText.isEmpty, summary == nil {
                        Text(errorText)
                            .font(.caption2)
                            .foregroundColor(.secondary)
                    } else if let summary {
                        VStack(alignment: .leading, spacing: 8) {
                            HStack(spacing: 12) {
                                if summary.hasUsableHR {
                                    VStack(alignment: .leading, spacing: 2) {
                                        Text("BPM")
                                            .font(.caption2)
                                            .foregroundColor(.secondary)
                                        Text(summary.bpm.map { String(Int($0.rounded())) } ?? "--")
                                            .font(.title3.weight(.bold))
                                    }
                                }
                                if summary.hasUsableHRV {
                                    VStack(alignment: .leading, spacing: 2) {
                                        Text("RMSSD")
                                            .font(.caption2)
                                            .foregroundColor(.secondary)
                                        Text(summary.rmssdMs.map { "\(Int($0.rounded())) ms" } ?? "--")
                                            .font(.subheadline.weight(.semibold))
                                    }
                                }
                                if let timestamp = timeText(summary.latestTsUtc) {
                                    VStack(alignment: .leading, spacing: 2) {
                                        Text("Time")
                                            .font(.caption2)
                                            .foregroundColor(.secondary)
                                        Text(timestamp)
                                            .font(.caption.weight(.semibold))
                                    }
                                }
                            }
                            Text(summaryText(summary))
                                .font(.caption2)
                                .foregroundColor(.secondary)
                            if summary.summaryStatus == .poor {
                                Text(poorSuggestion(summary))
                                    .font(.caption2)
                                    .foregroundColor(.secondary)
                            }
                            Text("\(saveScopeText(summary)) | Quality \(qualityLabel(summary.qualityLabel))")
                                .font(.caption2)
                                .foregroundColor(.secondary)
                        }
                        Text("Wellness estimate only. Not medical advice.")
                            .font(.caption2)
                            .foregroundColor(.secondary)
                    } else {
                        Text("No camera check yet today.")
                            .font(.caption2)
                            .foregroundColor(.secondary)
                    }
                }
                .padding(10)
                .background(Color.black.opacity(0.20))
                .clipShape(RoundedRectangle(cornerRadius: 12, style: .continuous))
                .overlay(
                    RoundedRectangle(cornerRadius: 12, style: .continuous)
                        .stroke(Color.white.opacity(0.06), lineWidth: 1)
                )
            }
        }

        private func gaugeRows(_ g: DashboardGaugeSet?) -> [GaugeRow] {
            guard let g else { return [] }
            let values: [(String, Double?)] = [
                ("pain", g.pain),
                ("focus", g.focus),
                ("heart", g.heart),
                ("stamina", g.stamina),
                ("energy", g.energy),
                ("sleep", g.sleep),
                ("mood", g.mood),
                ("health_status", g.healthStatus),
            ]
            let fallbackLabels: [String: String] = [
                "pain": "Pain",
                "focus": "Focus",
                "heart": "Heart",
                "stamina": "Recovery Load",
                "energy": "Energy",
                "sleep": "Sleep",
                "mood": "Mood",
                "health_status": "Health Status",
            ]
            func effectiveZoneLabel(for key: String, meta: DashboardGaugeMeta?) -> String? {
                let baseLabel = meta?.label
                guard let boost = gaugeRecentLogBoosts[key], boost > 0 else { return baseLabel }
                let zone = (meta?.zone ?? "").trimmingCharacters(in: .whitespacesAndNewlines).lowercased()
                let normalizedLabel = (baseLabel ?? "").trimmingCharacters(in: .whitespacesAndNewlines).lowercased()
                if zone == "low" || normalizedLabel == "quiet" || normalizedLabel == "calm" || normalizedLabel == "low strain" {
                    return boost >= 9 ? "Watchful" : baseLabel
                }
                return baseLabel
            }
            return values.map { key, value in
                let meta = gaugesMeta[key]
                let zoneKey = meta?.zone ?? inferredZoneKey(for: value)
                let delta = gaugesDelta[key] ?? 0
                let tappable = modalModels?.gauges?[key] != nil
                let zoneLabel = effectiveZoneLabel(for: key, meta: meta)
                return GaugeRow(
                    key: key,
                    label: gaugeLabels[key] ?? fallbackLabels[key] ?? key,
                    value: value,
                    delta: delta,
                    zoneKey: zoneKey,
                    zoneLabel: zoneLabel,
                    tappable: tappable,
                    showAffordance: gaugeShowsAffordance(zoneKey: zoneKey, zoneLabel: zoneLabel)
                )
            }
        }

        private func gaugeHasAffordance(zoneKey: String?) -> Bool {
            let zone = (zoneKey ?? "").lowercased()
            return zone == "elevated" || zone == "high"
        }

        private func gaugeShowsAffordance(zoneKey: String?, zoneLabel: String?) -> Bool {
            if gaugeHasAffordance(zoneKey: zoneKey) {
                return true
            }
            let label = (zoneLabel ?? "").trimmingCharacters(in: .whitespacesAndNewlines).lowercased()
            return label.contains("elevated") || label.contains("high") || label.contains("watch")
        }

        private func driverSeverityKey(_ raw: String?) -> String {
            let token = (raw ?? "").trimmingCharacters(in: .whitespacesAndNewlines).lowercased()
            if token == "high" { return "high" }
            if token == "watch" { return "elevated" }
            if token == "elevated" { return "elevated" }
            if token == "mild" { return "mild" }
            return "low"
        }

        private func formattedSymptomUpdate(_ raw: String?) -> String? {
            guard let raw, let date = ISO8601DateFormatter().date(from: raw) else { return nil }
            let formatter = DateFormatter()
            formatter.dateStyle = .none
            formatter.timeStyle = .short
            return formatter.string(from: date)
        }

        private func driverProgress(_ raw: String?) -> Double {
            let token = (raw ?? "").trimmingCharacters(in: .whitespacesAndNewlines).lowercased()
            if token == "high" { return 1.0 }
            if token == "watch" || token == "elevated" { return 0.76 }
            if token == "mild" { return 0.5 }
            return 0.28
        }

        private func driverHasAffordance(_ raw: String?) -> Bool {
            let token = (raw ?? "").trimmingCharacters(in: .whitespacesAndNewlines).lowercased()
            return token == "watch" || token == "elevated" || token == "high"
        }

        private func normalizedDriverKey(_ raw: String?) -> String {
            let token = (raw ?? "")
                .trimmingCharacters(in: .whitespacesAndNewlines)
                .replacingOccurrences(of: "-", with: "_")
                .replacingOccurrences(of: " ", with: "_")
                .lowercased()
            switch token {
            case "sw", "solarwind", "solar_wind_speed":
                return "solar_wind"
            case "sr", "earth_resonance":
                return "schumann"
            case "geomagnetic", "geomagnetic_activity":
                return "kp"
            case "pressure_swing", "barometric_pressure":
                return "pressure"
            default:
                return token
            }
        }

        private func dedupedDrivers(_ source: [DashboardDriverItem]) -> [DashboardDriverItem] {
            var seen: Set<String> = []
            var output: [DashboardDriverItem] = []
            for driver in source {
                let key = normalizedDriverKey(driver.key)
                guard !key.isEmpty, !seen.contains(key) else { continue }
                seen.insert(key)
                output.append(driver)
            }
            return output
        }

        private func whatMattersRole(
            for driver: DashboardDriverItem,
            index: Int,
            leadingKey: String?,
            supportingKeys: Set<String>
        ) -> WhatMattersRole {
            let role = normalizedDriverKey(driver.role)
            if role == "primary" { return .leading }
            if role == "supporting" { return .supporting }
            if role == "background" { return .background }

            let roleLabel = normalizedDriverKey(driver.roleLabel)
            if roleLabel == "leading now" { return .leading }
            if roleLabel == "also in play" { return .supporting }
            if roleLabel == "in the background" { return .background }

            let driverKey = normalizedDriverKey(driver.key)
            if let leadingKey, !leadingKey.isEmpty, driverKey == leadingKey {
                return .leading
            }
            if supportingKeys.contains(driverKey) {
                return .supporting
            }
            return index < 2 ? .supporting : .background
        }

        private func groupedDrivers() -> [DriverSectionGroup] {
            let ordered = combinedWhatMattersDrivers()
            let fallbackLeadingKey = drivers.first.map { normalizedDriverKey($0.key) }
            let leadingKey = normalizedDriverKey(primaryDriver?.key).isEmpty ? fallbackLeadingKey : normalizedDriverKey(primaryDriver?.key)
            let supportingKeys = Set(supportingDrivers.map { normalizedDriverKey($0.key) }.filter { !$0.isEmpty })
            var buckets: [WhatMattersRole: [DashboardDriverItem]] = [:]

            for (index, driver) in ordered.enumerated() {
                let role = whatMattersRole(
                    for: driver,
                    index: index,
                    leadingKey: leadingKey,
                    supportingKeys: supportingKeys
                )
                buckets[role, default: []].append(driver)
            }

            return WhatMattersRole.allCases.compactMap { role in
                let items = Array((buckets[role] ?? []).prefix(role.maxVisible))
                return items.isEmpty ? nil : DriverSectionGroup(role: role, items: items)
            }
        }

        private struct WhatMattersCardItem: Identifiable {
            let driver: DashboardDriverItem
            let role: WhatMattersRole

            var id: String { driver.id }
        }

        private func combinedWhatMattersDrivers() -> [DashboardDriverItem] {
            let primaryStack = dedupedDrivers(([primaryDriver].compactMap { $0 }) + supportingDrivers + drivers)
            guard primaryStack.count < 3 else { return primaryStack }
            return dedupedDrivers(primaryStack + previewDrivers)
        }

        private func topWhatMattersDrivers() -> [WhatMattersCardItem] {
            let ordered = combinedWhatMattersDrivers()
            let fallbackLeadingKey = drivers.first.map { normalizedDriverKey($0.key) }
            let leadingKey = normalizedDriverKey(primaryDriver?.key).isEmpty ? fallbackLeadingKey : normalizedDriverKey(primaryDriver?.key)
            let supportingKeys = Set(supportingDrivers.map { normalizedDriverKey($0.key) }.filter { !$0.isEmpty })

            return Array(
                ordered.enumerated().map { index, driver in
                    WhatMattersCardItem(
                        driver: driver,
                        role: whatMattersRole(
                            for: driver,
                            index: index,
                            leadingKey: leadingKey,
                            supportingKeys: supportingKeys
                        )
                    )
                }
                .prefix(3)
            )
        }

        private var currentSymptomsSummaryLine: String {
            guard let snapshot = currentSymptomsSnapshot else {
                return "Open the live view for updates, notes, and the timeline."
            }
            let count = snapshot.summary.activeCount
            if count <= 0 {
                return snapshot.semanticEmptyStateSummary ?? "No symptoms active right now. Log anything new here."
            }
            if let semanticSummary = snapshot.semanticActiveSummary {
                return semanticSummary
            }
            if let labelSummary = snapshot.semanticActiveLabelSummary {
                return "\(count) active right now: \(labelSummary)"
            }
            return "\(count) active right now."
        }

        private var dailyCheckInSummaryLine: String {
            guard let status = dailyCheckInStatus else {
                return "A short daily check-in helps this view stay current."
            }
            if let prompt = status.prompt, prompt.status != "answered" {
                if prompt.phase == "next_morning" {
                    return "Yesterday’s quick check-in is ready."
                }
                return "Today’s quick check-in is ready."
            }
            if let targetDay = status.targetDay,
               let latest = status.latestEntry,
               let completedAt = latest.completedAt,
               !completedAt.isEmpty,
               latest.day == targetDay {
                if let exposureSummary = latest.summaryExposureText {
                    return "Latest check-in saved for \(latest.day). Also logged: \(exposureSummary)."
                }
                return "Latest check-in saved for \(latest.day)."
            }
            if status.settings.enabled {
                return "Daily check-ins are on."
            }
            return "Turn on daily check-ins for a quick end-of-day read."
        }

        private var whatMattersSummaryLine: String {
            let trimmed = whatMattersSummary?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
            if !trimmed.isEmpty {
                return trimmed
            }
            return "The signals standing out most right now."
        }

