        private var magnetosphereCard: some View {
            let kpis = magnetosphere?.kpis
            let sw = magnetosphere?.sw
            let storminess = (kpis?.storminess ?? "Calm").capitalized
            let geoRisk = (kpis?.geoRisk ?? "Low").capitalized
            let bzText = sw?.bzNt.map { String(format: "%.1f nT", $0) } ?? "—"
            let r0Text = kpis?.r0Re.map { String(format: "%.1f Re", $0) } ?? "—"
            let kpText = kpis?.kp.map { String(format: "%.1f", $0) } ?? "—"
            let severity: StatusPill.Severity = {
                if storminess.lowercased().contains("storm") || geoRisk.lowercased().contains("high") {
                    return .alert
                }
                if storminess.lowercased().contains("active") || geoRisk.lowercased().contains("elev") {
                    return .warn
                }
                if ContentView.scrubError(magnetosphereError) != nil {
                    return .warn
                }
                return .ok
            }()
            let status: String
            if let error = ContentView.scrubError(magnetosphereError) {
                status = error
            } else if magnetosphereLoading {
                status = "Refreshing coupling and shield-edge conditions."
            } else {
                status = "\(storminess) storminess with \(geoRisk.lowercased()) GEO risk."
            }

            return NavigationLink(value: InsightsRoute.magnetosphere) {
                HubCard(
                    title: "Magnetosphere",
                    icon: "shield.lefthalf.filled",
                    status: status,
                    pillText: storminess,
                    severity: severity,
                    metrics: [
                        HubMetric(label: "R0", value: r0Text, tint: GaugePalette.low),
                        HubMetric(label: "Bz", value: bzText, tint: GaugePalette.elevated),
                        HubMetric(label: "Kp", value: kpText, tint: GaugePalette.mild)
                    ],
                    isExplore: !showsPersonalCards
                )
            }
            .buttonStyle(.plain)
        }

        private var schumannCard: some View {
            let schumannDriver = dashboardDriver(for: "schumann")
            let station = current?.schStation?.capitalized ?? "Station"
            let f0Text = current?.schF0Hz?.value.map { String(format: "%.2f Hz", $0) } ?? "—"
            let f1Text = current?.schF1Hz?.value.map { String(format: "%.2f Hz", $0) } ?? "—"
            let updated = updatedText ?? "recent"
            let pillText = normalizedPillText(
                schumannDriver?.state?.capitalized,
                fallback: current?.schF0Hz?.value == nil ? "Pending" : "Active"
            )
            let status = "Earth resonance activity with harmonics, source quality, and recent drift."

            return NavigationLink(value: InsightsRoute.schumann) {
                HubCard(
                    title: "Schumann Resonance",
                    icon: "waveform.path.ecg",
                    status: "\(status) Last app summary \(updated).",
                    pillText: pillText,
                    severity: schumannDriver == nil ? .warn : severity(for: schumannDriver?.severity),
                    metrics: [
                        HubMetric(label: "Source", value: station, tint: GaugePalette.low),
                        HubMetric(label: "f0", value: f0Text, tint: GaugePalette.mild),
                        HubMetric(label: "f1", value: f1Text, tint: GaugePalette.elevated)
                    ],
                    isExplore: !showsPersonalCards
                )
            }
            .buttonStyle(.plain)
        }

        private var healthCard: some View {
            let sleepText: String = {
                guard let current else { return "—" }
                let total = Int((current.sleepTotalMinutes?.value ?? 0).rounded())
                return "\(total / 60)h \(total % 60)m"
            }()
            let stepsText = current.map { "\(Int(($0.stepsTotal?.value ?? 0).rounded()))" } ?? "—"
            let currentActiveCount = currentSymptomsSnapshot?.summary.activeCount ?? 0
            let status: String
            if let snapshot = currentSymptomsSnapshot, currentActiveCount > 0 {
                status = snapshot.semanticHeaderSummary
                    ?? snapshot.semanticActiveSummary
                    ?? "\(currentActiveCount) symptoms are active right now. Open for body context, recent logs, and follow-up updates."
            } else if symptomsTodayCount > 0 {
                status = "\(symptomsTodayCount) symptoms logged today. Open for sleep, vitals, and body-context detail."
            } else if let topSymptomSummary, !topSymptomSummary.isEmpty {
                status = topSymptomSummary
            } else if queuedSymptomsCount > 0 {
                status = "\(queuedSymptomsCount) symptom entries are queued to sync."
            } else if let emptySummary = currentSymptomsSnapshot?.semanticEmptyStateSummary {
                status = emptySummary
            } else {
                status = "No symptoms active right now. Open for sleep, vitals, and body context."
            }
            let severity: StatusPill.Severity = currentActiveCount >= 3 ? .alert : (currentActiveCount > 0 || queuedSymptomsCount > 0 ? .warn : .ok)
            let pillText = currentActiveCount > 0 ? "Active" : (queuedSymptomsCount > 0 ? "Syncing" : "Calm")
            var metrics: [HubMetric] = [
                HubMetric(label: "Sleep", value: sleepText, tint: GaugePalette.low),
                HubMetric(label: "Steps", value: stepsText, tint: GaugePalette.mild)
            ]
            if currentActiveCount > 0 {
                metrics.append(HubMetric(label: "Active", value: "\(currentActiveCount)", tint: GaugePalette.elevated))
            }
            if ContentView.cameraHealthCheckVisible {
                let cameraText = latestCameraCheck?.bpm.map { "\(Int($0.rounded())) bpm" } ?? "—"
                metrics.append(HubMetric(label: "Quick Check", value: cameraText, tint: GaugePalette.elevated))
            }

            return NavigationLink(value: InsightsRoute.healthSymptoms) {
                HubCard(
                    title: "Health & Body Context",
                    icon: "heart.text.square.fill",
                    status: status,
                    pillText: pillText,
                    severity: severity,
                    metrics: metrics,
                    isExplore: false
                )
            }
            .buttonStyle(.plain)
        }

        private var earthquakesCard: some View {
            let total = quakeLatest?.allQuakes ?? quakeEvents.count
            let maxMag = quakeEvents.max(by: { ($0.mag ?? 0) < ($1.mag ?? 0) })?.mag
            let status: String
            if let error = ContentView.scrubError(quakeError) {
                status = error
            } else if quakeLoading {
                status = "Refreshing the global quake snapshot."
            } else if maxMag != nil {
                status = "Interesting global quake context, outside the core daily loop."
            } else {
                status = "Open for recent quake context when you want to explore."
            }

            return NavigationLink(value: InsightsRoute.earthquakes) {
                HubCard(
                    title: "Earthquakes",
                    icon: "waveform.path",
                    status: status,
                    pillText: (maxMag ?? 0) >= 6.5 ? "Watch" : "Ready",
                    severity: (maxMag ?? 0) >= 6.5 ? .warn : .ok,
                    metrics: [
                        HubMetric(label: "Total", value: total > 0 ? "\(total)" : "—", tint: GaugePalette.low),
                        HubMetric(label: "Max", value: maxMag.map { String(format: "M%.1f", $0) } ?? "—", tint: GaugePalette.elevated),
                        HubMetric(label: "M6+", value: quakeLatest?.m6p.map(String.init) ?? "—", tint: GaugePalette.mild)
                    ],
                    isExplore: true
                )
            }
            .buttonStyle(.plain)
        }

        private var hazardsCard: some View {
            let items = hazardsBrief?.items ?? []
            let severityCounts = countHazardSeverities(items)
            let total = items.count
            let status: String
            if let error = ContentView.scrubError(hazardsError) {
                status = error
            } else if hazardsLoading {
                status = "Refreshing the GDACS hazard brief."
            } else if total > 0 {
                status = "Global hazards stay available as optional exploration."
            } else {
                status = "Open for the latest hazard brief if you want broader context."
            }

            return NavigationLink(value: InsightsRoute.hazards) {
                HubCard(
                    title: "Hazards",
                    icon: "exclamationmark.triangle.fill",
                    status: status,
                    pillText: severityCounts.red > 0 ? "Alert" : severityCounts.orange > 0 ? "Watch" : "Ready",
                    severity: severityCounts.red > 0 ? .alert : severityCounts.orange > 0 ? .warn : .ok,
                    metrics: [
                        HubMetric(label: "Active", value: total > 0 ? "\(total)" : "—", tint: GaugePalette.low),
                        HubMetric(label: "Red", value: "\(severityCounts.red)", tint: GaugePalette.high),
                        HubMetric(label: "Orange", value: "\(severityCounts.orange)", tint: GaugePalette.elevated)
                    ],
                    isExplore: true
                )
            }
            .buttonStyle(.plain)
        }

        var body: some View {
            ZStack {
                Color.black.opacity(0.97).ignoresSafeArea()

                ScrollView {
                    LazyVStack(alignment: .leading, spacing: 18) {
                        VStack(alignment: .leading, spacing: 6) {
                            Text(introTitle)
                                .font(.system(size: 32, weight: .bold, design: .rounded))
                            Text(introSubtitle)
                                .font(.subheadline)
                                .foregroundColor(.secondary)
                            if usingYesterdayFallback {
                                Label("Showing yesterday’s features while today finishes updating.", systemImage: "clock.arrow.circlepath")
                                    .font(.caption)
                                    .foregroundColor(.secondary)
                            }
                        }

                        if showsPersonalCards {
                            understandingCard
                        }

                        if onOpenAllDrivers != nil {
                            allDriversCard
                        }

                        spaceWeatherCard
                        localConditionsCard
                        if showsPersonalCards {
                            yourOutlookCard
                            yourPatternsCard
                        }
                        magnetosphereCard
                        schumannCard
                        if showsPersonalCards {
                            healthCard
                        }

                        VStack(alignment: .leading, spacing: 10) {
                            Text(showsPersonalCards ? "Explore" : "More to Explore")
                                .font(.headline.weight(.semibold))
                            Text(
                                showsPersonalCards
                                    ? "Interesting context, but kept secondary so Insights stays fast and personal."
                                    : "These deeper system feeds stay reachable here without competing with the primary tabs."
                            )
                                .font(.caption)
                                .foregroundColor(.secondary)
                            earthquakesCard
                            hazardsCard
                        }
                        .padding(.top, 4)
                    }
                    .padding(16)
                    .frame(maxWidth: .infinity, alignment: .leading)
                }
                .refreshable {
                    await onRefresh()
                }
            }
            .navigationTitle(navigationTitle)
            .navigationBarTitleDisplayMode(.inline)
        }
    }

    private struct YourOutlookView: View {
        let mode: ExperienceMode
        let payload: UserForecastOutlook?
        let isLoading: Bool
        let error: String?
        let hasPlusAccess: Bool
        let onRefresh: () -> Void
        let onOpenAllDrivers: () -> Void
        @State private var shareDraft: ShareDraft? = nil

        private let columns = [
            GridItem(.adaptive(minimum: 150, maximum: 260), spacing: 10, alignment: .topLeading)
        ]
        private let suppressedOutlookPhrases = ["radio blackout", "radio-blackout"]

        private func severity(_ raw: String?) -> StatusPill.Severity {
            LocalConditionsStyle.pillSeverity(raw)
        }

        private func formatUpdate(_ iso: String?) -> String? {
            guard let iso else { return nil }
            let fmt = ISO8601DateFormatter()
            guard let date = fmt.date(from: iso) else { return nil }
            let out = DateFormatter()
            out.dateStyle = .medium
            out.timeStyle = .short
            return out.string(from: date)
        }

        private func driverValue(_ driver: UserOutlookDriver) -> String {
            if let value = driver.value {
                if let unit = driver.unit, !unit.isEmpty {
                    return "\(String(format: "%.1f", value)) \(unit)"
                }
                return String(format: "%.1f", value)
            }
            if let day = driver.day, !day.isEmpty {
                return day
            }
            return (driver.severity ?? "watch").capitalized
        }

        private func driverSeverityValue(_ driver: UserOutlookDriver) -> String {
            let severityText = (driver.severity ?? "").trimmingCharacters(in: .whitespacesAndNewlines)
            if !severityText.isEmpty {
                return severityText.capitalized
            }
            return driverValue(driver)
        }

        private func availabilityText(_ raw: String) -> String {
            switch raw {
            case "next_24h":
                return "24h"
            case "next_72h":
                return "72h"
            case "next_7d":
                return "7d"
            default:
                return raw
            }
        }

        private func windowTitle(_ hours: Int?) -> String {
            switch hours {
            case 24:
                return "Next 24 Hours"
            case 72:
                return "Next 72 Hours"
            case 168:
                return "Next 7 Days"
            default:
                return "Outlook"
            }
        }

        private func sharePrompt(for accent: ShareAccentLevel) -> String {
            _ = accent
            return "Share"
        }

        private func accent(for raw: String?) -> ShareAccentLevel {
            switch (raw ?? "").lowercased() {
            case "high", "strong", "storm":
                return .storm
            case "elevated":
                return .elevated
            case "watch", "active", "mild":
                return .watch
            default:
                return .calm
            }
        }

        private func outlookBackground(for driverKey: String?) -> ShareCardBackground {
            let normalized = (driverKey ?? "").lowercased()
            switch normalized {
            case "kp", "solar_wind", "bz", "flare", "sep", "drap":
                return ShareCardBackground(style: .solar)
            case "cme":
                return ShareCardBackground(style: .cme)
            case "pressure", "temp", "humidity", "aqi", "allergens":
                return ShareCardBackground(style: .atmospheric)
            case "schumann":
                return ShareCardBackground(style: .schumann)
            default:
                return ShareCardBackground(style: .abstract)
            }
        }

        private func shareDraft(for window: UserOutlookWindow?) -> ShareDraft? {
            guard let window else { return nil }
            let visible = visibleDrivers(window.topDrivers ?? [])
            guard let primary = visible.first else { return nil }
            let supporting = Array(visible.dropFirst().prefix(2)).map {
                $0.label ?? $0.key.replacingOccurrences(of: "_", with: " ").capitalized
            }
            let domains = Array((window.likelyElevatedDomains ?? []).prefix(3)).map {
                $0.label ?? $0.key.replacingOccurrences(of: "_", with: " ").capitalized
            }
            let actionLine = window.semanticSupportSummary ?? window.semanticSummary ?? primary.detail ?? "This window may be worth watching."
            let accentLevel = accent(for: primary.severity)
            return ShareDraftFactory.outlook(
                surface: "your_outlook",
                analyticsKey: primary.key,
                mode: mode,
                windowTitle: windowTitle(window.windowHours),
                primaryDriver: primary.label ?? primary.key.replacingOccurrences(of: "_", with: " ").capitalized,
                supportingDrivers: supporting,
                affectedDomains: domains,
                actionLine: actionLine,
                primaryState: driverSeverityValue(primary),
                primaryValue: driverValue(primary),
                accent: accentLevel,
                background: outlookBackground(for: primary.key),
                updatedAt: formatUpdate(payload?.generatedAt),
                promptText: sharePrompt(for: accentLevel)
            )
        }

        private func normalizeOutlookString(_ raw: String?) -> String {
            guard let raw = raw?.lowercased(), !raw.isEmpty else { return "" }
            return raw
                .replacingOccurrences(of: "—", with: "-")
                .replacingOccurrences(of: "[^a-z0-9]+", with: " ", options: .regularExpression)
                .replacingOccurrences(of: "\\s+", with: " ", options: .regularExpression)
                .trimmingCharacters(in: .whitespacesAndNewlines)
        }

        private func containsSuppressedOutlookPhrase(_ raw: String?) -> Bool {
            let normalized = normalizeOutlookString(raw)
            guard !normalized.isEmpty else { return false }
            return suppressedOutlookPhrases.contains { normalized.contains($0) }
        }

        private func filteredOutlookText(_ raw: String?) -> String? {
            guard let raw = raw?.nilIfTrimmedEmpty else { return nil }
            let refined = (CopyRefiner.refine(raw) ?? raw).trimmingCharacters(in: .whitespacesAndNewlines)
            guard !refined.isEmpty else { return nil }
            let sentences = refined.components(separatedBy: .newlines)
                .flatMap { block in
                    block.split(whereSeparator: { [".", "!", "?"].contains($0) }).map(String.init)
                }
                .map { $0.trimmingCharacters(in: .whitespacesAndNewlines) }
                .filter { !$0.isEmpty }
            let kept = sentences.filter { !containsSuppressedOutlookPhrase($0) }
            if !kept.isEmpty {
                let joined = kept.map { sentence -> String in
                    if sentence.hasSuffix(".") || sentence.hasSuffix("!") || sentence.hasSuffix("?") {
                        return sentence
                    }
                    return sentence + "."
                }.joined(separator: " ")
                return joined.nilIfTrimmedEmpty
            }
            return containsSuppressedOutlookPhrase(refined) ? nil : refined.nilIfTrimmedEmpty
        }

        private func refinedText(_ raw: String?) -> String? {
            filteredOutlookText(raw)
        }

        private func normalizedOutlookText(_ raw: String?) -> String {
            normalizeOutlookString(refinedText(raw))
        }

        private func visibleDrivers(_ drivers: [UserOutlookDriver]) -> [UserOutlookDriver] {
            drivers.filter { driver in
                let key = driver.key.lowercased()
                if key == "radio" || key == "radio_blackout" || key == "radio-blackout" {
                    return false
                }
                if containsSuppressedOutlookPhrase(driver.label) || containsSuppressedOutlookPhrase(driver.detail) {
                    return false
                }
                return true
            }
        }

        private func textCarriesSameIdea(_ lhs: String?, _ rhs: String?) -> Bool {
            let left = normalizedOutlookText(lhs)
            let right = normalizedOutlookText(rhs)
            guard !left.isEmpty, !right.isEmpty else { return false }
            return left.contains(right) || right.contains(left)
        }

        private func firstSentence(_ raw: String?) -> String? {
            guard let text = refinedText(raw) else { return nil }
            if let end = text.firstIndex(where: { [".", "!", "?"].contains($0) }) {
                return String(text[...end]).nilIfTrimmedEmpty
            }
            return text
        }

        private func trimmedLeadingPunctuation(_ raw: String?) -> String? {
            guard let raw = raw?.nilIfTrimmedEmpty else { return nil }
            return raw.trimmingCharacters(in: CharacterSet(charactersIn: " .,:;!-")).nilIfTrimmedEmpty
        }

        private func droppingRepeatedLead(from raw: String?, matching prefix: String?) -> String? {
            guard let text = refinedText(raw) else { return nil }
            guard let intro = firstSentence(text) else { return text }
            guard textCarriesSameIdea(intro, prefix) else { return text }
            let remainder = String(text.dropFirst(intro.count))
            return trimmedLeadingPunctuation(remainder)
        }

        private func leadingDetail(for window: UserOutlookWindow, primary: UserOutlookDriver) -> String? {
            let detail = refinedText(window.semanticLeadingSignalSummary ?? primary.detail)
            guard !textCarriesSameIdea(window.semanticSummary, detail) else { return nil }
            return detail
        }

        private func domainExplanation(_ domain: UserOutlookDomain, window: UserOutlookWindow, primary: UserOutlookDriver?) -> String? {
            var detail = refinedText(domain.explanation)
            detail = droppingRepeatedLead(from: detail, matching: firstSentence(window.semanticSummary))
            detail = droppingRepeatedLead(from: detail, matching: window.semanticLeadingSignalSummary ?? primary?.detail)
            return detail
        }

        @ViewBuilder
        private func driverFactChips(_ drivers: [UserOutlookDriver], primary: Bool = false) -> some View {
            LazyVGrid(columns: columns, alignment: .leading, spacing: 10) {
                ForEach(drivers) { driver in
                    LocalConditionsValueChip(
                        label: driver.label ?? driver.key.replacingOccurrences(of: "_", with: " ").capitalized,
                        value: primary ? driverSeverityValue(driver) : driverValue(driver),
                        tint: GaugePalette.zoneColor(primary ? (driver.severity ?? "watch") : driver.severity)
                    )
                }
            }
        }

        @ViewBuilder
        private func domainCard(_ domain: UserOutlookDomain, window: UserOutlookWindow, primary: UserOutlookDriver?) -> some View {
            VStack(alignment: .leading, spacing: 8) {
                HStack(alignment: .top, spacing: 8) {
                    Text(domain.label ?? domain.key.replacingOccurrences(of: "_", with: " ").capitalized)
                        .font(.headline.weight(.semibold))
                    Spacer()
                    StatusPill((domain.likelihood ?? "watch").capitalized, severity: severity(domain.likelihood))
                }
                if let gauge = domain.currentGauge {
                    Text("Gauge now \(Int(gauge.rounded()))")
                        .font(.footnote)
                        .foregroundColor(.secondary)
                }
                if let topDriver = (domain.topDriverLabel ?? domain.topDriverKey)?.nilIfTrimmedEmpty {
                    LocalConditionsValueChip(
                        label: "Linked signal",
                        value: topDriver,
                        tint: GaugePalette.zoneColor(domain.likelihood)
                    )
                }
            }
            .padding(12)
            .frame(maxWidth: .infinity, alignment: .leading)
            .background(Color.white.opacity(0.04))
            .clipShape(RoundedRectangle(cornerRadius: 16, style: .continuous))
            .overlay(
                RoundedRectangle(cornerRadius: 16, style: .continuous)
                    .stroke(Color.white.opacity(0.06), lineWidth: 1)
            )
        }

        private func dailyDateText(_ isoDay: String?) -> String? {
            guard let isoDay else { return nil }
            let parser = DateFormatter()
            parser.calendar = Calendar(identifier: .gregorian)
            parser.locale = Locale(identifier: "en_US_POSIX")
            parser.timeZone = TimeZone(secondsFromGMT: 0)
            parser.dateFormat = "yyyy-MM-dd"
            guard let date = parser.date(from: isoDay) else { return nil }
            let formatter = DateFormatter()
            formatter.setLocalizedDateFormatFromTemplate("MMM d")
            return formatter.string(from: date)
        }

        private func dailySummary(_ day: UserOutlookDay) -> String? {
            refinedText(day.voiceSemantic?.interpretation?.headerSummary ?? day.summary)
        }

        private func dailySupportLine(_ day: UserOutlookDay) -> String? {
            let support = refinedText(day.voiceSemantic?.interpretation?.supportSummary ?? day.supportLine)
            guard !textCarriesSameIdea(support, dailySummary(day)) else { return nil }
            return support
        }

        private func dailyState(_ day: UserOutlookDay) -> String {
            let raw = day.primaryState
                ?? day.topDrivers?.first?.severity
                ?? day.likelyElevatedDomains?.first?.likelihood
                ?? "watch"
            return raw.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty ? "watch" : raw
        }

        private func dailyDriverLabel(_ driver: UserOutlookDriver) -> String {
            driver.label ?? driver.key.replacingOccurrences(of: "_", with: " ").capitalized
        }

        @ViewBuilder
        private func dailyOutlookRow(_ day: UserOutlookDay) -> some View {
            let drivers = visibleDrivers(day.topDrivers ?? [])
            let domains = day.likelyElevatedDomains ?? []
            let state = dailyState(day)
            let title = day.label?.nilIfTrimmedEmpty ?? dailyDateText(day.day) ?? "Day"
            let dateText = dailyDateText(day.day)

            VStack(alignment: .leading, spacing: 10) {
                HStack(alignment: .firstTextBaseline, spacing: 10) {
                    VStack(alignment: .leading, spacing: 2) {
                        Text(title)
                            .font(.headline.weight(.semibold))
                        if let dateText, dateText != title {
                            Text(dateText)
                                .font(.caption)
                                .foregroundColor(.secondary)
                        }
                    }
                    Spacer()
                    StatusPill(state.capitalized, severity: severity(state))
                }

                if let summary = dailySummary(day) {
                    Text(summary)
                        .font(.subheadline)
                        .foregroundColor(.secondary)
                        .fixedSize(horizontal: false, vertical: true)
                }

                if let support = dailySupportLine(day) {
                    Text(support)
                        .font(.caption)
                        .foregroundColor(.secondary.opacity(0.86))
                        .fixedSize(horizontal: false, vertical: true)
                }

                if !drivers.isEmpty {
                    VStack(alignment: .leading, spacing: 8) {
                        Text("Signals in view")
                            .font(.caption.weight(.semibold))
                            .foregroundColor(.secondary)
                        driverFactChips(Array(drivers.prefix(3)))
                    }
                }

                if let domain = domains.first {
                    LocalConditionsValueChip(
                        label: "Likely",
                        value: domain.label ?? domain.key.replacingOccurrences(of: "_", with: " ").capitalized,
                        tint: GaugePalette.zoneColor(domain.likelihood)
                    )
                }
            }
            .padding(12)
            .frame(maxWidth: .infinity, alignment: .leading)
            .background(Color.white.opacity(0.04))
            .clipShape(RoundedRectangle(cornerRadius: 16, style: .continuous))
            .overlay(
                RoundedRectangle(cornerRadius: 16, style: .continuous)
                    .stroke(Color.white.opacity(0.06), lineWidth: 1)
            )
        }

        @ViewBuilder
        private func dailyOutlookSection(_ days: [UserOutlookDay]) -> some View {
            if !days.isEmpty {
                LocalConditionsSurfaceCard(title: hasPlusAccess ? "7-Day Forecast" : "Next 24 Hours", icon: "calendar") {
                    VStack(alignment: .leading, spacing: 10) {
                        ForEach(Array(days.prefix(7))) { day in
                            dailyOutlookRow(day)
                        }
                    }
                }
            }
        }

