                            }
                        }

                        if !domains.isEmpty {
                            VStack(alignment: .leading, spacing: 8) {
                                Text("Most likely to show up in")
                                    .font(.footnote.weight(.semibold))
                                    .foregroundColor(.secondary)
                                LazyVGrid(columns: columns, alignment: .leading, spacing: 10) {
                                    ForEach(domains) { domain in
                                        domainCard(domain, window: window, primary: primary)
                                    }
                                }
                            }
                        }

                        if let draft = shareDraft(for: window) {
                            Button {
                                shareDraft = draft
                            } label: {
                                Label(sharePrompt(for: draft.card.accentLevel), systemImage: "square.and.arrow.up")
                            }
                            .buttonStyle(.bordered)
                            .controlSize(.small)
                        }
                    }
                }
            }
        }

        var body: some View {
            let cleanError = ContentView.scrubError(error)

            ZStack {
                Color.black.opacity(0.97).ignoresSafeArea()

                ScrollView {
                    LazyVStack(spacing: 16) {
                        LocalConditionsSurfaceCard(title: "Near-Future Outlook", icon: "calendar.badge.clock") {
                            HStack(alignment: .center, spacing: 12) {
                                VStack(alignment: .leading, spacing: 8) {
                                    if let updated = formatUpdate(payload?.generatedAt) {
                                        Text("Updated \(updated)")
                                            .font(.footnote)
                                            .foregroundColor(.secondary)
                                    }
                                }
                                Spacer()
                                if isLoading { ProgressView().scaleEffect(0.85) }
                                HStack(spacing: 8) {
                                    Button("Refresh") { onRefresh() }
                                        .buttonStyle(.bordered)
                                        .controlSize(.small)
                                    Button("Drivers") { onOpenAllDrivers() }
                                        .buttonStyle(.bordered)
                                        .controlSize(.small)
                                }
                            }

                            if let cleanError, !cleanError.isEmpty {
                                Text(cleanError)
                                    .font(.caption)
                                    .foregroundColor(.orange)
                            }

                            if !isLoading && cleanError == nil && payload == nil {
                                Text(payload?.semanticEmptyState ?? "No outlook yet. Add your location and give forecast data a little more time.")
                                    .font(.caption)
                                    .foregroundColor(.secondary)
                            }
                        }

                        if let daily = payload?.dailyOutlook, !daily.isEmpty {
                            dailyOutlookSection(hasPlusAccess ? daily : Array(daily.prefix(1)))
                            if !hasPlusAccess && daily.count > 1 {
                                plusOutlookLockedCard
                            }
                        } else {
                            windowSection(payload?.next24h)
                            if hasPlusAccess {
                                windowSection(payload?.next72h)
                                windowSection(payload?.next7d)
                            } else if userOutlookWindowHasContent(payload?.next72h) || userOutlookWindowHasContent(payload?.next7d) {
                                plusOutlookLockedCard
                            }
                        }

                        if hasPlusAccess
                            && !isLoading
                            && (payload?.dailyOutlook?.isEmpty ?? true)
                            && !userOutlookWindowHasContent(payload?.next7d) {
                            LocalConditionsSurfaceCard(title: "7-Day Outlook", icon: "calendar") {
                                Text(payload?.semanticSevenDayPending ?? "The 7-day view will appear once the forecast layer is steady enough to support it.")
                                    .font(.subheadline)
                                    .foregroundColor(.secondary)
                            }
                        }
                    }
                    .padding(16)
                    .frame(maxWidth: .infinity, alignment: .leading)
                }
            }
            .navigationTitle("Outlook")
            .navigationBarTitleDisplayMode(.inline)
            .sheet(item: $shareDraft) { draft in
                SharePreviewView(draft: draft)
            }
        }
    }

    private struct YourPatternsView: View {
        @EnvironmentObject private var state: AppState
        let experienceMode: ExperienceMode
        let lunarSensitivityDeclared: Bool
        @AppStorage("user_patterns_cache_json") private var userPatternsCacheJSON: String = ""
        @State private var payload: UserPatternsPayload? = nil
        @State private var isLoading: Bool = false
        @State private var errorMessage: String? = nil
        @State private var lunarInsights: LunarInsightPayload? = nil
        @State private var lunarInsightsLoading: Bool = false
        @State private var lunarInsightsError: String? = nil
        @State private var showsAllStrongestPatterns: Bool = false
        @State private var showsAllEmergingPatterns: Bool = false
        @State private var showsAllBodySignalPatterns: Bool = false
        @State private var shareDraft: ShareDraft? = nil

        private func confidenceSeverity(_ confidence: String?) -> StatusPill.Severity {
            switch (confidence ?? "").lowercased() {
            case "strong":
                return .ok
            case "moderate":
                return .warn
            case "emerging":
                return .warn
            default:
                return .ok
            }
        }

        private func displayDate(_ value: String?) -> String {
            guard let value, let parsed = ISO8601DateFormatter().date(from: value) else { return "—" }
            let formatter = DateFormatter()
            formatter.dateStyle = .medium
            formatter.timeStyle = .none
            return formatter.string(from: parsed)
        }

        private func liftLine(_ card: UserPatternCard) -> String {
            if let semantic = card.semanticEvidenceSummary {
                return semantic
            }
            let lift = String(format: "%.1fx", card.relativeLift ?? 0)
            let lag = card.lagLabel ?? "same day"
            let sample = card.sampleSize ?? card.exposedDays ?? 0
            return "\(lift) more common when this signal was present • \(sample) days • Lag \(lag)"
        }

        private func rateLine(_ card: UserPatternCard) -> String {
            if let semantic = card.semanticBaselineSummary {
                return semantic
            }
            let exposedRate = Int(round((card.exposedRate ?? 0) * 100))
            let baselineRate = Int(round((card.unexposedRate ?? 0) * 100))
            let lastSeen = displayDate(card.lastSeenAt)
            return "Signal present: \(exposedRate)% • Baseline: \(baselineRate)% • Last seen: \(lastSeen)"
        }

        private func iconName(for signalKey: String) -> String {
            if signalKey.lowercased().contains("lunar") || signalKey.lowercased().contains("moon") {
                return "moon.stars.fill"
            }
            switch signalKey {
            case "pressure_swing_exposed":
                return "gauge.with.dots.needle.bottom.50percent"
            case "aqi_moderate_plus_exposed":
                return "aqi.low"
            case "temp_swing_exposed":
                return "thermometer.medium"
            case "kp_g1_plus_exposed":
                return "sun.max.fill"
            case "bz_south_exposed":
                return "arrow.down.circle"
            case "solar_wind_exposed":
                return "wind"
            case "schumann_exposed":
                return "waveform.path.ecg"
            default:
                return "chart.line.uptrend.xyaxis"
            }
        }

        private func visibleCards(_ cards: [UserPatternCard], expanded: Bool) -> [UserPatternCard] {
            if expanded {
                return cards
            }
            return Array(cards.prefix(3))
        }

        private func shareAccent(for card: UserPatternCard) -> ShareAccentLevel {
            switch (card.confidence ?? "").lowercased() {
            case "strong":
                return .elevated
            case "moderate":
                return .watch
            case "emerging":
                return .watch
            default:
                return card.usedToday == true ? .elevated : .calm
            }
        }

        private func sharePrompt(for card: UserPatternCard) -> String {
            _ = card
            return "Share"
        }

        private func shareBackground(for signalKey: String) -> ShareCardBackground {
            let key = signalKey.lowercased()
            if key.contains("lunar") || key.contains("moon") {
                return ShareCardBackground(style: .abstract, themeKeys: ["lunar", "moon", "full_moon", "new_moon"])
            }
            switch signalKey {
            case "schumann_exposed":
                return ShareCardBackground(style: .schumann)
            case "kp_g1_plus_exposed", "bz_south_exposed", "solar_wind_exposed":
                return ShareCardBackground(style: .solar)
            case "pressure_swing_exposed", "aqi_moderate_plus_exposed", "temp_swing_exposed":
                return ShareCardBackground(style: .atmospheric)
            default:
                return ShareCardBackground(style: .abstract)
            }
        }

        private func shareDraft(for card: UserPatternCard) -> ShareDraft {
            ShareDraftFactory.personalPattern(
                surface: "your_patterns",
                analyticsKey: card.signalKey,
                mode: experienceMode,
                relationship: "\(card.signal) → \(card.outcome) (for you)",
                explanation: card.explanation,
                evidenceCount: card.sampleSize ?? card.exposedDays,
                lagText: card.lagLabel ?? card.lagHours.map { "\($0)h" },
                confidence: card.confidence,
                accent: shareAccent(for: card),
                background: shareBackground(for: card.signalKey),
                updatedAt: displayDate(payload?.generatedAt),
                promptText: sharePrompt(for: card)
            )
        }

        private func lunarShareAccent(_ strength: String?) -> ShareAccentLevel {
            switch (strength ?? "").lowercased() {
            case "moderate":
                return .watch
            case "weak":
                return .calm
            default:
                return lunarSensitivityDeclared ? .watch : .calm
            }
        }

        private func lunarShareDraft() -> ShareDraft? {
            guard let lunarInsights else { return nil }
            let rawWindow = lunarInsights.highlightWindow?
                .trimmingCharacters(in: .whitespacesAndNewlines)
                .lowercased()
            let window = (rawWindow?.isEmpty == false ? rawWindow! : "lunar")
            let metric = lunarInsights.highlightMetric?
                .replacingOccurrences(of: "_", with: " ")
                .trimmingCharacters(in: .whitespacesAndNewlines)
            let metricText = metric?.isEmpty == false ? metric! : "your pattern"
            let windowLabel: String
            if window == "full" || window == "new" {
                windowLabel = "\(window.capitalized) moon window"
            } else {
                windowLabel = "Lunar window"
            }
            let analyticsKey = window == "full" || window == "new"
                ? "lunar_\(window)_window_exposed"
                : "lunar_window_exposed"
            let themeKeys = window == "full"
                ? ["lunar", "moon", "full_moon"]
                : window == "new"
                    ? ["lunar", "moon", "new_moon"]
                    : ["lunar", "moon"]
            let observed = lunarInsights.observedDays ?? lunarInsights.nNights
            return ShareDraftFactory.personalPattern(
                surface: "your_patterns",
                analyticsKey: analyticsKey,
                mode: experienceMode,
                relationship: "\(windowLabel) → \(metricText) (for you)",
                explanation: lunarInsightMessage ?? lunarWindowLine ?? "Lunar windows compared with your own history.",
                evidenceCount: (observed ?? 0) > 0 ? observed : nil,
                lagText: nil,
                confidence: lunarInsights.patternStrength,
                accent: lunarShareAccent(lunarInsights.patternStrength),
                background: ShareCardBackground(style: .abstract, themeKeys: themeKeys),
                updatedAt: displayDate(payload?.generatedAt),
                promptText: "Share"
            )
        }

        private var lunarInsightMessage: String? {
            switch experienceMode {
            case .scientific:
                return lunarInsights?.messageScientific
            case .mystical:
                return lunarInsights?.messageMystical
            }
        }

        private var shouldShowLunarSection: Bool {
            if lunarInsightsLoading {
                return true
            }
            if lunarSensitivityDeclared {
                return true
            }
            guard let lunarInsights else { return false }
            return lunarInsights.insufficientData == false
                && (lunarInsights.patternStrength?.lowercased() ?? "none") != "none"
        }

        private var lunarStrengthLabel: String {
            let strength = (lunarInsights?.patternStrength ?? "tracking").lowercased()
            switch strength {
            case "moderate":
                return "Moderate"
            case "weak":
                return "Weak"
            case "none":
                return lunarSensitivityDeclared ? "Tracking" : "Observed"
            default:
                return "Tracking"
            }
        }

        private var lunarStrengthSeverity: StatusPill.Severity {
            switch (lunarInsights?.patternStrength ?? "").lowercased() {
            case "moderate":
                return .warn
            case "weak":
                return .ok
            default:
                return .ok
            }
        }

        private var lunarWindowLine: String? {
            guard let lunarInsights else { return nil }
            guard
                let highlightWindow = lunarInsights.highlightWindow,
                let highlightMetric = lunarInsights.highlightMetric,
                let strength = lunarInsights.patternStrength,
                strength.lowercased() != "none"
            else {
                return nil
            }

            return "\(highlightWindow.capitalized) moon • \(highlightMetric.replacingOccurrences(of: "_", with: " ")) • \(strength.capitalized)"
        }

        private var lunarObservedLine: String? {
            let observedDays = lunarInsights?.observedDays ?? lunarInsights?.nNights ?? 0
            guard observedDays > 0 else { return nil }

            if let context = lunarInsights?.currentLunarContext,
               let phase = context.moonPhaseLabel,
               !phase.isEmpty {
                let fullDays = context.daysFromFullMoon.map { "\($0)d from full" } ?? nil
                let newDays = context.daysFromNewMoon.map { "\($0)d from new" } ?? nil
                let distanceText = [fullDays, newDays].compactMap { $0 }.joined(separator: " • ")
                if !distanceText.isEmpty {
                    return "Observed across \(observedDays) days • Current phase: \(phase) • \(distanceText)"
                }
                return "Observed across \(observedDays) days • Current phase: \(phase)"
            }

            return "Observed across \(observedDays) days"
        }

        private var lunarSectionTitle: String {
            if lunarInsightsLoading && lunarInsights == nil {
                return "Lunar windows"
            }
            if let strength = lunarInsights?.patternStrength?.lowercased(),
               strength == "moderate" || strength == "weak" {
                return "Possible lunar sensitivity"
            }
            if lunarInsights?.insufficientData == true {
                return "Lunar windows still forming"
            }
            return "No clear lunar signal yet"
        }

        @ViewBuilder
        private var lunarSectionView: some View {
            VStack(alignment: .leading, spacing: 12) {
                VStack(alignment: .leading, spacing: 4) {
                    Text("Lunar Windows")
                        .font(.title3.weight(.semibold))
                    Text("Full and new moon windows compared with your own sleep, HRV, and symptom history.")
                        .font(.caption)
                        .foregroundColor(.secondary)
                }

                VStack(alignment: .leading, spacing: 12) {
                    HStack(alignment: .top, spacing: 12) {
                        ZStack {
                            RoundedRectangle(cornerRadius: 14, style: .continuous)
                                .fill(Color.white.opacity(0.06))
                            Image(systemName: "moon.stars.fill")
                                .font(.headline)
                                .foregroundColor(.white.opacity(0.88))
                        }
                        .frame(width: 44, height: 44)

                        VStack(alignment: .leading, spacing: 4) {
                            Text(lunarSectionTitle)
                                .font(.headline.weight(.semibold))
                                .foregroundColor(.white.opacity(0.95))
                            if let lunarObservedLine, !lunarObservedLine.isEmpty {
                                Text(lunarObservedLine)
                                    .font(.subheadline)
                                    .foregroundColor(.secondary)
                            }
                        }

                        Spacer(minLength: 8)

                        VStack(alignment: .trailing, spacing: 8) {
                            StatusPill(lunarStrengthLabel, severity: lunarStrengthSeverity)
                            if let draft = lunarShareDraft(), !lunarInsightsLoading {
                                Button("Share") {
                                    shareDraft = draft
                                }
                                .buttonStyle(.bordered)
                                .controlSize(.small)
                            }
                        }
                    }

                    if lunarInsightsLoading && lunarInsights == nil {
                        HStack(spacing: 10) {
                            ProgressView()
                            Text("Checking lunar windows in your history.")
                                .font(.subheadline)
                                .foregroundColor(.secondary)
                        }
                    } else {
                        if let lunarInsightMessage, !lunarInsightMessage.isEmpty {
                            Text(CopyRefiner.refine(lunarInsightMessage) ?? lunarInsightMessage)
                                .font(.subheadline)
                                .foregroundColor(.white.opacity(0.88))
                        }

                        if let lunarWindowLine, !lunarWindowLine.isEmpty {
                            Text(lunarWindowLine)
                                .font(.caption)
                                .foregroundColor(.secondary)
                        } else if lunarInsights?.insufficientData == true {
                            Text("No lunar pattern yet. More overlap is needed before this section fills in.")
                                .font(.caption)
                                .foregroundColor(.secondary)
                        }

                        if let lunarInsightsError, lunarInsights == nil {
                            Text(lunarInsightsError)
                                .font(.caption)
                                .foregroundColor(.secondary)
                        }
                    }
                }
                .padding(16)
                .frame(maxWidth: .infinity, alignment: .leading)
                .background(Color.white.opacity(0.06))
                .clipShape(RoundedRectangle(cornerRadius: 22, style: .continuous))
                .overlay(
                    RoundedRectangle(cornerRadius: 22, style: .continuous)
                        .stroke(Color.white.opacity(0.08), lineWidth: 1)
                )
            }
        }

        @MainActor
        private func decodeCachedPatternsPayload() -> UserPatternsPayload? {
            guard !userPatternsCacheJSON.isEmpty,
                  let data = userPatternsCacheJSON.data(using: .utf8) else { return nil }
            return try? JSONDecoder().decode(UserPatternsPayload.self, from: data)
        }

        @MainActor
        private func hydrateCachedPatternsIfNeeded() {
            guard payload == nil, let cached = decodeCachedPatternsPayload() else { return }
            payload = cached
        }

        @MainActor
        private func persistPatternsPayload(_ value: UserPatternsPayload) {
            guard let data = try? JSONEncoder().encode(value),
                  let json = String(data: data, encoding: .utf8) else { return }
            userPatternsCacheJSON = json
        }

        private func mergeSummaryPayload(_ summary: UserPatternsPayload, into current: UserPatternsPayload?) -> UserPatternsPayload {
            let preservesFullSections = current?.partial == false
            return UserPatternsPayload(
                ok: summary.ok ?? current?.ok,
                partial: preservesFullSections ? false : (summary.partial ?? current?.partial),
                generatedAt: summary.generatedAt ?? current?.generatedAt,
                disclaimer: summary.disclaimer ?? current?.disclaimer,
                strongestPatterns: summary.strongestPatterns ?? current?.strongestPatterns,
                emergingPatterns: current?.emergingPatterns,
                bodySignalsPatterns: current?.bodySignalsPatterns,
                voiceSemantics: summary.voiceSemantics ?? current?.voiceSemantics
            )
        }

        private func loadPatterns(force: Bool = false) async {
            let alreadyLoading = await MainActor.run { isLoading }
            if alreadyLoading && !force {
                return
            }
            await MainActor.run {
                hydrateCachedPatternsIfNeeded()
                isLoading = true
            }

            let api = state.apiWithAuth()

            do {
                let summary: UserPatternsPayload = try await api.getJSON(
                    "v1/patterns/summary",
                    as: UserPatternsPayload.self,
                    perRequestTimeout: 8
                )
                await MainActor.run {
                    let merged = mergeSummaryPayload(summary, into: payload)
                    payload = merged
                    persistPatternsPayload(merged)
                    errorMessage = nil
                }
            } catch {
                let hasVisiblePayload = await MainActor.run { payload != nil }
                if !hasVisiblePayload {
                    await MainActor.run {
                        errorMessage = ContentView.scrubError(error.localizedDescription)
                    }
                }
            }

            do {
                let decoded: UserPatternsPayload = try await api.getJSON(
                    "v1/patterns",
                    as: UserPatternsPayload.self,
                    perRequestTimeout: 20
                )
                await MainActor.run {
                    payload = decoded
                    persistPatternsPayload(decoded)
                    errorMessage = nil
                }
            } catch {
                let hasVisiblePayload = await MainActor.run { payload != nil }
                if !hasVisiblePayload {
                    await MainActor.run {
                        errorMessage = ContentView.scrubError(error.localizedDescription)
                    }
                }
            }

            await MainActor.run {
                isLoading = false
            }
        }

        private func loadLunarInsights(force: Bool = false) async {
            let shouldStart = await MainActor.run { () -> Bool in
                if lunarInsightsLoading {
                    return false
                }
                if !force && lunarInsights != nil {
                    return false
                }
                lunarInsightsLoading = true
                lunarInsightsError = nil
                return true
            }
            guard shouldStart else { return }

            defer {
                Task { @MainActor in
                    lunarInsightsLoading = false
                }
            }

            let backendAvailable = await MainActor.run { state.backendDBAvailable }
            guard backendAvailable else {
                await MainActor.run {
                    lunarInsightsError = "Lunar patterns are unavailable while the backend database is offline."
                }
                return
            }

            let api = state.apiWithAuth()
            do {
                let decoded: LunarInsightPayload = try await api.getJSON(
                    "v1/insights/lunar",
                    as: LunarInsightPayload.self,
                    perRequestTimeout: 20
                )
                await MainActor.run {
                    lunarInsights = decoded
                    lunarInsightsError = nil
                }
            } catch {
                await MainActor.run {
                    if lunarInsights == nil {
                        lunarInsightsError = ContentView.scrubError(error.localizedDescription)
                    }
                }
            }
        }

