        @ViewBuilder
        private func sectionView(
            title: String,
            subtitle: String,
            cards: [UserPatternCard],
            emptyMessage: String,
            pendingMessage: String? = nil,
            isPending: Bool = false,
            expanded: Binding<Bool>
        ) -> some View {
            let displayedCards = visibleCards(cards, expanded: expanded.wrappedValue)

            VStack(alignment: .leading, spacing: 12) {
                VStack(alignment: .leading, spacing: 4) {
                    Text(title)
                        .font(.title3.weight(.semibold))
                    Text(subtitle)
                        .font(.caption)
                        .foregroundColor(.secondary)
                }

                if cards.isEmpty {
                    Group {
                        if isPending {
                            HStack(spacing: 10) {
                                ProgressView()
                                Text(pendingMessage ?? "Loading more pattern history.")
                            }
                            .font(.subheadline)
                            .foregroundColor(.secondary)
                        } else {
                            Text(emptyMessage)
                                .font(.subheadline)
                                .foregroundColor(.secondary)
                        }
                    }
                        .padding(16)
                        .frame(maxWidth: .infinity, alignment: .leading)
                        .background(Color.white.opacity(0.04))
                        .clipShape(RoundedRectangle(cornerRadius: 18, style: .continuous))
                } else {
                    ForEach(displayedCards) { card in
                        PatternCardView(
                            card: card,
                            iconName: iconName(for: card.signalKey),
                            confidenceSeverity: confidenceSeverity(card.confidence),
                            liftLine: liftLine(card),
                            rateLine: rateLine(card),
                            shareLabel: sharePrompt(for: card),
                            onShare: {
                                shareDraft = shareDraft(for: card)
                            }
                        )
                    }

                    if cards.count > 3 {
                        Button(expanded.wrappedValue ? "Show fewer patterns" : "Show all patterns (\(cards.count))") {
                            expanded.wrappedValue.toggle()
                        }
                        .font(.caption.weight(.semibold))
                        .foregroundColor(Color(red: 0.46, green: 0.7, blue: 1.0))
                        .buttonStyle(.plain)
                    }
                }
            }
        }

        var body: some View {
            let strongest = payload?.strongestPatterns ?? []
            let emerging = payload?.emergingPatterns ?? []
            let bodySignals = payload?.bodySignalsPatterns ?? []
            let isPartialPayload = payload?.partial == true
            let isLoadingSupplementalSections = isLoading && isPartialPayload

            ZStack {
                Color.black.opacity(0.97).ignoresSafeArea()

                ScrollView {
                    LazyVStack(alignment: .leading, spacing: 18) {
                        VStack(alignment: .leading, spacing: 6) {
                            Text("What keeps showing up in your history.")
                                .font(.system(size: 30, weight: .bold, design: .rounded))
                            Text(
                                CopyRefiner.refine(payload?.semanticHeaderSummary)
                                ?? payload?.semanticHeaderSummary
                                ?? CopyRefiner.refine(payload?.disclaimer)
                                ?? "Patterns compare your logs and health stats with repeating signals in your history."
                            )
                                .font(.subheadline)
                                .foregroundColor(.secondary)
                        }

                        if let errorMessage, payload == nil {
                            Text(errorMessage)
                                .font(.subheadline)
                                .foregroundColor(.secondary)
                                .padding(16)
                                .frame(maxWidth: .infinity, alignment: .leading)
                                .background(Color.white.opacity(0.04))
                                .clipShape(RoundedRectangle(cornerRadius: 18, style: .continuous))
                        }

                        if isLoading && payload == nil {
                            HStack(spacing: 10) {
                                ProgressView()
                                Text("Refreshing your pattern view.")
                                    .font(.subheadline)
                                    .foregroundColor(.secondary)
                            }
                            .padding(16)
                            .frame(maxWidth: .infinity, alignment: .leading)
                            .background(Color.white.opacity(0.04))
                            .clipShape(RoundedRectangle(cornerRadius: 18, style: .continuous))
                        }

                        sectionView(
                            title: "Clearest Patterns",
                            subtitle: payload?.semanticStrongestSubtitle ?? "The clearest repeats in your history so far.",
                            cards: strongest,
                            emptyMessage: payload?.semanticStrongestEmpty ?? "No clear patterns yet. Most people need about 14-30 days of symptom logs before repeat overlaps stand out. If you skipped the 30-day Health import, body-signal patterns may take about a month to appear. Keep logging ordinary days and rough days.",
                            expanded: $showsAllStrongestPatterns
                        )

                        sectionView(
                            title: "Body Signals",
                            subtitle: payload?.semanticBodySubtitle ?? "Wearable-based patterns appear here when the overlap is strong enough.",
                            cards: bodySignals,
                            emptyMessage: payload?.semanticBodyEmpty ?? "No body-signal patterns are standing out yet. Wearable patterns need enough sleep, heart, HRV, and symptom history. If you skipped backfill, this can take about a month of fresh Health data.",
                            pendingMessage: payload?.semanticBodyPending ?? "Checking wearable patterns now.",
                            isPending: isLoadingSupplementalSections,
                            expanded: $showsAllBodySignalPatterns
                        )

                        sectionView(
                            title: "Still Taking Shape",
                            subtitle: payload?.semanticEmergingSubtitle ?? "Possible repeats that still need more overlap before they feel reliable.",
                            cards: emerging,
                            emptyMessage: payload?.semanticEmergingEmpty ?? "Nothing is clearly emerging yet. More overlap will help this section fill in.",
                            pendingMessage: payload?.semanticEmergingPending ?? "Loading the rest of your pattern history.",
                            isPending: isLoadingSupplementalSections,
                            expanded: $showsAllEmergingPatterns
                        )

                        if shouldShowLunarSection {
                            lunarSectionView
                        }
                    }
                    .padding(16)
                    .frame(maxWidth: .infinity, alignment: .leading)
                }
                .refreshable {
                    async let patternsRefresh: Void = loadPatterns(force: true)
                    async let lunarRefresh: Void = loadLunarInsights(force: true)
                    _ = await (patternsRefresh, lunarRefresh)
                }
            }
            .navigationTitle("Patterns")
            .navigationBarTitleDisplayMode(.inline)
            .sheet(item: $shareDraft) { draft in
                SharePreviewView(draft: draft)
            }
            .toolbar {
                ToolbarItem(placement: .topBarTrailing) {
                    Button {
                        Task { await loadPatterns(force: true) }
                    } label: {
                        if isLoading {
                            ProgressView()
                        } else {
                            Image(systemName: "arrow.clockwise")
                        }
                    }
                }
            }
            .onAppear {
                hydrateCachedPatternsIfNeeded()
            }
            .task {
                async let patternsLoad: Void = loadPatterns()
                async let lunarLoad: Void = loadLunarInsights()
                _ = await (patternsLoad, lunarLoad)
            }
        }
    }

    private struct InsightsSpaceWeatherView: View {
        let current: FeaturesToday?
        let updatedText: String?
        let usingYesterdayFallback: Bool
        let forecast: ForecastSummary?
        let outlook: SpaceForecastOutlook?
        let magnetosphere: MagnetosphereData?
        let plusUnlocked: Bool
        let onRefresh: () async -> Void
        let onLoadFullForecast: () async -> Void
        @State private var showAllForecastDays: Bool = false
        @State private var fullForecastLoading: Bool = false
        @State private var manualRefreshLoading: Bool = false
        @State private var initialRefreshTriggered: Bool = false

        private func progress(_ value: Double?, max: Double) -> Double {
            guard let value, max > 0 else { return 0.12 }
            return LocalConditionsFormatting.clamped(abs(value) / max)
        }

        private func severity(_ raw: String?) -> StatusPill.Severity {
            LocalConditionsStyle.pillSeverity(raw)
        }

        private var metrics: SpaceWeatherCardMetrics {
            SpaceWeatherCardMetrics(current: current, outlook: outlook, series: nil, magnetosphere: magnetosphere)
        }

        private var needsInitialRefresh: Bool {
            guard plusUnlocked else { return false }
            let forecastDayCount = outlook?.forecastDaily?.count ?? 0
            let hasFullForecastDays = forecastDayCount >= 7
            let hasOutlookSummaries =
                !(outlook?.sections.isEmpty ?? true) ||
                !(outlook?.alerts?.isEmpty ?? true) ||
                !(outlook?.notes?.isEmpty ?? true)
            let hasForecastSummary =
                forecast != nil ||
                !(outlook?.headline?.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty ?? true) ||
                !(outlook?.summary?.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty ?? true)

            return magnetosphere == nil || !hasForecastSummary || !hasFullForecastDays || (!hasOutlookSummaries && forecastDayCount == 0)
        }

        private func cleanedOutlookLine(_ raw: String?) -> String? {
            guard let raw else { return nil }
            let trimmed = raw
                .trimmingCharacters(in: .whitespacesAndNewlines)
                .replacingOccurrences(of: "•", with: "")
                .trimmingCharacters(in: .whitespacesAndNewlines)
            guard !trimmed.isEmpty else { return nil }
            let lower = trimmed.lowercased()
            if lower == "space weather outlook" || lower == "outlook" || lower == "forecast" {
                return nil
            }
            return CopyRefiner.refine(trimmed)
        }

        private var forecastBodyLines: [String] {
            guard let body = forecast?.body, !body.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty else {
                return []
            }
            return body
                .components(separatedBy: .newlines)
                .compactMap(cleanedOutlookLine)
        }

        private var sectionSummaryLines: [String] {
            (outlook?.sections ?? [])
                .flatMap { section in
                    section.entries.compactMap { entry in
                        cleanedOutlookLine(entry.summary ?? entry.title)
                    }
                }
        }

        private func outlookMetricValue(matching keywords: [String]) -> Double? {
            let lowered = keywords.map { $0.lowercased() }
            for section in outlook?.sections ?? [] {
                for entry in section.entries {
                    let haystack = [
                        entry.title?.lowercased(),
                        entry.summary?.lowercased(),
                        entry.driver?.lowercased(),
                        entry.metric?.lowercased()
                    ]
                    .compactMap { $0 }
                    .joined(separator: " ")
                    if lowered.contains(where: { haystack.contains($0) }), let value = entry.value {
                        return value
                    }
                }
            }
            return nil
        }

        private var outlookSummaryLines: [String] {
            var lines: [String] = []
            if let headline = cleanedOutlookLine(outlook?.headline), !lines.contains(headline) {
                lines.append(headline)
            }
            if let summary = cleanedOutlookLine(outlook?.summary), !lines.contains(summary) {
                lines.append(summary)
            }
            if let forecastHeadline = cleanedOutlookLine(forecast?.headline), !lines.contains(forecastHeadline) {
                lines.append(forecastHeadline)
            }
            for bucket in [forecast?.lines ?? [], forecastBodyLines, outlook?.alerts ?? [], sectionSummaryLines, outlook?.notes ?? []] {
                for rawLine in bucket {
                    if let line = cleanedOutlookLine(rawLine), !lines.contains(line) {
                        lines.append(line)
                    }
                    if lines.count >= 4 {
                        return Array(lines.prefix(4))
                    }
                }
            }
            return Array(lines.prefix(4))
        }

        private func forecastDayLabel(_ iso: String?) -> String {
            guard let iso else { return "Day" }
            let fmt = ISO8601DateFormatter()
            if let date = fmt.date(from: iso) {
                let out = DateFormatter()
                out.dateFormat = "EEE, MMM d"
                return out.string(from: date)
            }
            let simple = DateFormatter()
            simple.dateFormat = "yyyy-MM-dd"
            if let date = simple.date(from: iso) {
                let out = DateFormatter()
                out.dateFormat = "EEE, MMM d"
                return out.string(from: date)
            }
            return iso
        }

        private func watchFlags(for day: SpaceForecastDay) -> [String] {
            var flags: [String] = []
            if day.cmeWatch == true { flags.append("CME watch") }
            if day.flareWatch == true { flags.append("Flare watch") }
            if day.solarWindWatch == true { flags.append("Solar wind watch") }
            return flags
        }

        private var forecastLockedCard: some View {
            LocalConditionsSurfaceCard(title: "Forecast", icon: "lock.fill") {
                VStack(alignment: .leading, spacing: 10) {
                    Text("Space forecast is included with Plus")
                        .font(.subheadline.weight(.semibold))
                    Text("Current Kp, solar wind, and event stats stay available. Plus unlocks the outlook summary and 7-day forecast.")
                        .font(.caption)
                        .foregroundColor(.secondary)
                        .fixedSize(horizontal: false, vertical: true)
                    NavigationLink(destination: SubscribeView()) {
                        Label("View Plus", systemImage: "sparkles")
                            .frame(maxWidth: .infinity)
                    }
                    .buttonStyle(.borderedProminent)
                }
            }
        }

        var body: some View {
            let metrics = metrics
            let kpNow = metrics.kpNow
            let kpMax = metrics.kpMax
            let bzNow = metrics.bzNow
            let swSpeed = metrics.swSpeedNow
            let density = metrics.swDensityNow
                ?? outlookMetricValue(matching: ["density", "cm^-3", "cm-3", "cm3"])
            let protonFlux = metrics.protonFlux
            let flaresCount = outlook?.flares?.total24h ?? Int((current?.flaresCount?.value ?? 0).rounded())
            let cmeCount = outlook?.cmes?.stats?.total72h ?? Int((current?.cmesCount?.value ?? 0).rounded())
            let geomagneticContext = current?.effectiveGeomagneticContext
            let geomagneticState = SpaceWeatherPresentation.resolvedStateLabel(
                context: geomagneticContext,
                outlookLabel: outlook?.kp?.gScaleNow,
                kp: kpNow,
                speed: swSpeed,
                bz: bzNow,
                storminess: metrics.storminess
            )
            let liveOverride = SpaceWeatherPresentation.liveOverridesContext(
                context: geomagneticContext,
                outlookLabel: outlook?.kp?.gScaleNow,
                kp: kpNow,
                speed: swSpeed,
                bz: bzNow,
                storminess: metrics.storminess
            )

            ZStack {
                Color.black.opacity(0.97).ignoresSafeArea()

                ScrollView {
                    LazyVStack(spacing: 16) {
                        LocalConditionsSurfaceCard(title: "Geomagnetic State", icon: "sun.max.fill") {
                            VStack(alignment: .leading, spacing: 12) {
                                HStack(alignment: .top, spacing: 12) {
                                    VStack(alignment: .leading, spacing: 4) {
                                        Text(geomagneticState)
                                            .font(.system(size: 32, weight: .bold, design: .rounded))
                                        if let updatedText {
                                            Text("Updated \(updatedText)")
                                                .font(.caption)
                                                .foregroundColor(.secondary)
                                        }
                                        if liveOverride {
                                            Text("Live Kp, wind, and Bz are driving this state")
                                                .font(.caption)
                                                .foregroundColor(.secondary)
                                        } else if let confidence = geomagneticContext?.confidenceLabel, !confidence.isEmpty {
                                            Text("Confidence: \(confidence)")
                                                .font(.caption)
                                                .foregroundColor(.secondary)
                                        }
                                        if geomagneticContext?.isProvisional == true {
                                            Text("Baseline still building")
                                                .font(.caption)
                                                .foregroundColor(.secondary)
                                        } else if let raw = geomagneticContext?.classRaw, raw.localizedCaseInsensitiveContains("coherent") {
                                            Text("Coherent ground variability detected")
                                                .font(.caption)
                                                .foregroundColor(.secondary)
                                        }
                                    }
                                    Spacer()
                                    StatusPill(geomagneticState, severity: SpaceWeatherPresentation.severity(for: geomagneticState, fallbackKp: kpNow))
                                }

                                HStack(spacing: 12) {
                                    LocalConditionsMetricTile(
                                        title: "Kp Now",
                                        value: kpNow.map { String(format: "%.1f", $0) } ?? "—",
                                        progress: progress(kpNow, max: 9),
                                        tint: GaugePalette.zoneColor(kpNow.map { $0 >= 4 ? "elevated" : "low" })
                                    )
                                    LocalConditionsMetricTile(
                                        title: "Kp 24h Max",
                                        value: kpMax.map { String(format: "%.1f", $0) } ?? "—",
                                        progress: progress(kpMax, max: 9),
                                        tint: GaugePalette.zoneColor(kpMax.map { $0 >= 5 ? "high" : $0 >= 4 ? "elevated" : "low" })
                                    )
                                }

                                if usingYesterdayFallback {
                                    Text("Showing yesterday’s feature summary while today updates.")
                                        .font(.caption)
                                        .foregroundColor(.secondary)
                                }
                            }
                        }

                        LocalConditionsSurfaceCard(title: "Solar Wind", icon: "dot.radiowaves.left.and.right") {
                            HStack(spacing: 12) {
                                LocalConditionsMetricTile(
                                    title: "Bz",
                                    value: bzNow.map { String(format: "%.1f nT", $0) } ?? "—",
                                    progress: progress(bzNow, max: 20),
                                    tint: GaugePalette.zoneColor(SpaceWeatherPresentation.bzToneKey(bzNow))
                                )
                                LocalConditionsMetricTile(
                                    title: "Speed",
                                    value: swSpeed.map { String(format: "%.0f km/s", $0) } ?? "—",
                                    progress: progress(swSpeed, max: 800),
                                    tint: GaugePalette.zoneColor(SpaceWeatherPresentation.windToneKey(swSpeed))
                                )
                            }
                            HStack(spacing: 10) {
                                LocalConditionsValueChip(
                                    label: "Density",
                                    value: density.map { String(format: "%.1f cm^-3", $0) } ?? "—",
                                    tint: GaugePalette.mild
                                )
                                LocalConditionsValueChip(
                                    label: "Proton Flux",
                                    value: protonFlux.map { String(format: "%.1f pfu", $0) } ?? "—",
                                    tint: GaugePalette.elevated
                                )
                                LocalConditionsValueChip(
                                    label: "S-Scale",
                                    value: metrics.sScale ?? "S0",
                                    tint: GaugePalette.zoneColor((metrics.sScale ?? "S0") == "S0" ? "low" : "elevated")
                                )
                            }
                        }

                        LocalConditionsSurfaceCard(title: "Events", icon: "bolt.horizontal.fill") {
                            HStack(spacing: 10) {
                                LocalConditionsValueChip(
                                    label: "Flares",
                                    value: "\(flaresCount)",
                                    tint: GaugePalette.mild
                                )
                                LocalConditionsValueChip(
                                    label: "CMEs",
                                    value: "\(cmeCount)",
                                    tint: GaugePalette.elevated
                                )
                                LocalConditionsValueChip(
                                    label: "Wind",
                                    value: swSpeed.map { String(format: "%.0f km/s", $0) } ?? "—",
                                    tint: GaugePalette.zoneColor(SpaceWeatherPresentation.windToneKey(swSpeed))
                                )
                            }
                            if let headline = outlook?.cmes?.headline, !headline.isEmpty {
                                Text(headline)
                                    .font(.caption)
                                    .foregroundColor(.secondary)
                            }
                        }

                        if plusUnlocked {
                            if !outlookSummaryLines.isEmpty {
                                LocalConditionsSurfaceCard(title: "Outlook", icon: "text.justify.left") {
                                    VStack(alignment: .leading, spacing: 8) {
                                        ForEach(Array(outlookSummaryLines.enumerated()), id: \.offset) { _, line in
                                            Text("• \(line)")
                                                .font(.subheadline)
                                                .foregroundColor(.secondary)
                                                .frame(maxWidth: .infinity, alignment: .leading)
                                        }
                                    }
                                }
                            }

                            if let forecastDays = outlook?.forecastDaily, !forecastDays.isEmpty {
                                let displayedForecastDays = showAllForecastDays ? forecastDays : Array(forecastDays.prefix(3))
                                LocalConditionsSurfaceCard(title: "7-Day Space Forecast", icon: "calendar") {
                                    VStack(alignment: .leading, spacing: 12) {
                                        ForEach(displayedForecastDays) { day in
                                            VStack(alignment: .leading, spacing: 8) {
                                                HStack(alignment: .top, spacing: 12) {
                                                    VStack(alignment: .leading, spacing: 3) {
                                                        Text(forecastDayLabel(day.forecastDay))
                                                            .font(.headline)
                                                        Text(day.gScaleMax ?? "Geomagnetic outlook")
                                                            .font(.caption)
                                                            .foregroundColor(.secondary)
                                                    }
                                                    Spacer()
                                                    StatusPill(
                                                        (day.geomagneticSeverityBucket ?? "mild").capitalized,
                                                        severity: severity(day.geomagneticSeverityBucket)
                                                    )
                                                }

                                                ScrollView(.horizontal, showsIndicators: false) {
                                                    HStack(spacing: 10) {
                                                        LocalConditionsValueChip(
                                                            label: "Kp Max",
                                                            value: day.kpMaxForecast.map { String(format: "%.1f", $0) } ?? "—",
                                                            tint: GaugePalette.low
                                                        )
                                                        LocalConditionsValueChip(
                                                            label: "G-Scale",
                                                            value: day.gScaleMax ?? "—",
                                                            tint: GaugePalette.elevated
                                                        )
                                                        LocalConditionsValueChip(
                                                            label: "S1+",
                                                            value: day.s1OrGreaterPct.map { String(format: "%.0f%%", $0) } ?? "—",
                                                            tint: GaugePalette.mild
                                                        )
                                                        LocalConditionsValueChip(
                                                            label: "R1-R2",
                                                            value: day.r1R2Pct.map { String(format: "%.0f%%", $0) } ?? "—",
                                                            tint: GaugePalette.elevated
                                                        )
                                                        LocalConditionsValueChip(
                                                            label: "R3+",
                                                            value: day.r3OrGreaterPct.map { String(format: "%.0f%%", $0) } ?? "—",
                                                            tint: GaugePalette.high
                                                        )
                                                    }
                                                }

                                                let flags = watchFlags(for: day)
                                                if !flags.isEmpty {
                                                    Text(flags.joined(separator: " · "))
                                                        .font(.caption2.weight(.semibold))
                                                        .foregroundColor(.secondary)
                                                }

                                                if let rationale = cleanedOutlookLine(day.geomagneticRationale), !rationale.isEmpty {
                                                    Text(rationale)
                                                        .font(.caption)
                                                        .foregroundColor(.secondary)
                                                }
                                            }
                                            .padding(.bottom, day.id == displayedForecastDays.last?.id ? 0 : 8)

                                            if day.id != displayedForecastDays.last?.id {
                                                Divider().overlay(Color.white.opacity(0.08))
                                            }
                                        }

                                        if !showAllForecastDays || forecastDays.count > 3 {
                                            let hasFullForecastLoaded = forecastDays.count > 3
                                            Button(showAllForecastDays && hasFullForecastLoaded ? "Show fewer days" : "Show full 7-day forecast") {
                                                if showAllForecastDays && hasFullForecastLoaded {
                                                    showAllForecastDays = false
                                                    return
                                                }
                                                Task {
                                                    if !hasFullForecastLoaded {
                                                        await MainActor.run { fullForecastLoading = true }
                                                        await onLoadFullForecast()
                                                        await MainActor.run { fullForecastLoading = false }
                                                    }
                                                    await MainActor.run { showAllForecastDays = true }
                                                }
                                            }
                                            .font(.caption.weight(.semibold))
                                            .foregroundColor(Color(red: 0.46, green: 0.7, blue: 1.0))
                                            .buttonStyle(.plain)
                                            .disabled(fullForecastLoading)
                                        }

                                        if fullForecastLoading {
                                            HStack(spacing: 8) {
                                                ProgressView()
                                                    .scaleEffect(0.82)
                                                Text("Loading the full 7-day forecast")
                                                    .font(.caption)
                                                    .foregroundColor(.secondary)
                                            }
                                        }
                                    }
                                }
                            }
                        } else {
                            forecastLockedCard
                        }
                    }
                    .padding(16)
                    .frame(maxWidth: .infinity, alignment: .leading)
                }
            }
            .navigationTitle("Space Weather")
            .navigationBarTitleDisplayMode(.inline)
            .toolbar {
                ToolbarItem(placement: .topBarTrailing) {
                    Button {
                        Task {
                            await MainActor.run { manualRefreshLoading = true }
                            await onRefresh()
                            await MainActor.run { manualRefreshLoading = false }
                        }
                    } label: {
                        if manualRefreshLoading {
                            ProgressView()
                        } else {
                            Image(systemName: "arrow.clockwise")
                        }
                    }
                }
            }
            .task {
                guard !initialRefreshTriggered else { return }
                initialRefreshTriggered = true
                guard needsInitialRefresh else { return }
                await onRefresh()
            }
        }
    }

    private struct InsightsMagnetosphereView: View {
        let data: MagnetosphereData?
        let isLoading: Bool
        let error: String?
        let onRefresh: () async -> Void

        private func formatValue(_ value: Double?, decimals: Int = 1, suffix: String = "") -> String {
            guard let value else { return "—" }
            let base = String(format: "%.\(decimals)f", value)
            return suffix.isEmpty ? base : "\(base) \(suffix)"
        }

        private func progress(_ value: Double?, max: Double) -> Double {
            guard let value, max > 0 else { return 0.12 }
            return LocalConditionsFormatting.clamped(abs(value) / max)
        }

        private func chartPoints() -> [(Date, Double)] {
            let fmt = ISO8601DateFormatter()
            return (data?.series?.r0 ?? []).compactMap { point in
                guard let t = point.t, let v = point.v, let d = fmt.date(from: t) else { return nil }
                return (d, v)
            }
        }

        var body: some View {
            let kpis = data?.kpis
            let sw = data?.sw

            ZStack {
                Color.black.opacity(0.97).ignoresSafeArea()

                ScrollView {
                    LazyVStack(spacing: 16) {
                        LocalConditionsSurfaceCard(title: "Magnetosphere Summary", icon: "shield.lefthalf.filled") {
                            HStack(alignment: .top, spacing: 12) {
                                VStack(alignment: .leading, spacing: 4) {
                                    Text((kpis?.storminess ?? "Calm").capitalized)
                                        .font(.system(size: 32, weight: .bold, design: .rounded))
                                    Text("GEO risk \((kpis?.geoRisk ?? "Low").capitalized) • GIC feel \((kpis?.dbdt ?? "Low").capitalized)")
                                        .font(.subheadline)
                                        .foregroundColor(.secondary)
                                    if let ts = data?.ts {
                                        Text("Updated \(ts)")
                                            .font(.caption)
                                            .foregroundColor(.secondary)
                                    }
                                }
                                Spacer()
                                if isLoading {
                                    ProgressView()
                                } else {
                                    StatusPill(
                                        (kpis?.storminess ?? "Calm"),
                                        severity: (kpis?.storminess ?? "").lowercased().contains("storm")
                                            ? .alert
                                            : (kpis?.storminess ?? "").lowercased().contains("active")
                                            ? .warn
                                            : .ok
                                    )
                                }
                            }
                            if let cleanError = ContentView.scrubError(error) {
                                Text(cleanError)
                                    .font(.caption)
                                    .foregroundColor(.orange)
                            }
                        }

                        LocalConditionsSurfaceCard(title: "KPIs", icon: "gauge.with.dots.needle.bottom.50percent") {
                            HStack(spacing: 12) {
                                LocalConditionsMetricTile(
                                    title: "R0",
                                    value: formatValue(kpis?.r0Re, suffix: "Re"),
                                    progress: progress(kpis?.r0Re, max: 16),
                                    tint: GaugePalette.low
                                )
                                LocalConditionsMetricTile(
                                    title: "Plasmapause",
                                    value: formatValue(kpis?.lppRe, suffix: "Re"),
                                    progress: progress(kpis?.lppRe, max: 8),
                                    tint: GaugePalette.mild
                                )
                                LocalConditionsMetricTile(
                                    title: "Kp",
                                    value: formatValue(kpis?.kp),
                                    progress: progress(kpis?.kp, max: 9),
                                    tint: GaugePalette.elevated
                                )
                            }
                            HStack(spacing: 10) {
                                LocalConditionsValueChip(label: "Storminess", value: (kpis?.storminess ?? "—").capitalized, tint: GaugePalette.mild)
                                LocalConditionsValueChip(label: "GEO Risk", value: (kpis?.geoRisk ?? "—").capitalized, tint: GaugePalette.elevated)
                                LocalConditionsValueChip(label: "Trend", value: (data?.trend?.r0 ?? "—").capitalized, tint: GaugePalette.low)
                            }
                        }

                        LocalConditionsSurfaceCard(title: "Solar Wind Coupling", icon: "arrow.triangle.2.circlepath") {
                            HStack(spacing: 12) {
                                LocalConditionsMetricTile(
                                    title: "Density",
                                    value: formatValue(sw?.nCm3, suffix: "cm^-3"),
                                    progress: progress(sw?.nCm3, max: 20),
                                    tint: GaugePalette.mild
                                )
                                LocalConditionsMetricTile(
                                    title: "Speed",
                                    value: formatValue(sw?.vKms, decimals: 0, suffix: "km/s"),
                                    progress: progress(sw?.vKms, max: 800),
                                    tint: GaugePalette.elevated
                                )
                                LocalConditionsMetricTile(
                                    title: "Bz",
                                    value: formatValue(sw?.bzNt, suffix: "nT"),
                                    progress: progress(sw?.bzNt, max: 20),
                                    tint: GaugePalette.zoneColor((sw?.bzNt ?? 0) <= -5 ? "elevated" : "low")
                                )
                            }
                        }

                        if !chartPoints().isEmpty {
                            LocalConditionsSurfaceCard(title: "Shield Edge Trend", icon: "chart.xyaxis.line") {
                                Chart(chartPoints(), id: \.0) { point in
                                    LineMark(
                                        x: .value("Time", point.0),
                                        y: .value("R0", point.1)
                                    )
                                    .interpolationMethod(.catmullRom)
                                    .foregroundStyle(GaugePalette.low)
                                }
                                .frame(height: 200)
                            }
                        }

                        LocalConditionsSurfaceCard(title: "How to Read This", icon: "text.book.closed.fill") {
                            Text("R0 tracks the magnetopause boundary, while the coupling metrics summarize how solar wind pressure and Bz may be loading the system. Higher Kp, stronger southward Bz, and tighter shield-edge values usually mean more active geospace conditions.")
                                .font(.subheadline)
                                .foregroundColor(.secondary)
                        }
                    }
                    .padding(16)
                    .frame(maxWidth: .infinity, alignment: .leading)
                }
                .refreshable {
                    await onRefresh()
                }
            }
            .navigationTitle("Magnetosphere")
            .navigationBarTitleDisplayMode(.inline)
        }
    }

    private struct InsightsHealthStatsCard: View {
        let current: FeaturesToday?
        let updatedText: String?
        let tempUnit: TemperatureUnit
        let trackedStatKeys: [TrackedStatKey]
        let smartStatSwapEnabled: Bool
        let onEditTrackedStats: () -> Void

        private struct HighlightStat: Identifiable, Hashable {
            let id: TrackedStatKey
            let title: String
            let value: String
            let detail: String
            let progress: Double
            let tint: Color
            let salience: Double
        }

        private struct HighlightTile: View {
            let stat: HighlightStat

            var body: some View {
                VStack(alignment: .leading, spacing: 8) {
                    Text(stat.title)
                        .font(.caption.weight(.semibold))
                        .foregroundColor(.secondary)
                    Text(stat.value)
                        .font(.title3.weight(.semibold))
                        .lineLimit(1)
                        .minimumScaleFactor(0.82)
                    Text(stat.detail)
                        .font(.caption)
                        .foregroundColor(.secondary)
                        .lineLimit(1)
                    LocalConditionsBar(progress: stat.progress, tint: stat.tint)
                }
                .frame(maxWidth: .infinity, alignment: .leading)
                .padding(12)
                .background(Color.black.opacity(0.20))
                .clipShape(RoundedRectangle(cornerRadius: 14, style: .continuous))
                .overlay(
                    RoundedRectangle(cornerRadius: 14, style: .continuous)
                        .stroke(stat.tint.opacity(0.22), lineWidth: 1)
                )
            }
        }

        private struct SupportingStat: Identifiable, Hashable {
            let id: TrackedStatKey
            let label: String
            let value: String
            let tint: Color
        }

        private func signedValue(_ value: Double?, suffix: String, decimals: Int = 1) -> String {
            guard let value else { return "—" }
            return String(format: "%+.\(decimals)f%@", value, suffix)
        }

        private func plainValue(_ value: Double?, suffix: String, decimals: Int = 1) -> String {
            guard let value else { return "—" }
            return String(format: "%.\(decimals)f%@", value, suffix)
        }

        private func deltaDetail(
            _ value: Double?,
            positive: String = "above usual",
            negative: String = "below usual",
            neutral: String = "near usual",
            threshold: Double = 0.15
        ) -> String {
            guard let value else { return "No baseline yet" }
            if value > threshold { return positive }
            if value < -threshold { return negative }
            return neutral
        }

        private func deltaProgress(_ value: Double?, maxAbs: Double) -> Double {
            guard let value, maxAbs > 0 else { return 0.16 }
            return LocalConditionsFormatting.clamped(abs(value) / maxAbs)
        }

        private func absoluteProgress(_ value: Double?, max: Double) -> Double {
            guard let value, max > 0 else { return 0.16 }
            return LocalConditionsFormatting.clamped(value / max)
        }

        private var heartRateRangeText: String? {
            guard let min = current?.hrMin?.value, let max = current?.hrMax?.value else { return nil }
            return "\(Int(min.rounded()))-\(Int(max.rounded())) bpm"
        }

        private var bloodPressureText: String? {
            guard let sys = current?.bpSysAvg?.value, let dia = current?.bpDiaAvg?.value else { return nil }
            return "\(Int(sys.rounded()))/\(Int(dia.rounded()))"
        }

        private var allStatCandidates: [HighlightStat] {
            guard let current else { return [] }
            var items: [HighlightStat] = []

            if let delta = current.restingHrBaselineDelta?.value {
                items.append(
                    HighlightStat(
                        id: .restingHr,
                        title: "Resting HR Δ",
                        value: signedValue(delta, suffix: " bpm"),
                        detail: deltaDetail(delta),
                        progress: deltaProgress(delta, maxAbs: 8),
                        tint: GaugePalette.mild,
                        salience: deltaProgress(delta, maxAbs: 8)
                    )
                )
            } else if let resting = current.restingHrAvg?.value {
                items.append(
                    HighlightStat(
                        id: .restingHr,
                        title: "Resting HR",
                        value: "\(Int(resting.rounded())) bpm",
                        detail: "daily average",
                        progress: absoluteProgress(resting, max: 90),
                        tint: GaugePalette.mild,
                        salience: 0.16
                    )
                )
            }

            if let delta = current.respiratoryRateBaselineDelta?.value {
                items.append(
                    HighlightStat(
                        id: .respiratory,
                        title: "Respiratory Δ",
                        value: signedValue(delta, suffix: " br/min"),
                        detail: deltaDetail(delta, threshold: 0.2),
                        progress: deltaProgress(delta, maxAbs: 3),
                        tint: GaugePalette.low,
                        salience: deltaProgress(delta, maxAbs: 3)
                    )
                )
            } else if let rate = current.respiratoryRateSleepAvg?.value ?? current.respiratoryRateAvg?.value {
                items.append(
                    HighlightStat(
                        id: .respiratory,
                        title: "Respiratory",
                        value: plainValue(rate, suffix: " br/min"),
                        detail: current.respiratoryRateSleepAvg?.value != nil ? "sleep average" : "daily average",
                        progress: absoluteProgress(rate, max: 20),
                        tint: GaugePalette.low,
                        salience: 0.16
                    )
                )
            }

            if let rawDelta = current.temperatureDeviationBaselineDelta?.value ?? current.temperatureDeviation?.value {
                let converted = LocalConditionsFormatting.convertTempDelta(rawDelta, unit: tempUnit)
                items.append(
                    HighlightStat(
                        id: .temperature,
                        title: "Temp Δ",
                        value: LocalConditionsFormatting.formatTemperatureDelta(rawDelta, unit: tempUnit),
                        detail: deltaDetail(converted, threshold: tempUnit == .fahrenheit ? 0.35 : 0.2),
                        progress: deltaProgress(converted, maxAbs: tempUnit == .fahrenheit ? 3.0 : 1.7),
                        tint: GaugePalette.elevated,
                        salience: deltaProgress(converted, maxAbs: tempUnit == .fahrenheit ? 3.0 : 1.7)
                    )
                )
            }

            if let hrv = current.hrvAvg?.value {
                items.append(
                    HighlightStat(
                        id: .hrv,
                        title: "HRV",
                        value: "\(Int(hrv.rounded()))",
                        detail: "daily average",
                        progress: absoluteProgress(hrv, max: 70),
                        tint: GaugePalette.low,
                        salience: 0.12
                    )
                )
            }

            if let spo2 = current.spo2AvgDisplay {
                items.append(
                    HighlightStat(
                        id: .spo2,
                        title: "SpO₂",
                        value: String(format: "%.0f%%", spo2),
                        detail: "daily average",
                        progress: LocalConditionsFormatting.clamped((spo2 - 90.0) / 10.0),
                        tint: GaugePalette.mild,
                        salience: LocalConditionsFormatting.clamped((96.0 - spo2) / 4.0)
                    )
                )
            }

            if let steps = current.stepsTotal?.value {
                items.append(
                    HighlightStat(
                        id: .steps,
                        title: "Steps",
                        value: "\(Int(steps.rounded()))",
                        detail: "today so far",
                        progress: absoluteProgress(steps, max: 10000),
                        tint: GaugePalette.low,
                        salience: 0.08
                    )
                )
            }

            if let heartRateRangeText {
                items.append(
                    HighlightStat(
                        id: .heartRange,
                        title: "Heart range",
                        value: heartRateRangeText,
                        detail: "today",
                        progress: 0.2,
                        tint: GaugePalette.low,
                        salience: 0.06
                    )
                )
            }

            if let bloodPressureText {
                items.append(
                    HighlightStat(
                        id: .bloodPressure,
                        title: "Blood pressure",
                        value: bloodPressureText,
                        detail: "average",
                        progress: 0.2,
                        tint: GaugePalette.mild,
                        salience: 0.06
                    )
                )
            }

            return items
        }

        private var preferredKeyOrder: [TrackedStatKey] {
            var order: [TrackedStatKey] = []
            for key in trackedStatKeys where !order.contains(key) {
                order.append(key)
            }
            for key in TrackedStatKey.defaultSelection where !order.contains(key) {
                order.append(key)
            }
            for key in TrackedStatKey.allCases where !order.contains(key) {
                order.append(key)
            }
            return order
        }

        private var highlightStats: [HighlightStat] {
            let candidatesByKey = Dictionary(uniqueKeysWithValues: allStatCandidates.map { ($0.id, $0) })
            let availableOrder = preferredKeyOrder.filter { candidatesByKey[$0] != nil }
            guard !availableOrder.isEmpty else { return [] }

            var selectedKeys = Array(availableOrder.prefix(4))
            let fifthPinned = availableOrder.dropFirst(4).first

            if smartStatSwapEnabled,
               let dynamic = allStatCandidates
                .filter({ !selectedKeys.contains($0.id) && $0.salience >= 0.55 })
                .sorted(by: { lhs, rhs in
                    if lhs.salience == rhs.salience {
                        return preferredKeyOrder.firstIndex(of: lhs.id) ?? .max < preferredKeyOrder.firstIndex(of: rhs.id) ?? .max
                    }
                    return lhs.salience > rhs.salience
                })
                .first
            {
                selectedKeys.append(dynamic.id)
            } else if let fifthPinned {
                selectedKeys.append(fifthPinned)
            }

            for key in availableOrder where !selectedKeys.contains(key) {
                guard selectedKeys.count < min(TrackedStatKey.maxPinnedCount, availableOrder.count) else { break }
                selectedKeys.append(key)
            }

            return selectedKeys.compactMap { candidatesByKey[$0] }
        }

        private var supportingStats: [SupportingStat] {
            guard let current else { return [] }
            let usedIDs = Set(highlightStats.map(\.id))
            var items: [SupportingStat] = []

            if !usedIDs.contains(.steps), let steps = current.stepsTotal?.value {
                items.append(SupportingStat(id: .steps, label: "Steps", value: "\(Int(steps.rounded()))", tint: GaugePalette.low))
            }
            if !usedIDs.contains(.hrv), let hrv = current.hrvAvg?.value {
                items.append(SupportingStat(id: .hrv, label: "HRV", value: "\(Int(hrv.rounded()))", tint: GaugePalette.low))
            }
            if !usedIDs.contains(.spo2), let spo2 = current.spo2AvgDisplay {
                items.append(SupportingStat(id: .spo2, label: "SpO₂", value: String(format: "%.0f%%", spo2), tint: GaugePalette.mild))
            }
            if !usedIDs.contains(.heartRange), let heartRateRangeText {
                items.append(SupportingStat(id: .heartRange, label: "Heart range", value: heartRateRangeText, tint: GaugePalette.low))
            }
            if !usedIDs.contains(.bloodPressure), let bloodPressureText {
                items.append(SupportingStat(id: .bloodPressure, label: "Blood pressure", value: bloodPressureText, tint: GaugePalette.mild))
            }
            if !usedIDs.contains(.respiratory), let rate = current.respiratoryRateSleepAvg?.value ?? current.respiratoryRateAvg?.value {
                items.append(SupportingStat(id: .respiratory, label: "Respiratory", value: plainValue(rate, suffix: " br/min"), tint: GaugePalette.low))
            }
            if !usedIDs.contains(.restingHr), let resting = current.restingHrAvg?.value {
                items.append(SupportingStat(id: .restingHr, label: "Resting HR", value: "\(Int(resting.rounded())) bpm", tint: GaugePalette.mild))
            }
            if !usedIDs.contains(.temperature),
               let rawDelta = current.temperatureDeviationBaselineDelta?.value ?? current.temperatureDeviation?.value {
                items.append(
                    SupportingStat(
                        id: .temperature,
                        label: "Temp Δ",
                        value: LocalConditionsFormatting.formatTemperatureDelta(rawDelta, unit: tempUnit),
                        tint: GaugePalette.elevated
                    )
                )
            }

            return items
        }

        private var supportingRows: [[SupportingStat]] {
            stride(from: 0, to: supportingStats.count, by: 3).map { start in
                let end = min(start + 3, supportingStats.count)
                return Array(supportingStats[start..<end])
            }
        }

        private var highlightRows: [[HighlightStat]] {
            stride(from: 0, to: highlightStats.count, by: 3).map { start in
                let end = min(start + 3, highlightStats.count)
                return Array(highlightStats[start..<end])
            }
        }

        var body: some View {
            LocalConditionsSurfaceCard(title: "Health Stats", icon: "heart.fill") {
                VStack(alignment: .leading, spacing: 12) {
                    if highlightStats.isEmpty && supportingStats.isEmpty {
                        Text("Health stats are still syncing for today.")
                            .font(.subheadline)
                            .foregroundColor(.secondary)
                    } else if !highlightStats.isEmpty {
                        ForEach(highlightRows.indices, id: \.self) { index in
                            HStack(spacing: 10) {
                                ForEach(highlightRows[index]) { stat in
                                    HighlightTile(stat: stat)
                                }
                            }
                        }
                    }

                    ForEach(supportingRows.indices, id: \.self) { index in
                        HStack(spacing: 10) {
                            ForEach(supportingRows[index]) { stat in
                                LocalConditionsValueChip(label: stat.label, value: stat.value, tint: stat.tint)
                            }
                        }
                    }

                    if let updatedText {
                        Text("Updated \(updatedText)")
                            .font(.caption)
                            .foregroundColor(.secondary)
                    }

                    Button(action: onEditTrackedStats) {
                        Text("Edit tracked stats")
                            .font(.caption.weight(.semibold))
                            .foregroundColor(.accentColor)
                    }
                    .buttonStyle(.plain)
                }
            }
        }
    }

    private struct InsightsCameraCheckCard: View {
        let summary: CameraHealthDailySummary?
        let isLoading: Bool
        let errorText: String?
        let onOpenQuickCheck: () -> Void

        private func statusColor(_ summary: CameraHealthDailySummary?) -> Color {
            switch summary?.summaryStatus ?? .pending {
            case .good:
                return GaugePalette.low
            case .partial:
                return GaugePalette.mild
            case .poor:
                return GaugePalette.elevated
            case .pending:
                return .secondary
            }
        }

        private func statusLabel(_ summary: CameraHealthDailySummary?) -> String {
            (summary?.summaryStatus ?? .pending).rawValue.capitalized
        }

        private func statusSeverity(_ summary: CameraHealthDailySummary?) -> StatusPill.Severity {
            switch summary?.summaryStatus ?? .pending {
            case .good:
                return .ok
            case .partial:
                return .warn
            case .poor:
                return .alert
            case .pending:
                return .warn
            }
        }

        private func qualityLabel(_ quality: String?) -> String {
            let token = (quality ?? "unknown").trimmingCharacters(in: .whitespacesAndNewlines)
            if token.isEmpty { return "Unknown" }
            return token.capitalized
        }

        private func saveScopeText(_ summary: CameraHealthDailySummary) -> String {
            switch summary.persistedSaveScope {
            case .account:
                return "Saved to your account"
            case .localOnly:
                return "Saved locally only"
            case .notSaved:
                return "Not saved"
            }
        }

        private func summaryText(_ summary: CameraHealthDailySummary) -> String {
            switch summary.summaryStatus {
            case .good:
                return "Heart rate and HRV were captured."
            case .partial:
                if summary.hrvMetricStatus == .notRequested {
                    return "Heart rate was captured. HRV was not requested in Quick HR mode."
                }
                return "Heart rate was captured. HRV is not shown because signal quality was too low."
            case .poor:
                return "No reliable reading captured. Try lighter pressure and keep still."
            case .pending:
                return "No quick check recorded yet today."
            }
        }

        private func metricChips(_ summary: CameraHealthDailySummary) -> some View {
            HStack(spacing: 10) {
                if summary.hasUsableHR {
                    LocalConditionsValueChip(
                        label: "BPM",
                        value: summary.bpm.map { "\(Int($0.rounded()))" } ?? "--",
                        tint: statusColor(summary)
                    )
                }
                if summary.hasUsableHRV {
                    LocalConditionsValueChip(
                        label: "RMSSD",
                        value: summary.rmssdMs.map { "\(Int($0.rounded())) ms" } ?? "--",
                        tint: GaugePalette.low
                    )
                }
                LocalConditionsValueChip(
                    label: "Time",
                    value: timeText(summary.latestTsUtc),
                    tint: GaugePalette.mild
                )
            }
        }

        private func timeText(_ raw: String?) -> String {
            guard let raw, let date = ISO8601DateFormatter().date(from: raw) else { return "—" }
            let out = DateFormatter()
            out.dateStyle = .none
            out.timeStyle = .short
            return out.string(from: date)
        }

        var body: some View {
            LocalConditionsSurfaceCard(title: "Quick Health Check", icon: "camera.metering.center.weighted") {
                VStack(alignment: .leading, spacing: 12) {
                    HStack(alignment: .top, spacing: 12) {
                        VStack(alignment: .leading, spacing: 4) {
                            Text(statusLabel(summary))
                                .font(.title3.weight(.semibold))
                            Text("Camera-based wellness estimate only. Not medical advice.")
                                .font(.caption)
                                .foregroundColor(.secondary)
                        }
                        Spacer()
                        StatusPill(statusLabel(summary), severity: statusSeverity(summary))
                    }

                    if isLoading {
                        ProgressView("Loading latest check...")
                            .font(.caption)
                    } else if let errorText, !errorText.isEmpty, summary == nil {
                        Text(errorText)
                            .font(.caption)
                            .foregroundColor(.secondary)
                    } else if let summary {
                        VStack(alignment: .leading, spacing: 10) {
                            metricChips(summary)
                            Text(summaryText(summary))
                                .font(.caption)
                                .foregroundColor(.secondary)
                            Text("\(saveScopeText(summary)) | Quality \(qualityLabel(summary.qualityLabel))")
                                .font(.caption)
                                .foregroundColor(.secondary)
                        }
                    } else {
                        Text("No quick check recorded yet today.")
                            .font(.caption)
                            .foregroundColor(.secondary)
                    }

                    Button(action: onOpenQuickCheck) {
                        Label("Open Quick Health Check", systemImage: "camera.fill")
                            .frame(maxWidth: .infinity)
                    }
                    .buttonStyle(.borderedProminent)
                }
            }
        }
    }

    private struct TrackedStatsSettingsSection: View {
        @Binding var trackedStatKeys: [TrackedStatKey]
        @Binding var smartStatSwapEnabled: Bool

        private func toggle(_ key: TrackedStatKey) {
            var updated = trackedStatKeys
            if updated.contains(key) {
                updated.removeAll { $0 == key }
            } else if updated.count < TrackedStatKey.maxPinnedCount {
                updated.append(key)
            }
            trackedStatKeys = updated.isEmpty ? TrackedStatKey.defaultSelection : updated
        }

        var body: some View {
            VStack(alignment: .leading, spacing: 10) {
                Text("Tracked body stats")
                    .font(.subheadline.weight(.semibold))
                Text("Choose up to five default body stats. When smart swap is on, Gaia can rotate a more relevant stat into the last slot when something stands out.")
                    .font(.caption)
                    .foregroundColor(.secondary)

                LazyVGrid(columns: [GridItem(.flexible()), GridItem(.flexible())], spacing: 10) {
                    ForEach(TrackedStatKey.allCases) { key in
                        let isSelected = trackedStatKeys.contains(key)
                        Button {
                            toggle(key)
                        } label: {
                            VStack(alignment: .leading, spacing: 4) {
                                HStack(spacing: 6) {
                                    Image(systemName: isSelected ? "checkmark.circle.fill" : "circle")
                                        .foregroundColor(isSelected ? .accentColor : .secondary)
                                    Text(key.title)
                                        .font(.subheadline.weight(.semibold))
                                        .foregroundColor(.primary)
                                }
                                Text(key.subtitle)
                                    .font(.caption2)
                                    .foregroundColor(.secondary)
                                    .fixedSize(horizontal: false, vertical: true)
                            }
                            .frame(maxWidth: .infinity, alignment: .leading)
                            .padding(12)
                            .background(Color.black.opacity(0.16))
                            .clipShape(RoundedRectangle(cornerRadius: 14, style: .continuous))
                            .overlay(
                                RoundedRectangle(cornerRadius: 14, style: .continuous)
                                    .stroke(isSelected ? Color.accentColor.opacity(0.44) : Color.white.opacity(0.08), lineWidth: 1)
                            )
                        }
                        .buttonStyle(.plain)
                        .disabled(!isSelected && trackedStatKeys.count >= TrackedStatKey.maxPinnedCount)
                    }
                }

                Toggle("Smartly swap the last slot when another stat matters more", isOn: $smartStatSwapEnabled)
            }
        }
    }

    private struct FavoriteSymptomsSettingsSection: View {
        let presets: [SymptomPreset]
        @Binding var favoriteSymptomCodes: [String]

        private var availablePresets: [SymptomPreset] {
            presets
                .filter { normalize($0.code) != SymptomCodeHelper.fallbackCode }
                .sorted { lhs, rhs in
                    let lhsFavorite = normalizedFavoriteCodes.contains(normalize(lhs.code))
                    let rhsFavorite = normalizedFavoriteCodes.contains(normalize(rhs.code))
                    if lhsFavorite != rhsFavorite {
                        return lhsFavorite && !rhsFavorite
                    }
                    return lhs.label.localizedCaseInsensitiveCompare(rhs.label) == .orderedAscending
                }
        }

        private var normalizedFavoriteCodes: [String] {
            var normalized: [String] = []
            for code in favoriteSymptomCodes {
                let token = normalize(code)
                if token.isEmpty || normalized.contains(token) {
                    continue
                }
                normalized.append(token)
            }
            return normalized
        }

        private var selectedLabelsSummary: String? {
            let selected = availablePresets
                .filter { normalizedFavoriteCodes.contains(normalize($0.code)) }
                .map(\.label)
            guard !selected.isEmpty else { return nil }
            return selected.prefix(3).joined(separator: ", ") + (selected.count > 3 ? " +" + String(selected.count - 3) : "")
        }

        private func toggle(_ preset: SymptomPreset) {
            let normalizedCode = normalize(preset.code)
            var updated = normalizedFavoriteCodes
            if updated.contains(normalizedCode) {
                updated.removeAll { $0 == normalizedCode }
            } else if updated.count < FavoriteSymptomPreference.maxCount {
                updated.append(normalizedCode)
            }
            favoriteSymptomCodes = updated
        }

        var body: some View {
            VStack(alignment: .leading, spacing: 10) {
                Text("Favorite symptoms")
                    .font(.subheadline.weight(.semibold))
                Text("Choose up to \(FavoriteSymptomPreference.maxCount) symptoms you log often. Gaia shows these first in the app and website symptom pickers.")
                    .font(.caption)
                    .foregroundColor(.secondary)
                if let selectedLabelsSummary, !selectedLabelsSummary.isEmpty {
                    Text("Saved favorites: \(selectedLabelsSummary)")
                        .font(.caption.weight(.semibold))
                        .foregroundColor(.white.opacity(0.82))
                }

                LazyVGrid(columns: [GridItem(.flexible()), GridItem(.flexible())], spacing: 10) {
                    ForEach(availablePresets, id: \.id) { preset in
                        let isSelected = normalizedFavoriteCodes.contains(normalize(preset.code))
                        Button {
                            toggle(preset)
                        } label: {
                            HStack(spacing: 8) {
                                Image(systemName: isSelected ? "star.fill" : "star")
                                    .foregroundColor(isSelected ? GaugePalette.elevated : .secondary)
                                Text(preset.label)
                                    .font(.subheadline.weight(.semibold))
                                    .foregroundColor(.primary)
                                    .multilineTextAlignment(.leading)
                                Spacer(minLength: 0)
                            }
                            .frame(maxWidth: .infinity, alignment: .leading)
                            .padding(12)
                            .background(Color.black.opacity(0.16))
                            .clipShape(RoundedRectangle(cornerRadius: 14, style: .continuous))
                            .overlay(
                                RoundedRectangle(cornerRadius: 14, style: .continuous)
                                    .stroke(isSelected ? GaugePalette.elevated.opacity(0.44) : Color.white.opacity(0.08), lineWidth: 1)
                            )
                        }
                        .buttonStyle(.plain)
                        .disabled(!isSelected && normalizedFavoriteCodes.count >= FavoriteSymptomPreference.maxCount)
                    }
                }
            }
        }
    }

    private struct NotificationTimeZoneSettingsSection: View {
        @Binding var timeZone: String

        private var selectedTimeZone: String {
            let trimmed = timeZone.trimmingCharacters(in: .whitespacesAndNewlines)
            return trimmed.isEmpty ? TimeZone.current.identifier : trimmed
        }

        private var availableTimeZones: [String] {
            var ordered: [String] = []
            let preferred = [
                selectedTimeZone,
                TimeZone.current.identifier,
                "America/Chicago",
                "America/New_York",
                "America/Denver",
                "America/Los_Angeles",
                "UTC",
            ]
            for identifier in preferred where !identifier.isEmpty && !ordered.contains(identifier) {
                ordered.append(identifier)
            }
            for identifier in TimeZone.knownTimeZoneIdentifiers.sorted() where !ordered.contains(identifier) {
                ordered.append(identifier)
            }
            return ordered
        }

        private func displayName(for identifier: String) -> String {
            let normalized = identifier.replacingOccurrences(of: "_", with: " ")
            if identifier == TimeZone.current.identifier {
                return "\(normalized) (device)"
            }
            return normalized
        }

        var body: some View {
            VStack(alignment: .leading, spacing: 10) {
                Text("Time zone")
                    .font(.subheadline.weight(.semibold))
                Text("Used for daily windows, check-in timing, reminders, and the member day boundary.")
                    .font(.caption)
                    .foregroundColor(.secondary)

                Picker("Time zone", selection: $timeZone) {
                    ForEach(availableTimeZones, id: \.self) { identifier in
                        Text(displayName(for: identifier)).tag(identifier)
                    }
                }
                .pickerStyle(.menu)

                Button("Use device time zone (\(TimeZone.current.identifier))") {
                    timeZone = TimeZone.current.identifier
                }
                .buttonStyle(.borderless)
                .font(.caption.weight(.semibold))
            }
        }
    }

    private struct InsightsHealthSymptomsView: View {
        let current: FeaturesToday?
        let todayString: String
        let updatedText: String?
        let tempUnit: TemperatureUnit
        let trackedStatKeys: [TrackedStatKey]
        let smartStatSwapEnabled: Bool
        let bannerText: String?
        let usingYesterdayFallback: Bool
        let todayCount: Int
        let queuedCount: Int
        let sparklinePoints: [SymptomSparkPoint]
        let topSummary: String?
        let diagnostics: [SymptomDiagSummary]
        let currentSymptomsSnapshot: CurrentSymptomsSnapshot?
        let lunarInsights: LunarInsightPayload?
        let lunarInsightsLoading: Bool
        let lunarInsightsError: String?
        let experienceMode: ExperienceMode
        let lunarSensitivityDeclared: Bool
        let latestCameraCheck: CameraHealthDailySummary?
        let latestCameraCheckLoading: Bool
        let latestCameraCheckError: String?
        let dailyCheckInStatus: DailyCheckInStatus?
        let dailyCheckInLoading: Bool
        let dailyCheckInError: String?
        let onOpenDailyCheckIn: () -> Void
        let onEditTrackedStats: () -> Void
        @Binding var showSymptomSheet: Bool
        let onOpenQuickCheck: () -> Void
        let onLoadLunarInsights: () async -> Void

        private var topDiagnostics: [SymptomDiagSummary] {
            diagnostics.sorted { $0.events > $1.events }
        }

        private var lunarInsightMessage: String? {
            switch experienceMode {
            case .scientific:
                return lunarInsights?.messageScientific
            case .mystical:
                return lunarInsights?.messageMystical
            }
        }

        private var shouldShowLunarCard: Bool {
            if lunarInsightsLoading {
                return true
            }
            if lunarSensitivityDeclared {
                return true
            }
            guard let lunarInsights else { return false }
            if lunarInsights.insufficientData == false,
               let strength = lunarInsights.patternStrength,
               strength.lowercased() != "none" {
                return true
            }
            return false
        }

        private var currentSymptomsCount: Int {
            currentSymptomsSnapshot?.summary.activeCount ?? 0
        }

        private var currentSymptomsHeadline: String {
            currentSymptomsCount > 0 ? "\(currentSymptomsCount) active right now" : "No symptoms active right now"
        }

        private var currentSymptomsLabels: String? {
            guard currentSymptomsCount > 0 else { return nil }
            return currentSymptomsSnapshot?.semanticActiveLabelSummary
        }

        private var currentSymptomsDetail: String {
            if currentSymptomsCount > 0 {
                return currentSymptomsSnapshot?.semanticActiveSummary ?? "Open the live view for notes, updates, and follow-ups."
            }
            return currentSymptomsSnapshot?.semanticFollowUpSummary ?? currentSymptomsSnapshot?.semanticEmptyStateSummary ?? "Open the live view for notes, updates, and follow-ups."
        }

        private var dailyCheckInHeadline: String {
            if let error = ContentView.scrubError(dailyCheckInError), dailyCheckInStatus == nil {
                return error
            }
            if dailyCheckInLoading && dailyCheckInStatus == nil {
                return "Refreshing today’s check-in"
            }
            if let targetDay = dailyCheckInStatus?.targetDay,
               let entry = dailyCheckInStatus?.latestEntry,
               let completedAt = entry.completedAt,
               !completedAt.isEmpty,
               entry.day == targetDay {
                return "Completed for today"
            }
            if dailyCheckInStatus?.prompt != nil {
                return "Ready for today’s check-in"
            }
            return "Check in with the day"
        }

        private var dailyCheckInDetail: String {
            if ContentView.scrubError(dailyCheckInError) != nil, dailyCheckInStatus == nil {
                return "Try again in a moment."
            }
            if dailyCheckInLoading && dailyCheckInStatus == nil {
                return "Pulling the latest prompt and status."
            }
            if let targetDay = dailyCheckInStatus?.targetDay,
               let entry = dailyCheckInStatus?.latestEntry,
               let completedAt = entry.completedAt,
               !completedAt.isEmpty,
               entry.day == targetDay {
                return "Open to revise the read or review the last response."
            }
            if let prompt = dailyCheckInStatus?.prompt,
               !prompt.questionText.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty {
                return prompt.questionText
            }
            return "A short check-in helps keep this page grounded in how the day actually felt."
        }

        private var dailyCheckInExposureLine: String? {
            guard let targetDay = dailyCheckInStatus?.targetDay,
                  let entry = dailyCheckInStatus?.latestEntry,
                  let completedAt = entry.completedAt,
                  !completedAt.isEmpty,
                  entry.day == targetDay else {
                return nil
            }
            return entry.summaryExposureText.map { "Also logged: \($0)" }
        }

        private var dailyCheckInPill: (String, StatusPill.Severity)? {
            if let targetDay = dailyCheckInStatus?.targetDay,
               let entry = dailyCheckInStatus?.latestEntry,
               let completedAt = entry.completedAt,
               !completedAt.isEmpty,
               entry.day == targetDay {
                return ("Done", .ok)
            }
            if dailyCheckInStatus?.prompt != nil {
                return ("Ready", .warn)
            }
            return nil
        }

        private var lunarStrengthPill: (String, StatusPill.Severity)? {
            guard let strength = lunarInsights?.patternStrength?.trimmingCharacters(in: .whitespacesAndNewlines),
                  !strength.isEmpty,
                  strength.lowercased() != "none" else {
                return nil
            }
            return (strength.capitalized, .warn)
        }

        var body: some View {
            ZStack {
                Color.black.opacity(0.97).ignoresSafeArea()

                ScrollView {
                    LazyVStack(spacing: 16) {
                        Button {
                            showSymptomSheet = true
                        } label: {
                            Label("Log symptom", systemImage: "plus.circle.fill")
                                .font(.subheadline.weight(.semibold))
                                .frame(maxWidth: .infinity)
                        }
                        .buttonStyle(.borderedProminent)
                        .controlSize(.large)

                        NavigationLink(value: InsightsRoute.currentSymptoms) {
                            LocalConditionsSurfaceCard(title: "Current Symptoms", icon: "waveform.path.ecg.rectangle") {
                                HStack(alignment: .top, spacing: 12) {
                                    VStack(alignment: .leading, spacing: 6) {
                                        Text(currentSymptomsHeadline)
                                            .font(.subheadline.weight(.semibold))
                                            .foregroundColor(.primary)
                                        if let currentSymptomsLabels, !currentSymptomsLabels.isEmpty {
                                            Text(currentSymptomsLabels)
                                                .font(.caption.weight(.semibold))
                                                .foregroundColor(.white.opacity(0.82))
                                                .fixedSize(horizontal: false, vertical: true)
                                        }
                                        Text(currentSymptomsDetail)
                                            .font(.caption)
                                            .foregroundColor(.secondary)
                                            .fixedSize(horizontal: false, vertical: true)
                                    }
                                    Spacer(minLength: 8)
                                    if currentSymptomsCount > 0 {
                                        StatusPill("\(currentSymptomsCount) Active", severity: currentSymptomsCount >= 3 ? .warn : .ok)
                                    }
                                }
                            }
                        }
                        .buttonStyle(.plain)

                        if let current {
                            SleepCard(
                                title: current.day == todayString ? "Sleep (Today)" : "Sleep (\(current.day))",
                                totalMin: Int((current.sleepTotalMinutes?.value ?? 0).rounded()),
                                remMin: Int((current.remM?.value ?? 0).rounded()),
                                coreMin: Int((current.coreM?.value ?? 0).rounded()),
                                deepMin: Int((current.deepM?.value ?? 0).rounded()),
                                awakeMin: Int((current.awakeM?.value ?? 0).rounded()),
                                inbedMin: Int((current.inbedM?.value ?? 0).rounded()),
                                efficiency: current.sleepEfficiency?.value
                            )
                        }

                        if let bannerText, !bannerText.isEmpty {
                            LocalConditionsSurfaceCard(title: "Sleep Sync", icon: "clock.arrow.circlepath") {
                                Text(bannerText)
                                    .font(.subheadline)
                                    .foregroundColor(.secondary)
                            }
                        }

                        if usingYesterdayFallback {
                            LocalConditionsSurfaceCard(title: "Feature Lag", icon: "calendar.badge.clock") {
                                Text("Today’s health view is still filling in, so some cards are using yesterday’s summary.")
                                    .font(.subheadline)
                                    .foregroundColor(.secondary)
                            }
                        }

                        InsightsHealthStatsCard(
                            current: current,
                            updatedText: updatedText,
                            tempUnit: tempUnit,
                            trackedStatKeys: trackedStatKeys,
                            smartStatSwapEnabled: smartStatSwapEnabled,
                            onEditTrackedStats: onEditTrackedStats
                        )

                        Button(action: onOpenDailyCheckIn) {
                            LocalConditionsSurfaceCard(title: "Daily Check-In", icon: "checklist") {
                                HStack(alignment: .top, spacing: 12) {
                                    VStack(alignment: .leading, spacing: 6) {
                                        Text(dailyCheckInHeadline)
                                            .font(.subheadline.weight(.semibold))
                                            .foregroundColor(.primary)
                                        if let dailyCheckInExposureLine, !dailyCheckInExposureLine.isEmpty {
                                            Text(dailyCheckInExposureLine)
                                                .font(.caption.weight(.semibold))
                                                .foregroundColor(.white.opacity(0.82))
                                                .fixedSize(horizontal: false, vertical: true)
                                        }
                                        Text(dailyCheckInDetail)
                                            .font(.caption)
                                            .foregroundColor(.secondary)
                                            .fixedSize(horizontal: false, vertical: true)
                                    }
                                    Spacer(minLength: 8)
                                    if let dailyCheckInPill {
                                        StatusPill(dailyCheckInPill.0, severity: dailyCheckInPill.1)
                                    }
                                }
                            }
                        }
                        .buttonStyle(.plain)

                        if shouldShowLunarCard {
                            LocalConditionsSurfaceCard(title: "Lunar Pattern Watch", icon: "moon.stars.fill") {
                                VStack(alignment: .leading, spacing: 10) {
                                    HStack(alignment: .top, spacing: 12) {
                                        VStack(alignment: .leading, spacing: 4) {
                                            if let message = lunarInsightMessage, !message.isEmpty {
                                                Text(CopyRefiner.refine(message) ?? message)
                                                    .font(.subheadline.weight(.semibold))
                                                    .foregroundColor(.primary)
                                                    .fixedSize(horizontal: false, vertical: true)
                                            } else if lunarInsightsLoading {
                                                Text("Checking lunar windows in your history.")
                                                    .font(.subheadline.weight(.semibold))
                                                    .foregroundColor(.primary)
                                            } else {
                                                Text("No clear lunar signal yet")
                                                    .font(.subheadline.weight(.semibold))
                                                    .foregroundColor(.primary)
                                            }
                                        }
                                        Spacer(minLength: 8)
                                        if let lunarStrengthPill {
                                            StatusPill(lunarStrengthPill.0, severity: lunarStrengthPill.1)
                                        }
                                    }

                                    if lunarInsightsLoading {
                                        ProgressView("Checking lunar windows…")
                                            .font(.caption)
                                    } else {
                                        if let highlightWindow = lunarInsights?.highlightWindow,
                                           let highlightMetric = lunarInsights?.highlightMetric,
                                           let strength = lunarInsights?.patternStrength,
                                           !highlightWindow.isEmpty,
                                           !highlightMetric.isEmpty,
                                           strength.lowercased() != "none" {
                                            Text("\(highlightWindow.capitalized) moon • \(highlightMetric.replacingOccurrences(of: "_", with: " ")) • \(strength.capitalized)")
                                                .font(.caption)
                                                .foregroundColor(.secondary)
                                        } else if lunarInsights?.insufficientData == true {
                                            Text("No lunar pattern yet. More nights are needed before this can be compared with your baseline.")
                                                .font(.caption)
                                                .foregroundColor(.secondary)
                                        }

                                        if let error = lunarInsightsError, lunarInsights == nil {
                                            Text(error)
                                                .font(.caption)
                                                .foregroundColor(.secondary)
                                        }
                                    }
                                }
                            }
                        }

                        if !topDiagnostics.isEmpty {
                            LocalConditionsSurfaceCard(title: "Top Symptoms", icon: "waveform.path.ecg") {
                                VStack(spacing: 10) {
                                    ForEach(Array(topDiagnostics.prefix(3).enumerated()), id: \.offset) { _, item in
                                        HStack(spacing: 10) {
                                            Text(item.symptomCode.replacingOccurrences(of: "_", with: " ").capitalized)
                                                .font(.subheadline.weight(.semibold))
                                            Spacer()
                                            LocalConditionsValueChip(
                                                label: "Events",
                                                value: "\(item.events)",
                                                tint: GaugePalette.mild
                                            )
                                        }
                                    }
                                }
                            }
                        }

                        if ContentView.cameraHealthCheckVisible {
                            InsightsCameraCheckCard(
                                summary: latestCameraCheck,
                                isLoading: latestCameraCheckLoading,
                                errorText: latestCameraCheckError,
                                onOpenQuickCheck: onOpenQuickCheck
                            )
                        }
                    }
                    .padding(16)
                    .frame(maxWidth: .infinity, alignment: .leading)
                }
            }
            .navigationTitle("Body")
            .navigationBarTitleDisplayMode(.inline)
            .task {
                if lunarInsights == nil {
                    await onLoadLunarInsights()
                }
            }
        }
    }

    private struct InsightsHazardsView: View {
        let payload: HazardsBriefResponse?
        let isLoading: Bool
        let error: String?

        private var items: [HazardItem] {
            payload?.items ?? []
        }

        private func severityTint(_ value: String?) -> Color {
            let token = (value ?? "").lowercased()
            if token.contains("red") { return GaugePalette.high }
            if token.contains("orange") { return GaugePalette.elevated }
            if token.contains("yellow") { return GaugePalette.mild }
            return GaugePalette.low
        }

        var body: some View {
            ZStack {
                Color.black.opacity(0.97).ignoresSafeArea()

                ScrollView {
                    LazyVStack(spacing: 16) {
                        HazardsBriefCard(payload: payload, isLoading: isLoading, error: error)

                        if items.isEmpty, !isLoading {
                            LocalConditionsSurfaceCard(title: "Hazard Feed", icon: "globe.americas.fill") {
                                Text("No active hazard items are available right now.")
                                    .font(.subheadline)
                                    .foregroundColor(.secondary)
                            }
                        } else if !items.isEmpty {
                            LocalConditionsSurfaceCard(title: "Latest Items", icon: "list.bullet.rectangle") {
                                VStack(spacing: 10) {
                                    ForEach(Array(items.prefix(12).enumerated()), id: \.offset) { _, item in
                                        VStack(alignment: .leading, spacing: 6) {
                                            HStack(spacing: 10) {
                                                Text(item.title ?? item.kind ?? "Hazard")
                                                    .font(.subheadline.weight(.semibold))
                                                Spacer()
                                                LocalConditionsValueChip(
                                                    label: "Severity",
                                                    value: item.severity?.capitalized ?? "Info",
                                                    tint: severityTint(item.severity)
                                                )
                                            }
                                            Text([item.location, item.source, item.startedAt].compactMap { $0 }.joined(separator: " • "))
                                                .font(.caption)
                                                .foregroundColor(.secondary)
                                        }
                                        .frame(maxWidth: .infinity, alignment: .leading)
                                    }
                                }
                            }
                        }
                    }
                    .padding(16)
                    .frame(maxWidth: .infinity, alignment: .leading)
                }
            }
            .navigationTitle("Hazards")
            .navigationBarTitleDisplayMode(.inline)
        }
    }

    private struct DashboardToolsSectionView: View {
        @ObservedObject var state: AppState
        let seriesForCharts: SpaceSeries
        let symptomHighlights: [SymptomHighlight]
        @Binding var showTrends: Bool
        let hazardsBrief: HazardsBriefResponse?
        let hazardsLoading: Bool
        let hazardsError: String?
        @Binding var showHazards: Bool
        let quakeLatest: QuakeDaily?
        let quakeEvents: [QuakeEvent]
        let quakeError: String?
        @Binding var showQuakes: Bool
        let auroraPowerValue: Double?
        let auroraWingKp: Double?
        let auroraProbabilityText: String?
        @Binding var showAuroraForecast: Bool
        let magnetosphere: MagnetosphereData?
        let magnetosphereLoading: Bool
        let magnetosphereError: String?
        @Binding var showMagnetosphereDetail: Bool
        @Binding var localHealthZip: String
        let localHealth: LocalCheckResponse?
        let localHealthLoading: Bool
        let localHealthError: String?
        let onRefreshLocalHealth: () -> Void
        @Binding var profileUseGPS: Bool
        @Binding var profileLocalInsightsEnabled: Bool
        let profileLocationMessage: String?
        let profileLocationSaving: Bool
        let onSaveProfileLocation: () -> Void
        let tagCatalog: [TagCatalogItem]
        @Binding var selectedTagKeys: Set<String>
        let tagSaveMessage: String?
        let tagsSaving: Bool
        let onSaveTags: () -> Void
        let showDebug: Bool
        @Binding var showTools: Bool
        @Binding var showConnections: Bool
        @Binding var showActions: Bool
        @Binding var showBle: Bool
        @Binding var showPolar: Bool
        let onFetchVisuals: () -> Void
        @Binding var showMagnetosphere: Bool

        private enum SensitivitySection: String {
            case environmental = "Sensitivities"
            case health = "Health Context"
        }

        private func sectionForTag(_ item: TagCatalogItem) -> SensitivitySection {
            let key = canonicalProfileTagKey(item.tagKey)
            if healthContextTagKeys.contains(key) {
                return .health
            }
            let section = (item.section ?? "").lowercased()
            if section.contains("health") || section.contains("context") {
                return .health
            }
            return .environmental
        }

        private func tags(in section: SensitivitySection) -> [TagCatalogItem] {
            tagCatalog
                .filter { sectionForTag($0) == section }
                .sorted { (lhs, rhs) in
                    (lhs.label ?? lhs.tagKey).localizedCaseInsensitiveCompare(rhs.label ?? rhs.tagKey) == .orderedAscending
                }
        }

        private func toggleBinding(for key: String) -> Binding<Bool> {
            let canonicalKey = canonicalProfileTagKey(key)
            return Binding(
                get: { selectedTagKeys.contains(canonicalKey) },
                set: { isOn in
                    if isOn { selectedTagKeys.insert(canonicalKey) } else { selectedTagKeys.remove(canonicalKey) }
                }
            )
        }

        @ViewBuilder
        private func tagToggle(_ item: TagCatalogItem) -> some View {
            let key = canonicalProfileTagKey(item.tagKey)
            Toggle(isOn: toggleBinding(for: key)) {
                VStack(alignment: .leading, spacing: 2) {
                    Text(item.label ?? key)
                    if let desc = item.description, !desc.isEmpty {
                        Text(desc).font(.caption2).foregroundColor(.secondary)
                    }
                }
            }
        }

        var body: some View {
            VStack(spacing: 16) {
                LocalHealthCard(
                    zip: $localHealthZip,
                    snapshot: localHealth,
                    isLoading: localHealthLoading,
                    error: localHealthError,
                    onRefresh: onRefreshLocalHealth
                )
                .padding(.horizontal)

                GroupBox {
                    VStack(alignment: .leading, spacing: 10) {
                        Text("Enable local insights")
                            .font(.subheadline)
                        TextField("ZIP code", text: $localHealthZip)
                            .textFieldStyle(.roundedBorder)
                            .keyboardType(.numberPad)
                        Toggle("Use GPS (optional)", isOn: $profileUseGPS)
                        Toggle("Enable local insights", isOn: $profileLocalInsightsEnabled)
                        Button(action: onSaveProfileLocation) {
                            HStack {
                                if profileLocationSaving {
                                    ProgressView().scaleEffect(0.8)
                                }
                                Text(profileLocationSaving ? "Saving..." : "Save Location")
                            }
                            .frame(maxWidth: .infinity)
                        }
                        .buttonStyle(.borderedProminent)
                        .disabled(profileLocationSaving)
                        if let msg = profileLocationMessage {
                            Text(msg)
                                .font(.caption)
                                .foregroundColor(.secondary)
                        }
                    }
                } label: {
                    Label("Location Settings", systemImage: "location.fill")
                }
                .padding(.horizontal)

                GroupBox {
                    VStack(alignment: .leading, spacing: 10) {
                        if tagCatalog.isEmpty {
                            Text("No personalization tags available yet.")
                                .font(.caption)
                                .foregroundColor(.secondary)
                        } else {
                            let environmentalTags = tags(in: .environmental)
                            if !environmentalTags.isEmpty {
                                Text(SensitivitySection.environmental.rawValue)
                                    .font(.subheadline.weight(.semibold))
                                ForEach(environmentalTags) { item in
                                    tagToggle(item)
                                }
                            }

                            let healthTags = tags(in: .health)
                            if !healthTags.isEmpty {
                                Divider()
                                Text(SensitivitySection.health.rawValue + " (Optional)")
                                    .font(.subheadline.weight(.semibold))
                                ForEach(healthTags) { item in
                                    tagToggle(item)
                                }
                                Text("Self-reported health context only. Not for diagnosis.")
                                    .font(.caption2)
                                    .foregroundColor(.secondary)
                            }
                        }
                        Button(action: onSaveTags) {
                            HStack {
                                if tagsSaving {
                                    ProgressView().scaleEffect(0.8)
                                }
                                Text(tagsSaving ? "Saving..." : "Save Personalization")
                            }
                            .frame(maxWidth: .infinity)
                        }
                        .buttonStyle(.borderedProminent)
                        .disabled(tagsSaving)
                        if let msg = tagSaveMessage {
                            Text(msg)
                                .font(.caption)
                                .foregroundColor(.secondary)
                        }
                    }
                } label: {
                    Label("Personalization", systemImage: "slider.horizontal.3")
                }
                .padding(.horizontal)

                DisclosureGroup(isExpanded: $showTrends) {
                    SpaceChartsCard(series: seriesForCharts, highlights: symptomHighlights)
                        .padding(.top, 6)
                } label: {
                    HStack {
                        Image(systemName: "chart.line.uptrend.xyaxis")
                        Text("Weekly Trends (Kp, Bz, f0, HR)")
                        Spacer()
                    }
                }
                .padding(.horizontal)

                DisclosureGroup(isExpanded: $showHazards) {
                    HazardsBriefCard(payload: hazardsBrief, isLoading: hazardsLoading, error: hazardsError)
                        .padding(.top, 6)
                } label: {
                    HStack {
                        Image(systemName: "exclamationmark.triangle.fill")
                        Text("Global Hazards Brief")
                        Spacer()
                    }
                }
                .padding(.horizontal)

                DisclosureGroup(isExpanded: $showQuakes) {
                    EarthquakesSummaryCard(
                        latest: quakeLatest,
                        events: quakeEvents,
                        error: quakeError
                    )
                    .padding(.top, 6)
                } label: {
                    HStack {
                        Image(systemName: "waveform.path")
                        Text("Earthquakes")
                        Spacer()
                    }
                }
                .padding(.horizontal)

                DisclosureGroup(isExpanded: $showAuroraForecast) {
                    AuroraThumbsSectionView(
                        auroraPowerValue: auroraPowerValue,
                        auroraWingKp: auroraWingKp,
                        auroraProbabilityText: auroraProbabilityText
                    )
                    .padding(.top, 6)
                } label: {
                    HStack {
                        Image(systemName: "sparkles")
                        Text("Aurora Forecast")
                        Spacer()
                    }
                }
                .padding(.horizontal)

                DisclosureGroup(isExpanded: $showMagnetosphere) {
                    MagnetosphereCard(
                        data: magnetosphere,
                        isLoading: magnetosphereLoading,
                        error: magnetosphereError,
                        onOpenDetail: { showMagnetosphereDetail = true }
                    )
                    .padding(.top, 6)
                    .sheet(isPresented: $showMagnetosphereDetail) {
                        MagnetosphereDetailView(data: magnetosphere)
                    }
                } label: {
                    HStack {
                        Image(systemName: "shield.fill")
                        Text("Magnetosphere")
                        Spacer()
                    }
                }
                .padding(.horizontal)

                if showDebug {
                    DisclosureGroup(isExpanded: $showTools) {
                        VStack(spacing: 12) {
                            ConnectionSettingsSection(state: state, isExpanded: $showConnections)
                            NavigationLink(destination: SubscribeView()) {
                                Label("Account & Membership", systemImage: "creditcard")
                                    .frame(maxWidth: .infinity)
                            }
                            .buttonStyle(.bordered)
                            .controlSize(.small)
                            DisclosureGroup(isExpanded: $showActions) {
                                ActionsSection(state: state, onFetchVisuals: onFetchVisuals)
                            } label: { HStack { Image(systemName: "wrench.and.screwdriver"); Text("Developer Actions"); Spacer() } }
                            DisclosureGroup(isExpanded: $showBle) {
                                BleStatusSection(state: state)
                            } label: { HStack { Image(systemName: "antenna.radiowaves.left.and.right"); Text("Bluetooth / BLE"); Spacer() } }
                            DisclosureGroup(isExpanded: $showPolar) {
                                PolarStatusSection(state: state)
                            } label: { HStack { Image(systemName: "waveform.path.ecg"); Text("Polar ECG"); Spacer() } }
                        }
                        .padding(.top, 8)
                    } label: { HStack { Image(systemName: "slider.horizontal.3"); Text("Advanced"); Spacer() } }
                        .padding(.horizontal)
                }
            }
        }
    }

    @ViewBuilder
    private var dashboardEmptyView: some View {
        GroupBox {
            Text("No features for today yet. Pull to refresh after the rollup, or try again in a minute.")
                .font(.footnote)
                .foregroundColor(.secondary)
                .frame(maxWidth: .infinity, alignment: .leading)
        } label: { Text("Status") }
            .padding(.horizontal)
        if showDebug {
            DisclosureGroup(isExpanded: $showTools) {
                VStack(spacing: 12) {
                    ConnectionSettingsSection(state: state, isExpanded: $showConnections)
