                                Label("Public Support Page", systemImage: "paperplane")
                                    .frame(maxWidth: .infinity)
                            }
                            .buttonStyle(.bordered)
                        }
                        if let privacyURL = helpCenterPrivacyURL {
                            Button {
                                openURL(privacyURL)
                            } label: {
                                Label("Privacy Policy", systemImage: "lock.shield")
                                    .frame(maxWidth: .infinity)
                            }
                            .buttonStyle(.bordered)
                        }
                        if let termsURL = helpCenterTermsURL {
                            Button {
                                openURL(termsURL)
                            } label: {
                                Label("Terms of Use", systemImage: "doc.text")
                                    .frame(maxWidth: .infinity)
                            }
                            .buttonStyle(.bordered)
                        }
                    }
                }
                }
            }
        } label: {
            Label("Help & Support", systemImage: "questionmark.circle")
        }
        .padding(.horizontal)
    }

    private var missionSettingsAccountSection: some View {
        GroupBox {
            missionSettingsDisclosure(
                title: "Account, membership, and data",
                summary: "Plan, Health data, billing, delete controls",
                isExpanded: $showAccountSettingsSection
            ) {
                VStack(alignment: .leading, spacing: 12) {
                Text("Signed-in state, current plan, billing, and account deletion live here.")
                    .font(.subheadline)
                    .foregroundColor(.secondary)

                if let email = auth.signedInEmail {
                    Text("Signed in as \(email)")
                        .font(.caption)
                        .foregroundColor(.secondary)
                } else if auth.hasAppOnlyProfile {
                    Text("Using a free app profile on this device. Add an email in Account & Membership when you want website access.")
                        .font(.caption)
                        .foregroundColor(.secondary)
                }

                NavigationLink(destination: SubscribeView(guideProfile: currentGuideProfile, helpContext: helpCenterContext)) {
                    Label("Open Account & Membership", systemImage: "creditcard")
                        .frame(maxWidth: .infinity)
                }
                .buttonStyle(.borderedProminent)

                missionSettingsHealthDataSection

                Divider()

                VStack(alignment: .leading, spacing: 8) {
                    Text("Safe delete preflight")
                        .font(.subheadline.weight(.semibold))
                    Text("Checks whether account deletion is fully wired and shows what would be removed, without deleting anything.")
                        .font(.caption)
                        .foregroundColor(.secondary)

                    Button {
                        Task { await runDeleteAccountPreflight() }
                    } label: {
                        HStack {
                            if accountDeletionPreflightInFlight {
                                ProgressView()
                                    .scaleEffect(0.8)
                            }
                            Text(accountDeletionPreflightInFlight ? "Checking..." : "Run Safe Preflight")
                                .frame(maxWidth: .infinity)
                        }
                    }
                    .buttonStyle(.bordered)
                    .disabled(accountDeletionPreflightInFlight || accountDeletionInFlight)

                    if let accountDeletionPreflightMessage, !accountDeletionPreflightMessage.isEmpty {
                        Text(accountDeletionPreflightMessage)
                            .font(.caption)
                            .foregroundColor(
                                accountDeletionPreflightMessage.lowercased().contains("ready.")
                                ? .secondary
                                : .orange
                            )
                    }
                }

                Divider()

                VStack(alignment: .leading, spacing: 8) {
                    Text("Delete account")
                        .font(.subheadline.weight(.semibold))
                    Text("Permanently deletes your Gaia Eyes account and associated app data. App Store subscriptions are managed separately in Apple Subscriptions.")
                        .font(.caption)
                        .foregroundColor(.secondary)

                    Button(role: .destructive) {
                        showDeleteAccountConfirmation = true
                    } label: {
                        HStack {
                            if accountDeletionInFlight {
                                ProgressView()
                                    .scaleEffect(0.8)
                            }
                            Text(accountDeletionInFlight ? "Deleting..." : "Delete Account")
                                .frame(maxWidth: .infinity)
                        }
                    }
                    .buttonStyle(.bordered)
                    .tint(.red)
                    .disabled(accountDeletionInFlight)

                    if let accountDeletionMessage, !accountDeletionMessage.isEmpty {
                        Text(accountDeletionMessage)
                            .font(.caption)
                            .foregroundColor(
                                accountDeletionMessage.lowercased().contains("could not")
                                || accountDeletionMessage.lowercased().contains("sign in")
                                ? .orange
                                : .secondary
                            )
                    }
                }
                }
            }
        } label: {
            Label("Account & Membership", systemImage: "person.crop.circle")
        }
        .padding(.horizontal)
    }

