                                        billing: debugBillingSnapshot,
                                        profile: debugProfileSnapshot,
                                        featureInputs: debugFeatureInputSnapshot,
                                        selectedCacheTarget: $debugSelectedCacheTarget,
                                        isBillingLoading: debugEntitlementsLoading,
