    private struct AppNoticeBannerView: View {
        let notice: AppNotice
        let onDismiss: () -> Void
        let onOpen: (URL) -> Void

        private var tint: Color {
            switch notice.type?.lowercased() {
            case "update":
                return .blue
            case "warning":
                return .orange
            default:
                return .teal
            }
        }

        var body: some View {
            HStack(alignment: .top, spacing: 10) {
                Image(systemName: notice.type?.lowercased() == "update" ? "arrow.down.app.fill" : "info.circle.fill")
                    .foregroundColor(tint)
                    .font(.headline)
                    .padding(.top, 2)

                VStack(alignment: .leading, spacing: 5) {
                    if let title = notice.trimmedTitle {
                        Text(title)
                            .font(.subheadline.weight(.semibold))
                    }
                    if let message = notice.trimmedMessage {
                        Text(message)
                            .font(.caption)
                            .foregroundColor(.secondary)
                            .fixedSize(horizontal: false, vertical: true)
                    }
                    if let link = notice.link {
                        Button {
                            onOpen(link)
                        } label: {
                            Text(notice.trimmedLinkLabel ?? "Open")
                                .font(.caption.weight(.semibold))
                        }
                        .buttonStyle(.bordered)
                        .controlSize(.small)
                        .tint(tint)
                    }
                }

                Spacer(minLength: 8)

                Button(action: onDismiss) {
                    Image(systemName: "xmark")
                        .font(.caption.weight(.bold))
                        .foregroundColor(.secondary)
                        .padding(8)
                        .contentShape(Rectangle())
                }
                .buttonStyle(.plain)
                .accessibilityLabel("Dismiss notice")
            }
            .padding(12)
            .background(.ultraThinMaterial, in: RoundedRectangle(cornerRadius: 16, style: .continuous))
            .overlay(
                RoundedRectangle(cornerRadius: 16, style: .continuous)
                    .stroke(tint.opacity(0.35), lineWidth: 1)
            )
            .shadow(color: Color.black.opacity(0.18), radius: 12, x: 0, y: 6)
        }
    }

