                        }
                        .buttonStyle(.borderedProminent)
                        .controlSize(.regular)
                    }

                    HStack(spacing: 10) {
                        LocalConditionsValueChip(
                            label: "Today",
                            value: "\(todayCount)",
                            tint: todayCount > 0 ? GaugePalette.mild : GaugePalette.low
                        )
                        if activeCount > 0 {
                            LocalConditionsValueChip(
                                label: "Active",
                                value: "\(activeCount)",
                                tint: activeCount >= 3 ? GaugePalette.elevated : GaugePalette.low
                            )
                        }
                        if queuedCount > 0 {
