                    }
                    Text("Tap Earthscope on the dashboard for the full journal and quake context.")
                        .font(.caption2)
                        .foregroundColor(.secondary)
                        .padding(.top, 6)
                }
                .padding()
                .frame(maxWidth: .infinity, alignment: .leading)
            }
            .navigationTitle("Earthquakes")
            .navigationBarTitleDisplayMode(.inline)
        }
    }

    private enum LocalConditionsFormatting {
        static func formatNumber(_ value: Double?, decimals: Int = 1) -> String {
            guard let value else { return "—" }
            return String(format: "%.\(decimals)f", value)
        }

        static func convertTemp(_ valueC: Double?, unit: TemperatureUnit) -> Double? {
            guard let valueC else { return nil }
            if unit == .fahrenheit {
                return (valueC * 9.0 / 5.0) + 32.0
            }
            return valueC
        }

        static func convertTempDelta(_ valueC: Double?, unit: TemperatureUnit) -> Double? {
            guard let valueC else { return nil }
            if unit == .fahrenheit {
                return valueC * 9.0 / 5.0
            }
            return valueC
        }

        static func formatTemperature(_ celsius: Double?, unit: TemperatureUnit, decimals: Int = 1) -> String {
            guard let converted = convertTemp(celsius, unit: unit) else { return "—" }
            return "\(String(format: "%.\(decimals)f", converted)) \(unit.symbol)"
        }

        static func formatTemperatureDelta(_ celsius: Double?, unit: TemperatureUnit, decimals: Int = 1) -> String {
            guard let converted = convertTempDelta(celsius, unit: unit) else { return "—" }
            return "\(String(format: "%+.\(decimals)f", converted)) \(unit.symbol)"
        }

        static func formatTempMetric(_ celsius: Double?) -> String {
            formatTemperature(celsius, unit: .celsius)
        }

        static func formatTempImperial(_ celsius: Double?) -> String {
            formatTemperature(celsius, unit: .fahrenheit)
        }

        static func formatTempDelta(_ celsius: Double?, unit: TemperatureUnit = .celsius) -> String {
            formatTemperatureDelta(celsius, unit: unit)
        }

        static func formatPressure(_ hpa: Double?) -> String {
            guard let hpa else { return "—" }
            let inHg = hpa * 0.02953
            return "\(String(format: "%.1f", hpa)) hPa (\(String(format: "%.2f", inHg)) inHg)"
        }

        static func formatPressureShort(_ hpa: Double?) -> String {
            guard let hpa else { return "—" }
            return "\(String(format: "%.1f", hpa)) hPa"
        }

        static func formatPressureImperial(_ hpa: Double?) -> String {
            guard let hpa else { return "—" }
            return "\(String(format: "%.2f", hpa * 0.02953)) inHg"
        }

        static func formatPressureDelta(_ hpa: Double?) -> String {
            guard let hpa else { return "—" }
            return "\(String(format: "%+.1f", hpa)) hPa"
        }

        static func formatPercent(_ value: Double?) -> String {
            guard let value else { return "—" }
            return "\(String(format: "%.0f", value)) %"
        }

        static func formatAllergenState(_ raw: String?, fallbackLabel: String? = nil) -> String {
            if let fallbackLabel, !fallbackLabel.isEmpty {
                switch fallbackLabel.trimmingCharacters(in: .whitespacesAndNewlines).lowercased() {
                case "quiet", "calm", "low":
                    return "Low"
                case "moderate", "elevated":
                    return "Elevated"
                case "high", "very high", "very_high":
                    return "High"
                default:
                    return fallbackLabel
                }
            }
            switch (raw ?? "").trimmingCharacters(in: .whitespacesAndNewlines).lowercased() {
            case "very_high", "high":
                return "High"
            case "moderate":
                return "Elevated"
            case "low":
                return "Low"
            default:
                return "—"
            }
        }

        static func formatAllergenType(_ raw: String?) -> String {
            switch (raw ?? "").trimmingCharacters(in: .whitespacesAndNewlines).lowercased() {
            case "tree":
                return "Tree pollen"
            case "grass":
                return "Grass pollen"
            case "weed":
                return "Weed pollen"
            case "mold":
                return "Mold"
            default:
                return "—"
            }
        }

        static func normalizedTrend(_ raw: String?) -> String? {
            guard let raw, !raw.isEmpty else { return nil }
            switch raw.lowercased() {
            case "rising": return "rising"
            case "falling": return "falling"
            case "steady": return "steady"
            default: return raw.lowercased()
            }
        }

        static func derivedPressureTrend(raw: String?, deltaHpa: Double?) -> String? {
            let normalized = normalizedTrend(raw)
            guard let deltaHpa else { return normalized }
            if abs(deltaHpa) < 1 {
                return normalized ?? "steady"
            }
            if normalized == nil || normalized == "steady" {
                return deltaHpa > 0 ? "rising" : "falling"
            }
            if normalized == "rising", deltaHpa < 0 {
                return "falling"
            }
            if normalized == "falling", deltaHpa > 0 {
                return "rising"
            }
            return normalized
        }

        static func formatTrend(_ raw: String?) -> String {
            normalizedTrend(raw)?.capitalized ?? "—"
        }

        static func asofText(_ iso: String?) -> String? {
            guard let iso else { return nil }
            let formatter = ISO8601DateFormatter()
            if let date = formatter.date(from: iso) {
                return DateFormatter.localizedString(from: date, dateStyle: .medium, timeStyle: .short)
            }
            return nil
        }

        static func illuminationFraction(_ value: Double?) -> Double {
            guard let value else { return 0 }
            if value > 1 { return clamped(value / 100.0) }
            return clamped(value)
        }

        static func illuminationText(_ value: Double?) -> String {
            guard let value else { return "—" }
            let percent = value > 1 ? value : value * 100.0
            return "\(String(format: "%.0f", percent)) %"
        }

        static func clamped(_ value: Double) -> Double {
            min(max(value, 0), 1)
        }
    }

    private enum LocalConditionsStyle {
        static func severityKey(_ raw: String?) -> String {
            switch (raw ?? "").trimmingCharacters(in: .whitespacesAndNewlines).lowercased() {
            case "high", "very_high", "alert":
                return "high"
            case "watch", "elevated":
                return "elevated"
            case "mild", "moderate":
                return "mild"
            default:
                return "low"
            }
        }

        static func progress(_ raw: String?) -> Double {
            switch severityKey(raw) {
            case "high":
                return 0.95
            case "elevated":
                return 0.72
            case "mild":
                return 0.45
            default:
                return 0.20
            }
        }

        static func pillSeverity(_ raw: String?) -> StatusPill.Severity {
            switch severityKey(raw) {
            case "high":
                return .alert
            case "elevated", "mild":
                return .warn
            default:
                return .ok
            }
        }
    }

