    private struct LocalConditionsSummaryCard<Destination: View>: View {
        @Binding var zip: String
        let snapshot: LocalCheckResponse?
        let isLoading: Bool
        let error: String?
        let useGPS: Bool
        let localInsightsEnabled: Bool
        let destination: () -> Destination

        private var locationStatus: String {
            let resolvedZip = (snapshot?.whereInfo?.zip ?? zip).trimmingCharacters(in: .whitespacesAndNewlines)
            if useGPS {
                return resolvedZip.isEmpty ? "Using GPS for your area" : "Using GPS for your area • ZIP \(resolvedZip)"
            }
            return resolvedZip.isEmpty ? "Add a ZIP code to improve local conditions" : "ZIP \(resolvedZip)"
        }

        private var lastUpdated: String {
            LocalConditionsFormatting.asofText(snapshot?.asof) ?? "—"
        }

        var body: some View {
            GroupBox {
                VStack(alignment: .leading, spacing: 10) {
                    HStack(spacing: 8) {
                        Text("Local Conditions")
                            .font(.headline)
                        Spacer()
                        if isLoading { ProgressView().scaleEffect(0.8) }
                    }
                    HStack(spacing: 8) {
                        StatusPill(localInsightsEnabled ? "Ready" : "Off", severity: localInsightsEnabled ? .ok : .warn)
                        Text(locationStatus)
                            .font(.caption)
                            .foregroundColor(.secondary)
                    }
                    Text("Last updated \(lastUpdated)")
                        .font(.caption2)
                        .foregroundColor(.secondary)
                    if let error, !error.isEmpty {
                        Text(error)
                            .font(.caption)
                            .foregroundColor(.orange)
                    }
                    NavigationLink {
                        destination()
                    } label: {
                        HStack {
                            Text("Open Local Conditions")
                            Spacer()
                            Image(systemName: "chevron.right")
                        }
                        .frame(maxWidth: .infinity)
                    }
                    .buttonStyle(.borderedProminent)
                    .controlSize(.small)
                }
                .frame(maxWidth: .infinity, alignment: .leading)
            } label: {
                Label("Local Conditions", systemImage: "location.fill")
            }
        }
    }

