    private struct LocalConditionsView: View {
        let zip: String
        let snapshot: LocalCheckResponse?
        let drivers: [DashboardDriverItem]
        let mode: ExperienceMode
        let tone: ToneStyle
        let tempUnit: TemperatureUnit
        let isLoading: Bool
        let error: String?
        let useGPS: Bool
        let onRefresh: () -> Void
        @State private var showAllForecastDays: Bool = false
        @State private var shareDraft: ShareDraft? = nil

        init(
            zip: String,
            snapshot: LocalCheckResponse?,
            drivers: [DashboardDriverItem],
            mode: ExperienceMode = .scientific,
            tone: ToneStyle = .balanced,
            tempUnit: TemperatureUnit,
            isLoading: Bool,
            error: String?,
            useGPS: Bool,
            onRefresh: @escaping () -> Void
        ) {
            self.zip = zip
            self.snapshot = snapshot
            self.drivers = drivers
            self.mode = mode
            self.tone = tone
            self.tempUnit = tempUnit
            self.isLoading = isLoading
            self.error = error
            self.useGPS = useGPS
            self.onRefresh = onRefresh
        }

        private func driver(for key: String) -> DashboardDriverItem? {
            drivers.first { $0.key.trimmingCharacters(in: .whitespacesAndNewlines).lowercased() == key.lowercased() }
        }

        private func effectiveAQIValue(air: LocalAir?) -> Double? {
            air?.aqi ?? driver(for: "aqi")?.value
        }

        private func formattedDriverValue(_ driver: DashboardDriverItem) -> String? {
            guard let value = driver.value else { return nil }
            let unit = (driver.unit ?? "").trimmingCharacters(in: .whitespacesAndNewlines)
            switch driver.key.lowercased() {
            case "aqi", "sw":
                return unit.isEmpty ? String(Int(round(value))) : "\(String(Int(round(value)))) \(unit)"
            case "temp":
                return LocalConditionsFormatting.formatTemperatureDelta(value, unit: tempUnit)
            case "pressure", "bz":
                return unit.isEmpty ? String(format: "%+.1f", value) : "\(String(format: "%+.1f", value)) \(unit)"
            case "schumann":
                return unit.isEmpty ? String(format: "%.2f", value) : "\(String(format: "%.2f", value)) \(unit)"
            default:
                return unit.isEmpty ? String(format: "%.1f", value) : "\(String(format: "%.1f", value)) \(unit)"
            }
        }

        private func driverStatus(
            for key: String,
            fallbackLabel: String,
            fallbackState: String,
            fallbackSeverity: String,
            fallbackDetail: String?
        ) -> LocalConditionsDriverStatus {
            if let driver = driver(for: key) {
                let severityKey = LocalConditionsStyle.severityKey(driver.severity)
                return LocalConditionsDriverStatus(
                    label: driver.label ?? fallbackLabel,
                    state: driver.state ?? fallbackState,
                    severityKey: severityKey,
                    progress: LocalConditionsStyle.progress(severityKey),
                    detail: formattedDriverValue(driver) ?? fallbackDetail
                )
            }
            let severityKey = LocalConditionsStyle.severityKey(fallbackSeverity)
            return LocalConditionsDriverStatus(
                label: fallbackLabel,
                state: fallbackState,
                severityKey: severityKey,
                progress: LocalConditionsStyle.progress(severityKey),
                detail: fallbackDetail
            )
        }

        private func pressureStatus(weather: LocalWeather?) -> LocalConditionsDriverStatus {
            let delta = abs(weather?.baroDelta24hHpa ?? 0)
            let trend = LocalConditionsFormatting.derivedPressureTrend(
                raw: weather?.pressureTrend ?? weather?.baroTrend,
                deltaHpa: weather?.baroDelta24hHpa
            )
            let pressure = weather?.pressureHpa
            let state: String
            let severity: String
            if delta >= 12 {
                state = "Swing"
                severity = "high"
            } else if delta >= 8 {
                state = "Swing"
                severity = "elevated"
            } else if delta >= 6 {
                state = "Swing"
                severity = "mild"
            } else if trend == "rising" {
                state = "Rising"
                severity = "low"
            } else if trend == "falling" {
                state = "Falling"
                severity = "low"
            } else if let pressure, pressure <= 1008 {
                state = "Low"
                severity = "mild"
            } else if let pressure, pressure >= 1025 {
                state = "Elevated"
                severity = "mild"
            } else {
                state = "Steady"
                severity = "low"
            }
            return driverStatus(
                for: "pressure",
                fallbackLabel: "Pressure Swing",
                fallbackState: state,
                fallbackSeverity: severity,
                fallbackDetail: LocalConditionsFormatting.formatPressureDelta(weather?.baroDelta24hHpa)
            )
        }

        private func temperatureStatus(weather: LocalWeather?) -> LocalConditionsDriverStatus {
            let delta = abs(weather?.tempDelta24hC ?? 0)
            let severity: String
            if delta >= 12 {
                severity = "high"
            } else if delta >= 8 {
                severity = "elevated"
            } else if delta >= 6 {
                severity = "mild"
            } else {
                severity = "low"
            }
            let state = delta >= 6 ? "Swing" : "Steady"
            return driverStatus(
                for: "temp",
                fallbackLabel: "Temperature Swing",
                fallbackState: state,
                fallbackSeverity: severity,
                fallbackDetail: LocalConditionsFormatting.formatTemperatureDelta(weather?.tempDelta24hC, unit: tempUnit)
            )
        }

        private func airQualityStatus(air: LocalAir?) -> LocalConditionsDriverStatus {
            let aqi = effectiveAQIValue(air: air)
            let severity: String
            if let aqi, aqi >= 151 {
                severity = "high"
            } else if let aqi, aqi >= 101 {
                severity = "elevated"
            } else if let aqi, aqi >= 51 {
                severity = "mild"
            } else {
                severity = "low"
            }
            let trimmedCategory = air?.category?.trimmingCharacters(in: .whitespacesAndNewlines)
            let state: String
            if let trimmedCategory, !trimmedCategory.isEmpty {
                state = trimmedCategory
            } else {
                state = severity == "high" ? "Unhealthy" : severity == "elevated" ? "USG" : severity == "mild" ? "Moderate" : "Good"
            }
            return driverStatus(
                for: "aqi",
                fallbackLabel: "Air Quality",
                fallbackState: state,
                fallbackSeverity: severity,
                fallbackDetail: LocalConditionsFormatting.formatNumber(aqi, decimals: 0)
            )
        }

        private func allergenStatus(allergens: LocalAllergens?) -> LocalConditionsDriverStatus {
            let rawState = allergens?.overallLevel ?? allergens?.state
            let severity: String
            switch (rawState ?? "").trimmingCharacters(in: .whitespacesAndNewlines).lowercased() {
            case "very_high", "high":
                severity = "high"
            case "moderate":
                severity = "elevated"
            default:
                severity = "low"
            }
            let primaryLabel = allergens?.primaryLabel ?? LocalConditionsFormatting.formatAllergenType(allergens?.primaryType)
            return driverStatus(
                for: "allergens",
                fallbackLabel: "Allergens",
                fallbackState: LocalConditionsFormatting.formatAllergenState(rawState, fallbackLabel: allergens?.overallLabel ?? allergens?.stateLabel),
                fallbackSeverity: severity,
                fallbackDetail: primaryLabel == "—" ? nil : primaryLabel
            )
        }

        private func hasAllergenData(_ allergens: LocalAllergens?) -> Bool {
            guard let allergens else { return false }
            return allergens.overallLevel != nil
                || allergens.primaryType != nil
                || allergens.treeLevel != nil
                || allergens.grassLevel != nil
                || allergens.weedLevel != nil
                || allergens.moldLevel != nil
        }

        private func forecastAllergenValue(_ day: LocalForecastDay) -> String {
            let state = LocalConditionsFormatting.formatAllergenState(day.pollenOverallLevel)
            let primary = LocalConditionsFormatting.formatAllergenType(day.pollenPrimaryType)
            if state == "—" { return "—" }
            if primary == "—" { return state }
            return "\(primary) • \(state)"
        }

        private var locationSummary: String {
            let resolvedZip = (snapshot?.whereInfo?.zip ?? zip).trimmingCharacters(in: .whitespacesAndNewlines)
            if useGPS {
                return resolvedZip.isEmpty ? "Using GPS for your area" : "Using GPS for your area • ZIP \(resolvedZip)"
            }
            return resolvedZip.isEmpty ? "Add a ZIP code to improve local conditions" : "ZIP \(resolvedZip)"
        }

        private func forecastDayLabel(_ iso: String?) -> String {
            guard let iso else { return "Day" }
            let fmt = ISO8601DateFormatter()
            if let date = fmt.date(from: iso) {
                let out = DateFormatter()
                out.dateFormat = "EEE, MMM d"
                return out.string(from: date)
            }
            let simple = DateFormatter()
            simple.dateFormat = "yyyy-MM-dd"
            if let date = simple.date(from: iso) {
                let out = DateFormatter()
                out.dateFormat = "EEE, MMM d"
                return out.string(from: date)
            }
            return iso
        }

        private func forecastTempRange(_ day: LocalForecastDay) -> String {
            let high = LocalConditionsFormatting.formatTemperature(day.tempHighC, unit: tempUnit)
            let low = LocalConditionsFormatting.formatTemperature(day.tempLowC, unit: tempUnit)
            return "\(high) / \(low)"
        }

        private func sharePrompt(for accent: ShareAccentLevel) -> String {
            _ = accent
            return "Share"
        }

        private func accent(for severityKey: String) -> ShareAccentLevel {
            switch severityKey.lowercased() {
            case "high":
                return .storm
            case "elevated":
                return .elevated
            case "mild":
                return .watch
            default:
                return .calm
            }
        }

        private func signalDraft(
            key: String,
            status: LocalConditionsDriverStatus,
            interpretation: String,
            bullets: [String],
            updatedText: String
        ) -> ShareDraft {
            let accentLevel = accent(for: status.severityKey)
            return ShareDraftFactory.signalSnapshot(
                surface: "local_conditions",
                analyticsKey: key,
                mode: mode,
                tone: tone,
                title: mode.copyVocabulary.driverLabel(for: key, fallback: status.label),
                value: status.detail,
                state: status.state,
                interpretation: interpretation,
                bullets: bullets,
                accent: accentLevel,
                background: ShareCardBackground(style: .atmospheric),
                sourceLine: locationSummary,
                updatedAt: updatedText,
                promptText: sharePrompt(for: accentLevel)
            )
        }

        private func localSnapshotDraft(
            tempStatus: LocalConditionsDriverStatus,
            baroStatus: LocalConditionsDriverStatus,
            airStatus: LocalConditionsDriverStatus,
            allergenStatus: LocalConditionsDriverStatus,
            updatedText: String
        ) -> ShareDraft {
            let ranked = [tempStatus, baroStatus, airStatus, allergenStatus].sorted {
                $0.progress > $1.progress
            }
            let leading = ranked.first ?? tempStatus
            let supporting = Array(ranked.dropFirst().prefix(2)).map(\.label)
            let accentLevel = accent(for: leading.severityKey)
            let interpretation = tone.resolveCopy(
                straight: "\(leading.label) looks most active in your area right now.",
                balanced: "\(leading.label) is the local factor standing out most right now.",
                humorous: "\(leading.label) is currently doing the loudest local weather monologue."
            )
            return ShareDraftFactory.dailyState(
                surface: "local_conditions",
                analyticsKey: "local_snapshot",
                mode: mode,
                title: "Local Conditions",
                leading: leading.label,
                supporting: supporting,
                interpretation: interpretation,
                accent: accentLevel,
                background: ShareCardBackground(style: .atmospheric),
                updatedAt: updatedText,
                promptText: sharePrompt(for: accentLevel)
            )
        }

